  const objectiveSaveQueueRef = useRef([]);
  useLayoutEffect(() => {
    objectiveSaveModule.lockRef = objectiveSaveLockRef;
    objectiveSaveModule.queueRef = objectiveSaveQueueRef;
  }, []);

  const [terms,    setTerms]    = useState([]);
  const nonCbseBlocksForCBSE = useMemo(
    () => terms.flatMap((tr) => tr.blocks || []).filter((b) => !isCBSEBlock(b)),
    [terms]
  );
  const [lectures, setLecs]     = useState([]);
  const [sessions, setSessions] = useState([]);
  const [analyses, setAnalyses] = useState({});
  const [ready,    setReady]    = useState(false);
  const [saveMsg,  setSaveMsg]  = useState("");

  useEffect(() => {
    if (typeof window === "undefined") return;
    try {
      if (localStorage.getItem("rxt-completion-migrated-v1")) return;
      const stored = JSON.parse(localStorage.getItem("rxt-completion") || "{}");
      Object.keys(stored).forEach((key) => {
        const rec = stored[key];
        if (rec && !rec.sessionCount) {
          rec.sessionCount = rec.sessions?.length || 1;
        }
      });
      localStorage.setItem("rxt-completion", JSON.stringify(stored));
      localStorage.setItem("rxt-completion-migrated-v1", "true");
    } catch (e) {
      console.warn("rxt-completion migration v1:", e);
    }
  }, []);

  useEffect(() => {
    if (typeof window === "undefined") return;
    try {
      const lecs = JSON.parse(localStorage.getItem("rxt-lec-meta") || "[]");
      const hasDLA3 = lecs.some(
        (l) =>
          l &&
          String(l.lectureType || "").toUpperCase() === "DLA" &&
          String(l.lectureNumber) === "3"
      );
      if (!hasDLA3) {
        const cache = JSON.parse(localStorage.getItem("rxt-upload-cache") || "{}");
        const cleaned = {};
        Object.entries(cache).forEach(([key, val]) => {
          const k = key.toLowerCase();
          if (!k.includes("dla 3") && !k.includes("dla3")) {
            cleaned[key] = val;
          }
        });
        localStorage.setItem("rxt-upload-cache", JSON.stringify(cleaned));
        console.log("Cleared DLA 3 cache entry — ready for re-upload");
      }
    } catch (e) {
      console.warn("DLA 3 cache clear:", e);
    }
  }, []);

  const [theme, setTheme] = useState(() => {
    if (typeof window === "undefined") return "dark";
    return localStorage.getItem("rxt-theme") || "dark";
  });
  const isDark = theme === "dark";
  const [aiProvider, setAiProvider] = useState(DEFAULT_PROVIDER);
  const [aiNavActive, setAiNavActive] = useState(() => {
    try {
      return getActiveProvider();
    } catch {
      return DEFAULT_PROVIDER;
    }
  });
  const [aiNavStatus, setAiNavStatus] = useState(() => getProviderStatus());

  useEffect(() => {
    const sync = (e) => {
      const active = e?.detail?.active;
      const st = e?.detail?.status;
      try {
        const next = active ?? getActiveProvider();
        setAiNavActive(next);
        setAiProvider(next);
      } catch {
        setAiNavActive(DEFAULT_PROVIDER);
        setAiProvider(DEFAULT_PROVIDER);
      }
      setAiNavStatus(st ?? getProviderStatus());
    };
    sync();
    window.addEventListener("rxt-provider-changed", sync);
    return () => window.removeEventListener("rxt-provider-changed", sync);
  }, []);

  const [view,    setView]    = useState("block");
  // Remember which view launched practice so we can restore it on session close.
  // Set whenever setView("study") is invoked from a non-study view; consumed by
  // Session's onBack/onDone handlers.
