  const handleDrillMCQAnswer = useCallback(
    (optionIndex) => {
      if (drillCardModeRef.current !== "mcq_ready") return;
      setMcqData((prev) => {
        if (!prev) return prev;
        const isCorrect = prev.options?.[optionIndex]?.correct === true;
        const bid = activeBlock?.id ?? blockId;
        const currentObj = drillQueueRef.current[drillIndexRef.current];
        queueMicrotask(() => {
          void (async () => {
            if (!bid) return;
            if (!isCorrect) {
              const lec = (lectures || []).find((l) => l.id === currentObj?.linkedLecId);
              const lectureLabel = lec
                ? `${lec.lectureType || "LEC"} ${lec.lectureNumber ?? ""} — ${lec.lectureTitle || lec.fileName || ""}`
                : "";
              await recordWrongAnswer({
                blockId: bid,
                blockName: activeBlock?.name || "",
                question: prev.question || "",
                wrongAnswer: prev.options?.[optionIndex]?.text || "",
                correctAnswer: prev.options?.find((o) => o.correct)?.text || "",
                linkedLecId: currentObj?.linkedLecId,
                lectureLabel,
                source: "drill",
                objectiveId: currentObj?.id || currentObj?.objectiveId || null,
              });
              setWeakConceptsRefreshKey((k) => k + 1);
            } else {
              const { block } = getWeakConcepts(bid);
              const matchingConcept = block.find(
                (c) =>
                  currentObj?.linkedLecId &&
                  (c.linkedLecIds || []).includes(currentObj.linkedLecId) &&
                  c.masteryLevel !== "mastered"
              );
              if (matchingConcept) {
                recordConceptCorrect(bid, matchingConcept.id);
                setWeakConceptsRefreshKey((k) => k + 1);
              }
            }
          })();
        });
        return { ...prev, selectedIndex: optionIndex };
      });
      if (drillStyleRef.current === "exam_block") {
        // Exam block: silent recording, no feedback, immediate advance
        if (drillAssessBusyRef.current) return;
        drillAssessBusyRef.current = true;
        const isCorrectForEB = mcqData?.options?.[optionIndex]?.correct === true;
        const currentObj = drillQueueRef.current[drillIndexRef.current];
        if (currentObj) {
          const bid = currentObj._drillBlockId || activeBlock?.id || blockId;
          examBlockAnswersRef.current.push({
            obj: currentObj,
            mcqData: mcqData ? { ...mcqData, selectedIndex: optionIndex } : null,
            selectedIndex: optionIndex,
            wasCorrect: isCorrectForEB,
            correctIndex: mcqData?.options?.findIndex((o) => o.correct),
          });
          setExamBlockAnswers([...examBlockAnswersRef.current]);
          updateDrillProgression(currentObj.id, bid, isCorrectForEB, true);
        }
        drillAssessBusyRef.current = false;
        advanceDrillRef.current?.();
        return;
      }
      setDrillCardMode("mcq_answered");
      drillCardModeRef.current = "mcq_answered";
    },
    [activeBlock?.id, activeBlock?.name, blockId, lectures, mcqData, updateDrillProgression]
  );

  const generateCardAnswer = useCallback(async (obj) => {
    setCardBack({ answer: "", loading: true });
    try {
      const lec = (lectures || []).find((l) => l.id === obj.linkedLecId);
      const lecTitle = lec?.lectureTitle || lec?.title || lec?.fileName || "";
      const systemPrompt = `You are a concise medical education assistant.
Give a direct, accurate answer to the learning objective.
2-4 sentences maximum. No preamble. No "The answer is...".
Just the factual answer a medical student needs.
Plain text only — no markdown, no bullet points.`;

      const userPrompt = `Learning objective: ${obj.objective || obj.text || ""}
Lecture context: ${lecTitle}
Bloom's level: ${obj.bloom_level_name || ""}

Provide the answer to this objective in 2-4 sentences.`;

      const answer = await callAI(systemPrompt, userPrompt, 300);

      setCardBack({
        answer: answer?.trim() || "No answer generated.",
        loading: false,
      });
    } catch (e) {
      console.error("generateCardAnswer failed:", e);
      setCardBack({
        answer: "Could not generate answer — check your knowledge against the lecture.",
        loading: false,
      });
    }
  }, [lectures]);

  const buildMCQPrompts = useCallback(
    (obj, levelConfig = null) => {
      const drillBid = activeBlock?.id ?? blockId;
      const blockObjs = getBlockObjectives(drillBid) || [];
      const bloomLevel = getQuestionLevel(obj, blockObjs);
      const lec = (lectures || []).find((l) => l.id === obj.linkedLecId);
      const lecTitle = lec
        ? `${lec.lectureType || "LEC"} ${lec.lectureNumber ?? ""} — ${lec.lectureTitle || lec.fileName || ""}`
        : "";
      const objText = obj.objective || obj.text || "";
      let lecObjs = blockObjs.filter((o) => o.linkedLecId === obj.linkedLecId);
      if (!lecObjs.length && (obj._drillBlockId || obj.sourceBlock)) {
        const homeBid = obj._drillBlockId || obj.sourceBlock;
        lecObjs = (getBlockObjectives(homeBid) || []).filter((o) => o.linkedLecId === obj.linkedLecId);
      }
      const currentIdx = Math.max(1, lecObjs.findIndex((o) => o.id === obj.id) + 1);
      const objectivesLines = lecObjs
        .map(
          (o, i) =>
            `${i + 1}. [${(o.code || o.activity || "").trim()}] ${(o.text || o.objective || "").trim()}${o.id ? ` [objectiveId: ${o.id}]` : ""}`
        )
        .join("\n");
      const lecBody = lec ? getLecText(lec) : "";
      const isPanicMode = (() => { try { return localStorage.getItem("rxt-panic-mode") === "true"; } catch { return false; } })();
      const panicTierInfo = isPanicMode ? DIFFICULTY_TIERS["exam"] : null;
      const levelBlock = isPanicMode
        ? `\n${buildDifficultyInstruction({ ...panicTierInfo, tier: "exam", sessionCount: 99, lastScore: 100 })}\n`
        : (levelConfig && levelConfig.promptInstruction ? `\n${levelConfig.promptInstruction}\n` : "");

      const systemPrompt = `${LECTURE_MARKDOWN_SYSTEM_INSTRUCTION}

You are an expert medical MCQ writer. You write questions that build deep understanding, not just memorization.

${MCQ_OPTION_UNIQUENESS_CRITICAL}

Lecture content uses markdown:
**Bold terms** = high yield, always test these
Tables = comparisons, generate differentiation questions
Headers = major topics, anchor clinical cases to these

For this single question, choose ONE style that fits best:
- Clinical vignette: patient presentation requiring application of lecture content
- Cross-objective linking: stem testing 2–3 of the listed objectives at once (use objectiveIndices)
- Elimination/reasoning: three plausible distractors wrong for specific reasons
- Image-based: describe a diagram/structure; use [IMAGE: description] in imagePrompt if no slide image

${(() => {
        const qr = obj.questionRound;
        const bloomOverride =
          qr === 1 ? "recall" : qr === 2 ? "application" : qr >= 3 ? "clinical reasoning" : null;
        if (bloomOverride) {
          const angleGuide =
            qr === 1
              ? "Test the definition, identification, or core fact directly."
              : qr === 2
                ? "DIFFERENT ANGLE REQUIRED: The student already saw a recall question on this objective. Now test the mechanism, a comparison, or a clinical scenario — do NOT ask the same factual question again."
                : "FRESH ANGLE REQUIRED: The student has seen recall and application questions on this objective. Now test a downstream consequence, an exception, a clinical decision, or cross-concept integration. A student who only memorised the definition should get this wrong.";
          return `DIFFICULTY ROUND ${qr} (${bloomOverride}): ${angleGuide}`;
        }
        return `BLOOM LEVEL: ${
          bloomLevel === 1
            ? "L1 — recall, definitions, basic identification"
            : bloomLevel === 2
              ? "L2 — application, clinical scenarios, comparisons"
              : "L3 — synthesis, multi-step reasoning, evaluation"
        }`;
      })()}

CRITICAL — STEM MUST CONTAIN A COMPLETE QUESTION:
The stem MUST end with an explicit interrogative sentence ending in "?". Examples:
- "Which of the following best explains the diagnosis?"
- "What is the most likely underlying mechanism?"
- "Which structure is most likely involved?"
A clinical vignette alone is NOT acceptable — it must be followed by an actual question. Never end the stem mid-description (e.g., "...consistent with respiratory distress syndrome" with no question). Always append a clear lead-in question on its own final sentence ending in "?".

Return JSON only. No markdown fences. One object (not an array) with exactly 4 options, exactly one isCorrect true.
For EVERY wrong option include whyWrong (string). Correct option: whyWrong null.
Include teachingPoint and which objective(s) via objectiveIndices (1-based indices into the list below).
imagePrompt: Set this whenever the question tests something that has a recognizable visual form. This includes:
- Histology slides (H&E, special stains, microscopy)
- Anatomy diagrams or cross-sections
- Physiology graphs or loops (pressure-volume loop, Frank-Starling curve, action potential, spirometry)
- ECG/EKG waveforms
- Lab findings (peripheral blood smear, urinalysis, etc.)
- X-ray, CT, MRI, ultrasound findings
- Pharmacology dose-response curves
- Biochemistry pathway diagrams
If any of the above apply, set imagePrompt to a plain-English description of what the image should show. Otherwise null.
IMPORTANT: Do NOT describe the image inside the stem field. The stem should only contain the clinical scenario and question. Put all image descriptions exclusively in the imagePrompt field.
visualSearchQuery: if imagePrompt is set, provide a short precise Wikimedia Commons search query optimized for finding a labeled diagram or slide (e.g. "left ventricular pressure volume loop diagram", "bone marrow sinusoid H&E stain", "ECG normal sinus rhythm labeled"). Otherwise null.`;

      const starredNote = obj.starred
        ? `\n⭐ THIS IS A MASTERY-REQUIRED OBJECTIVE (professor-designated, exam-critical). ` +
          `Write a high-yield question that directly and unambiguously tests this objective. ` +
          `Distractors must represent common misconceptions — wrong answers should teach.\n`
        : "";

      // ── Style examples from uploaded block questions (Madcow style) ───────
      const styleExamplesBlock = (() => {
        try {
          const banks = JSON.parse(localStorage.getItem("rxt-question-banks") || "{}");
          const allQ = Object.values(banks).flat();
          if (!allQ.length) return "";
          // Pick up to 2 questions roughly matching the lecture topic
          const lecWords = new Set(
            (lecTitle + " " + objText).toLowerCase().split(/\W+/).filter((w) => w.length > 4)
          );
          const scored = allQ.map((q) => {
            const stemWords = String(q.stem || "").toLowerCase().split(/\W+/);
            const hits = stemWords.filter((w) => lecWords.has(w)).length;
            return { q, hits };
          });
          scored.sort((a, b) => b.hits - a.hits);
          const picks = scored.slice(0, 2).filter((s) => s.q.stem);
          if (!picks.length) return "";
          const ex = picks.map(({ q }, i) => {
            const opts = q.choices
              ? Object.entries(q.choices).map(([letter, text]) =>
                  `  ${letter}. ${text}${letter === q.correct ? " ✓" : ""}`
                ).join("\n")
              : "";
            return `Example ${i + 1}:\n${q.stem}\n${opts}`;
          }).join("\n\n");
          return `\nSTYLE REFERENCE — write questions in this clinical vignette style:\n${ex}\n`;
        } catch { return ""; }
      })();
      // ─────────────────────────────────────────────────────────────────────

      const notebooklmBlock = lec?.notebooklmNotes?.trim()
        ? `\nSTUDY NOTES (from NotebookLM — high-yield summary, key concepts, active recall points):\n${lec.notebooklmNotes.trim().slice(0, 2000)}\n`
        : "";

      const userPrompt = `${LECTURE_MARKDOWN_CONTEXT_FOR_AI}

LEARNING OBJECTIVES for this lecture (primary focus: index ${currentIdx}):
${objectivesLines || `1. ${objText}`}

LECTURE CONTENT:
${lecBody.slice(0, 5000)}
${notebooklmBlock}${levelBlock}${starredNote}${styleExamplesBlock}
Write exactly ONE MCQ. Return JSON only:
{"stem":"...","style":"vignette","objectiveIndices":[${currentIdx}],"options":[{"letter":"A","text":"...","isCorrect":false,"whyWrong":"..."},{"letter":"B","text":"...","isCorrect":true,"whyWrong":null},{"letter":"C","text":"...","isCorrect":false,"whyWrong":"..."},{"letter":"D","text":"...","isCorrect":false,"whyWrong":"..."}],"explanation":"...","teachingPoint":"...","imagePrompt":null,"imagePage":null,"visualSearchQuery":null,"objectiveId":"${obj.id || ""}"}`;

      return { systemPrompt, userPrompt, objText, lecTitle, lecObjs };
    },
    [lectures, activeBlock?.id, blockId, getBlockObjectives]
  );

  const prefetchMCQ = useCallback(
    async (obj) => {
      if (!obj?.id) return;
      const objId = obj.id;
      const drillBid = activeBlock?.id ?? blockId;
      const blockObjs = getBlockObjectives(drillBid) || [];
      const questionLevel = getQuestionLevel(obj, blockObjs);
      const levelConfig = QUESTION_LEVELS[questionLevel];
      const cacheKey = `${objId}_${questionLevel}_r${obj.questionRound ?? 0}`;
      const existing = prefetchCacheRef.current[cacheKey];
      if (existing?.status === "ready") return;
      if (existing?.status === "loading") return;
      if (activePrefetchesRef.current >= MAX_CONCURRENT_PREFETCHES) return;

      // ── Check persistent bank first ───────────────────────────────────────
      const bankedQ = getMcqFromBank(objId, obj.questionRound ?? 0);
      if (bankedQ && bankedQ.question && bankedQ.options?.length >= 4) {
        prefetchCacheRef.current[cacheKey] = { status: "ready", data: bankedQ };
        return;
      }
      // ─────────────────────────────────────────────────────────────────────

      prefetchCacheRef.current[cacheKey] = { status: "loading", data: null };
      activePrefetchesRef.current += 1;

      const hasValidOptions = (options) => {
        if (!options || options.length < 4) return false;
        const hasRealText = options.every(
          (o) =>
            o.text &&
            o.text.trim().length > 3 &&
            o.text !== "None of the above" &&
            o.text !== "Not applicable"
        );
        const correctCount = options.filter((o) => o.correct).length;
        return hasRealText && correctCount === 1;
      };

      // Stem must be a proper question: at least 20 chars, ends with "?" or contains
      // a question word, and is not a bare fragment like "Within the bone marrow"
      const hasValidStem = (question) => {
        if (!question || typeof question !== "string") return false;
        const q = question.trim();
        if (q.length < 20) return false;
        // Stem MUST end with an explicit question. Vignettes that trail off
        // mid-description (e.g. "...consistent with respiratory distress syndrome")
        // are rejected even if they contain a question word elsewhere.
        if (!q.endsWith("?")) return false;
        // The final sentence must contain an interrogative cue.
        const lastSentence = q.split(/(?<=[.?!])\s+/).pop() || q;
        const hasQuestionWord = /\b(what|which|why|how|where|when|who|identify|select|choose|describe|is|are|does|do|will|would|should|could|can|name)\b/i.test(lastSentence);
        return hasQuestionWord;
      };

      try {
        const { systemPrompt, userPrompt, objText, lecObjs } = buildMCQPrompts(obj, levelConfig);
        const raw = await callAI(systemPrompt, userPrompt, 2500);
        const parsed = tryParseJSON(raw);
        const normalized = normalizeDrillMcqFromParsed(parsed, lecObjs || [], obj.id);

        if (!normalized || !hasValidStem(normalized.question) || !hasValidOptions(normalized.options)) {
          throw new Error("Invalid prefetch result — bad stem or options");
        }

        const finalizedOpts = finalizeDrillMcqOptionsAfterParse(normalized.options);
        if (!finalizedOpts || !hasValidOptions(finalizedOpts.options)) {
          throw new Error("Invalid prefetch result");
        }

        let drillObjectiveIdsForProgress = normalized.drillObjectiveIdsForProgress || [];
        if (!drillObjectiveIdsForProgress.length) drillObjectiveIdsForProgress = [obj.id];
        else if (!drillObjectiveIdsForProgress.includes(obj.id)) drillObjectiveIdsForProgress = [obj.id, ...drillObjectiveIdsForProgress];

        const bankData = {
          question: normalized.question,
          options: finalizedOpts.options,
          overallExplanation: normalized.overallExplanation,
          teachingPoint: normalized.teachingPoint,
          imagePrompt: normalized.imagePrompt,
          imagePage: normalized.imagePage,
          drillObjectiveIdsForProgress,
          objectiveText: objText,
          selectedIndex: null,
          isFallback: false,
          questionLevel,
        };
        prefetchCacheRef.current[cacheKey] = { status: "ready", data: bankData };
        // ── Persist to Supabase bank (also writes localStorage cache) ──────
        saveMcqBankEntry(currentUser?.id || null, objId, obj.questionRound ?? 0, bankData);
        // ──────────────────────────────────────────────────────────────────
      } catch (e) {
        prefetchCacheRef.current[cacheKey] = { status: "error", data: null };
      } finally {
        activePrefetchesRef.current -= 1;
      }
    },
    [buildMCQPrompts, getBlockObjectives, activeBlock?.id, blockId]
  );

  const scheduleMcqPrefetchForQueue = useCallback((queue) => {
    prefetchCacheRef.current = {};
    activePrefetchesRef.current = 0;
    if ((drillStyle !== "mcq" && drillStyle !== "exam_block") || !queue?.length) return;
    if (queue[1]) prefetchMCQRef.current?.(queue[1]);
    if (queue[2]) {
      setTimeout(() => prefetchMCQRef.current?.(queue[2]), 200);
    }
  }, [drillStyle]);

  const generateSyntheticObjectives = useCallback(async (lecId, blockId, existingObjs, count) => {
    const resolvedLecId = lecId || existingObjs.find((o) => o.linkedLecId)?.linkedLecId;
    if (!resolvedLecId || !count) return [];
    try {
      const allLecs = JSON.parse(localStorage.getItem("rxt-lec-meta") || "[]");
      const lec = allLecs.find((l) => l.id === resolvedLecId);
      if (!lec) return [];

      const collected = [];
      let remaining = count;
      while (remaining > 0) {
        const batch = Math.min(20, remaining);
        const lecText = (lec.chunks || []).map((c) => getChunkBody(c)).join("\n").slice(0, 3000);
        const existingTopics = [...existingObjs, ...collected]
          .map((o) => (o.objective || o.text || "").slice(0, 60))
          .join("\n");

        const systemPrompt = `Generate ${batch} additional learning objectives for this medical lecture.
Return JSON only:
{"objectives":[{"text":"objective text","bloom_level":2}]}
Make them DIFFERENT from the existing ones.
Cover topics not yet addressed.
Vary Bloom levels: some recall, some application, some analysis.`;

        const userPrompt = `Lecture: ${lec.lectureTitle || ""}
Type: ${lec.lectureType || ""}

Existing objectives already covered:
${existingTopics}

Lecture content summary:
${lecText.slice(0, 1500)}

Generate ${batch} new objectives that cover different aspects of this lecture.`;

        const raw = await callAI(systemPrompt, userPrompt, 1500);
        const parsed = tryParseJSON(raw);
        if (!parsed?.objectives?.length) break;
        const batchObjs = parsed.objectives.slice(0, batch).map((o) => ({
          id: newSyntheticObjectiveId(),
          _drillBlockId: blockId || "msk",
          linkedLecId: resolvedLecId,
          objective: o.text || "",
          text: o.text || "",
          status: "untested",
          bloom_level: o.bloom_level || 2,
          isSynthetic: true,
        }));
        collected.push(...batchObjs);
        remaining -= batchObjs.length;
        if (batchObjs.length < batch) break;
      }
      return collected.slice(0, count);
    } catch (e) {
      console.error("generateSyntheticObjectives failed:", e);
      return [];
    }
  }, []);

