  /** Reset MCQ UI when a new question is shown (without touching generateDrillMCQ). */
  useEffect(() => {
    if (drillCardMode !== "mcq_ready" || !mcqData?.question) return;
    setEliminatedOptions([]);
    setSelectedOption(null);
    setLockedAnswer(null);
    setMcqOptionHover(null);
  }, [drillCardMode, mcqData?.question, drillIndex]);

  useEffect(() => {
    const q =
      stripImageTagFromStem(mcqData?.question || "") || String(mcqData?.question || "");
    drillMcqStemContextRef.current = q;
  }, [mcqData?.question]);

  useEffect(() => {
    setDrillStemAnnotation(null);
  }, [drillIndex, mcqData?.question, drillCardMode]);

  useEffect(() => {
    if (!drillMode) {
      setDrillStemAnnotation(null);
      setDrillStemToast(null);
    }
  }, [drillMode]);

  const fetchDrillStemAnnotation = useCallback(async (selectedText) => {
    const questionContext = drillMcqStemContextRef.current || "";
    const fallback = {
      normalRange: null,
      direction: null,
      significance: "No information found.",
      clinicalImplication: null,
    };
    try {
      const result = await callAIJSON(
        `You are a clinical medicine tutor helping a medical student think through a question stem. When given a selected term or lab value, return a JSON object with:
{
  "normalRange": "string or null — only for lab values/vitals",
  "direction": "HIGH or LOW or null — if it's a lab value, is this value abnormal and in which direction",
  "significance": "1-2 sentences: what does this finding mean clinically in plain language",
  "clinicalImplication": "1 sentence: what diagnosis or mechanism does this point toward"
}
Be concise. Medical student level. No preamble.`,
        `Question context: "${questionContext.slice(0, 400)}"
Student selected: "${selectedText}"

What is the clinical significance of this finding?`,
        fallback,
        1000
      );
      const merged = {
        normalRange: result?.normalRange ?? null,
        direction: result?.direction ?? null,
        significance:
          result?.significance != null && String(result.significance).trim()
            ? String(result.significance).trim()
            : fallback.significance,
        clinicalImplication: result?.clinicalImplication ?? null,
      };
      setDrillStemAnnotation((prev) =>
        prev ? { ...prev, loading: false, result: merged } : null
      );
    } catch {
      setDrillStemAnnotation((prev) =>
        prev
          ? {
              ...prev,
              loading: false,
              result: { significance: "Could not load — check AI connection." },
            }
          : null
      );
    }
  }, []);

  // Paste-to-attach: capture clipboard images while drill is active
  useEffect(() => {
    const handlePaste = (e) => {
      if (!currentUser?.id) return;
      const obj = drillQueueRef.current[drillIndexRef.current];
      if (!obj?.id) return;
      const items = Array.from(e.clipboardData?.items || []);
      const imageItems = items.filter((item) => item.type.startsWith("image/"));
      if (!imageItems.length) return;
      const objId = obj.id;
      const round = obj.questionRound ?? 0;
      Promise.all(
        imageItems.map((item) => {
          const file = item.getAsFile();
          if (!file) return null;
          const ext = file.type.split("/")[1] || "png";
          const namedFile = new File([file], `paste_${Date.now()}.${ext}`, { type: file.type });
          return uploadQuestionImage(currentUser.id, objId, round, namedFile);
        }).filter(Boolean)
      ).then(() => {
        setQuestionImagesCache(objId, round, null);
        setQuestionImagesVer(v => v + 1);
      });
    };
    document.addEventListener("paste", handlePaste);
    return () => document.removeEventListener("paste", handlePaste);
  }, [currentUser?.id]);

  const handleDrillStemSelection = useCallback(() => {
    if (typeof window === "undefined") return;
    const container = drillStemContainerRef.current;
    const selection = window.getSelection();
    const selectedText = selection?.toString().trim();
    if (!selectedText || selectedText.length < 2) return;
    if (!container || !selection?.anchorNode || !selection?.focusNode) return;
    if (!container.contains(selection.anchorNode) || !container.contains(selection.focusNode)) return;
    let range;
    try {
      range = selection.getRangeAt(0);
    } catch {
      return;
    }
    const rect = range.getBoundingClientRect();
    const centerX = rect.left + rect.width / 2;
    const topY = rect.top - 8;
    setDrillStemAnnotation({
      text: selectedText,
      x: centerX,
      y: topY,
      loading: true,
      result: null,
    });
    fetchDrillStemAnnotation(selectedText);
  }, [fetchDrillStemAnnotation]);

  const handleAddDrillStemAnnotationToNotes = useCallback(
    (annotation) => {
      const obj = drillQueueRef.current[drillIndexRef.current];
      if (!obj?.id) return;
      const bid =
        obj._drillBlockId || drillBlockIdRef.current || activeBlock?.id || blockId;
      if (!bid) return;
      const allObjs = getMSKObjectives(bid);
      const noteAddition = `\n[${annotation.text}]: ${annotation.result?.significance || ""}`;
      const updated = allObjs.map((o) =>
        o.id === obj.id
          ? { ...o, personalNotes: (o.personalNotes || "") + noteAddition }
          : o
      );
      saveMSKObjectives(bid, updated);
      setDrillStemAnnotation(null);
      setDrillStemToast("📝 Added to objective notes");
      window.setTimeout(() => setDrillStemToast(null), 2000);
      try {
        window.dispatchEvent(new CustomEvent("rxt-objectives-updated"));
      } catch {}
    },
    [activeBlock?.id, blockId]
  );

  useEffect(() => {
    if (!drillMode || drillQueue.length === 0 || drillComplete) {
      if (drillComplete) {
        try {
          localStorage.removeItem("rxt-drill-progress");
        } catch {}
      }
      return;
    }
    try {
      localStorage.setItem(
        "rxt-drill-progress",
        JSON.stringify({
          blockId: activeBlock?.id ?? blockId,
          drillIndex,
          drillStats,
          drillStyle,
          drillFilter,
          drillLecFilter: Array.from(selectedLectureIds),
          drillIdAllowlist,
          savedAt: new Date().toISOString(),
        })
      );
    } catch {}
  }, [
    drillMode,
    drillQueue.length,
    drillComplete,
    drillIndex,
    drillStats,
    drillStyle,
    drillFilter,
    selectedLectureIds,
    drillIdAllowlist,
    activeBlock?.id,
    blockId,
  ]);

  useEffect(() => {
    if (!drillMode || drillQueue.length > 0 || drillComplete) {
      setDrillResumeSnapshot(null);
      return;
    }
    try {
      const raw = localStorage.getItem("rxt-drill-progress");
      const saved = raw ? JSON.parse(raw) : null;
      const bid = activeBlock?.id ?? blockId;
      if (saved && saved.blockId === bid && Date.now() - new Date(saved.savedAt) < 3600000) {
        setDrillResumeSnapshot(saved);
      } else {
        setDrillResumeSnapshot(null);
      }
    } catch {
      setDrillResumeSnapshot(null);
    }
  }, [drillMode, drillQueue.length, drillComplete, activeBlock?.id, blockId]);

  useEffect(() => {
    if (drillStyle === "mcq" && drillCardMode === "mcq_answered") {
      setCardState("mcq_answered");
    }
  }, [drillCardMode, drillStyle]);

  useEffect(() => {
    if (!drillMode) return;
    if (drillComplete) return;
    if (drillStyle !== "mcq" && drillStyle !== "exam_block") return;
    const q = drillQueueRef.current;
    if (!q.length) return;
    const currentObj = q[drillIndex];
    if (!currentObj) return;
    setRevealedCardKey(currentObj.id);
    revealedCardKeyRef.current = currentObj.id;

    generateDrillMCQRef.current?.(currentObj);

    const nextObj = q[drillIndex + 1];
    if (nextObj) prefetchMCQRef.current?.(nextObj);
    const nextNextObj = q[drillIndex + 2];
    if (nextNextObj) prefetchMCQRef.current?.(nextNextObj);
  }, [drillMode, drillIndex, drillStyle, drillComplete, drillQueue.length]);

  useEffect(() => {
    if (drillStyle !== "mcq" && drillStyle !== "exam_block") {
      prefetchCacheRef.current = {};
      activePrefetchesRef.current = 0;
    }
  }, [drillStyle]);

  useEffect(() => {
    if (drillMode && drillComplete) {
      prefetchCacheRef.current = {};
      activePrefetchesRef.current = 0;
    }
  }, [drillMode, drillComplete]);

  drillKeyHandlersRef.current = {
    assess: handleDrillAssess,
    skip: handleDrillSkip,
    exit: requestDrillExit,
  };

  useEffect(() => {
    if (!drillMode) return;
    const onKeyDown = (e) => {
      if (e.defaultPrevented) return;
      const tag = (e.target && e.target.tagName) || "";
      if (tag === "INPUT" || tag === "TEXTAREA" || tag === "SELECT" || e.target?.isContentEditable) return;
      const { assess, skip, exit } = drillKeyHandlersRef.current;
      if (e.key === "Escape") {
        if (
          drillStyle === "mcq" &&
          drillCardModeRef.current === "mcq_ready" &&
          drillMcqSelectedOptionRef.current !== null
        ) {
          e.preventDefault();
          setSelectedOption(null);
          return;
        }
        e.preventDefault();
        exit();
        return;
      }
      if (drillComplete || drillQueue.length === 0) return;

      const curObj = drillQueueRef.current[drillIndexRef.current];
      const curId = curObj?.id;
      const revealKeys = e.key === " " || e.key === "Spacebar" || e.key === "Enter";
      if (e.key === "m" || e.key === "M") {
        e.preventDefault();
        toggleDrillStyleAndReset();
        return;
      }
      if (curId != null && revealedCardKey !== curId && revealKeys) {
        if (drillStyle === "mcq") {
          return;
        }
        if (e.key === " " || e.key === "Spacebar") {
          e.preventDefault();
          e.stopPropagation();
        } else if (e.key === "Enter") {
          e.preventDefault();
        }
        setRevealedCardKey(curId);
        revealedCardKeyRef.current = curId;
        generateCardAnswer(curObj);
        return;
      }

      if (curId == null || revealedCardKey !== curId) return;

      const mode = drillCardModeRef.current;
      if (mode === "mcq_loading") return;

      if (mode === "mcq_ready") {
        const selOpt = drillMcqSelectedOptionRef.current;
        const elim = drillMcqEliminatedRef.current;

        if (e.key === "Enter" || e.key === " " || e.key === "Spacebar") {
          if (selOpt !== null) {
            e.preventDefault();
            setLockedAnswer(selOpt);
            handleDrillMCQAnswerRef.current?.(selOpt);
            setSelectedAnswer(selOpt);
          }
          return;
        }

        const digitMatch = e.code?.match(/^Digit([1-4])$/);
        if (digitMatch) {
          e.preventDefault();
          const idx = parseInt(digitMatch[1], 10) - 1;
          if (e.shiftKey) {
            setEliminatedOptions((prev) =>
              prev.includes(idx) ? prev.filter((i) => i !== idx) : [...prev, idx]
            );
            if (selOpt === idx) setSelectedOption(null);
          } else if (elim.includes(idx)) {
            setEliminatedOptions((prev) => prev.filter((i) => i !== idx));
          } else if (selOpt === idx) {
            setSelectedOption(null);
          } else {
            setSelectedOption(idx);
          }
          return;
        }
        const k = e.key;
        const kl = k.length === 1 ? k.toLowerCase() : "";
        if (kl === "a" || kl === "b" || kl === "c" || kl === "d") {
          e.preventDefault();
          const idx = kl.charCodeAt(0) - 97;
          if (e.shiftKey) {
            setEliminatedOptions((prev) =>
              prev.includes(idx) ? prev.filter((i) => i !== idx) : [...prev, idx]
            );
            if (selOpt === idx) setSelectedOption(null);
          } else if (elim.includes(idx)) {
            setEliminatedOptions((prev) => prev.filter((i) => i !== idx));
          } else if (selOpt === idx) {
            setSelectedOption(null);
          } else {
            setSelectedOption(idx);
          }
        }
        return;
      }

      if (mode === "mcq_answered") {
        if (e.key === "Enter") {
          e.preventDefault();
          const idx = mcqData?.selectedIndex;
          if (idx != null && mcqData?.options?.[idx]?.correct) {
            assess("mastered");
          } else {
            assess("struggling");
          }
          return;
        }
        if (e.key === "1" || e.key === "ArrowLeft") {
          e.preventDefault();
          assess("struggling");
        } else if (e.key === "2" || e.key === "ArrowDown") {
          e.preventDefault();
          assess("inprogress");
        } else if (e.key === "3" || e.key === "ArrowRight") {
          e.preventDefault();
          assess("mastered");
        }
        return;
      }

      if (mode === "back") {
        if (e.key === "1" || e.key === "ArrowLeft") {
          e.preventDefault();
          assess("struggling");
        } else if (e.key === "2" || e.key === "ArrowDown") {
          e.preventDefault();
          assess("inprogress");
        } else if (e.key === "3" || e.key === "ArrowRight") {
          e.preventDefault();
          assess("mastered");
        } else if (e.key === "s" || e.key === "S" || e.key === "ArrowUp") {
          e.preventDefault();
          skip();
        }
      }
    };
    window.addEventListener("keydown", onKeyDown);
    return () => window.removeEventListener("keydown", onKeyDown);
  }, [
    drillMode,
    drillComplete,
    drillQueue,
    drillQueue.length,
    drillIndex,
    drillStyle,
    revealedCardKey,
    drillCardMode,
    cardState,
    mcqData,
    eliminatedOptions,
    selectedAnswer,
    toggleDrillStyleAndReset,
    generateCardAnswer,
  ]);

  useEffect(() => {
    if (!drillMode || drillQueue.length === 0 || drillComplete) return;
    if (drillCardFirstRenderRef.current) {
      drillCardFirstRenderRef.current = false;
      setDrillCardOpacity(1);
      return;
    }
    setDrillCardOpacity(0);
    const tid = setTimeout(() => setDrillCardOpacity(1), 80);
    return () => clearTimeout(tid);
  }, [drillIndex, drillMode, drillQueue.length, drillComplete]);

  // ONLY update objective statuses for the target lecture — never by lecture number or topic string.
  const syncSessionToObjectives = (sessionResults, blockId, targetObjectives, targetLecId) => {
    const targetLecIdResolved =
      targetLecId ?? targetObjectives?.[0]?.linkedLecId;
    if (!targetLecIdResolved) {
      console.warn("syncSessionToObjectives: no targetLecId — skipping");
      return { updatedCount: 0, masteredCount: 0, strugglingCount: 0, updates: [] };
    }
    if (!blockId || !sessionResults?.length) return { updatedCount: 0, masteredCount: 0, strugglingCount: 0, updates: [] };

    const blockObjs = getBlockObjectives(blockId) || [];
    const updatesRef = { current: [] };
    let updatedCount = 0;
    let masteredCount = 0;
    let strugglingCount = 0;

    sessionResults.forEach((result) => {
      const obj =
        (result.objectiveId &&
          blockObjs.find((o) => o.linkedLecId === targetLecIdResolved && o.id === result.objectiveId)) ||
        blockObjs.find(
          (o) =>
            o.linkedLecId === targetLecIdResolved &&
            (result.objectiveCovered || result.topic || "")
              .toLowerCase()
              .includes((o.objective || "").toLowerCase().slice(0, 20))
        );
      if (obj) {
        const newStatus =
          result.confidenceFlag === "guessed"
            ? "inprogress"
            : result.correct
              ? "mastered"
              : "struggling";
        const patch = {
          status: newStatus,
          lastTested: new Date().toISOString(),
          quizScore: result?.score ?? obj.quizScore,
        };
        if (result.confidenceFlag === "guessed") {
          patch.consecutiveCorrect = 0;
        }
        updateObjective(blockId, obj.id, patch);
        updatedCount++;
        if (newStatus === "mastered") masteredCount++;
        if (newStatus === "struggling") strugglingCount++;
        updatesRef.current.push({ id: obj.id, objective: (obj.objective || "").slice(0, 60), newStatus });
      }
    });

    return { updatedCount, masteredCount, strugglingCount, updates: updatesRef.current };
  };

  useEffect(() => {
    if (!FTM2_DATA?.objectives?.length) return;

    const allBlocks = terms.flatMap((t) => t.blocks || []);
    const currentBlock = allBlocks.find((b) => b.id === blockId);
    if (!currentBlock?.id) return;

    const isFTMBlock = /ftm/i.test(currentBlock.name || "");
    if (!isFTMBlock) return;

    setBlockObjectives((prev) => {
      const storedCount = prev[currentBlock.id]?.imported?.length || 0;
      const blockLectures = getBlockLecs(lectures, currentBlock);

      if (storedCount > 0) {
        if (!blockLectures.length) return prev;
        const aligned = alignObjectivesToLectures(
          currentBlock.id,
          prev[currentBlock.id].imported,
          blockLectures
        );
        const linked = aligned.filter((o) => o.hasLecture).length;
        const prevLinked = (prev[currentBlock.id].imported || []).filter((o) => o.hasLecture).length;
        if (linked === prevLinked) return prev;
        console.log(`Re-alignment: ${linked}/${aligned.length} objectives now linked`);
        const updated = {
          ...prev,
          [currentBlock.id]: { ...prev[currentBlock.id], imported: aligned },
        };
        try {
          safeSetItem("rxt-block-objectives", updated);
        } catch {}
        return updated;
      }

      if (!/ftm\s*2/i.test(currentBlock.name || "") && currentBlock.id !== "ftm2") return prev;
      const aligned = blockLectures.length
        ? alignObjectivesToLectures(currentBlock.id, FTM2_DATA.objectives, blockLectures)
        : FTM2_DATA.objectives;
      const linked = aligned.filter((o) => o.hasLecture).length;
      console.log(`Seeding + aligning: ${linked}/${aligned.length} objectives linked to lectures`);
      const updated = {
        ...prev,
        [currentBlock.id]: {
          imported: aligned,
          extracted: prev[currentBlock.id]?.extracted || [],
        },
      };
      if (prev["ftm1"]?.imported?.length > 0 && currentBlock.id !== "ftm1") {
        delete updated["ftm1"];
      }
      try {
        safeSetItem("rxt-block-objectives", updated);
      } catch {}
      return updated;
    });
  }, [blockId, terms, lectures.length]);

  const updatePerformance = (_topicKey, _score, _difficulty, _questionCount, _objectivesCovered = []) => {
    // Session data is written only in finalizeSession — no other writes
  };

  const getTopicDifficulty = (topicKey) => {
    return performanceHistory[topicKey]?.currentDifficulty || "medium";
  };

  const computeWeakAreas = (blockId) => {
    const objs = getBlockObjectives(blockId) || [];
    const perf = performanceHistory;
    const blockLecs = getBlockLecs(lectures, resolveBlockMeta(blockId));
    const resolveActivity = (o) => {
      if ((o.activity || "").trim() && (o.activity || "").trim() !== "Unknown") return o.activity || "Unknown";
      const lec =
        blockLecs.find((l) => l.id === o.linkedLecId) ||
        blockLecs.find(
          (l) =>
            String(l.lectureNumber) === String(o.lectureNumber) &&
            (l.lectureType || "LEC") === (o.lectureType || l.lectureType || "LEC")
        ) ||
        (() => {
          if ((o.lectureTitle || "").trim().length < 5) return null;
          const objTitle = (o.lectureTitle || "").trim().toLowerCase().slice(0, 50);
          const matches = blockLecs.filter((l) => {
            const lecTitle = (l.lectureTitle || l.fileName || "").toLowerCase();
            return lecTitle.includes(objTitle) || objTitle.includes(lecTitle.slice(0, 50));
          });
          return matches.find((l) => (l.lectureType || "").toUpperCase().includes("DLA")) || matches[0] || null;
        })();
      return lec ? `${lec.lectureType || "LEC"} ${lec.lectureNumber ?? ""}`.trim() : "Unknown";
    };
    const weakAreas = [];
    const byLecture = {};
    objs.forEach((o) => {
      const key = resolveActivity(o);
      if (!byLecture[key])
        byLecture[key] = { activity: key, lectureTitle: o.lectureTitle, discipline: o.discipline, objectives: [] };
      byLecture[key].objectives.push(o);
    });
    Object.values(byLecture).forEach((group) => {
      const total = group.objectives.length;
      const struggling = group.objectives.filter((o) => o.status === "struggling").length;
      const untested = group.objectives.filter((o) => o.status === "untested").length;
      const mastered = group.objectives.filter((o) => o.status === "mastered").length;
      const lecPerf = Object.entries(perf)
        .filter(([k]) => k.includes(group.activity))
        .map(([, v]) => v);
      const avgScore =
        lecPerf.length
          ? lecPerf.reduce((a, p) => a + (p.sessions?.slice(-1)[0]?.score || 0), 0) / lecPerf.length
          : null;
      const weaknessScore =
        struggling * 3 +
        untested * 1 +
        (avgScore !== null && avgScore < 60 ? 5 : 0) +
        (avgScore !== null && avgScore < 40 ? 5 : 0);
      if (weaknessScore > 0) {
        weakAreas.push({
          ...group,
          total,
          struggling,
          untested,
          mastered,
          avgScore,
          weaknessScore,
          priority: weaknessScore >= 8 ? "critical" : weaknessScore >= 4 ? "high" : "medium",
        });
      }
    });
    return weakAreas.sort((a, b) => b.weaknessScore - a.weaknessScore);
  };

  const [weakAreas, setWeakAreas] = useState([]);

  const generateTopicVignettes = useCallback(
    (cfg) =>
      genTopicVignettesWithContext(cfg, {
        lectures,
        getBlockObjectives,
        getTopicDifficulty,
        sessions,
        performanceHistory,
        makeTopicKey,
        stylePrefs,
      }),
    [lectures, getBlockObjectives, getTopicDifficulty, sessions, performanceHistory, makeTopicKey, stylePrefs]
  );

  const showPerformanceFeedback = (topicKey, score, justUpgraded = false) => {
    const perf = performanceHistory[topicKey];
    const streak = perf?.streak ?? 0;
    const lastScore = perf?.sessions?.slice(-1)[0]?.score;
    const upgraded = justUpgraded || (score >= 80 && lastScore >= 80 && (perf?.sessions?.length ?? 0) >= 1);

    let toast = null;
    if (score >= 80 && streak >= 1 && upgraded) {
      toast = {
        type: "upgrade",
        title: "Difficulty Increased! 🔥",
        message: "You scored " + score + "% twice in a row. Next session will be " + (perf?.currentDifficulty || "medium").toUpperCase() + " difficulty.",
        color: "#10b981",
      };
    } else if (score >= 80) {
      toast = {
        type: "great",
        title: "Strong Performance! ✓",
        message: score + "% — " + (streak > 1 ? streak + " in a row above 80%!" : "One more above 80% and difficulty increases."),
        color: "#10b981",
      };
    } else if (score >= 60) {
      toast = {
        type: "ok",
        title: "Keep Going",
        message: score + "% — Review weak objectives and try again.",
        color: "#f59e0b",
      };
    } else {
      toast = {
        type: "low",
        title: "Needs Review",
        message: score + "% — Difficulty adjusted. Focus on fundamentals first.",
        color: "#ef4444",
      };
    }
    setPerfToast(toast);
    setTimeout(() => setPerfToast(null), 6000);
  };

  const [learningProfile, setLearningProfile] = useState(() => loadProfile());
  const saveRef = useRef(null);

  // ── Load from storage ──────────────────────
  useEffect(() => {
    (async () => {
      try {
        // Ensure all linkedLecIds in block-objectives have stubs in lec-meta
        try {
          const allObjs = JSON.parse(localStorage.getItem("rxt-block-objectives") || "{}");
          const metaArr = JSON.parse(localStorage.getItem("rxt-lec-meta") || "[]");
          const existingIds = new Set(metaArr.map(l => l.id));
          const newStubs = [];
          let seqCounter = 900;
          Object.entries(allObjs).forEach(([wk, data]) => {
            const blockId = (data?.blockId) || wk.split("__")[0];
            if (!blockId) return;
            const imported = data?.imported || [];
            const byLecId = {};
            imported.forEach(o => {
              if (o.linkedLecId && !byLecId[o.linkedLecId]) byLecId[o.linkedLecId] = o;
            });
            Object.entries(byLecId).forEach(([lecId, rep]) => {
              if (existingIds.has(lecId)) return;
              const rawNum = rep.lectureNumber;
              const hasNum = rawNum != null && rawNum !== 0 && String(rawNum).trim() !== "";
              const rawType = rep.lectureType === "Lecture" ? "LEC" : (rep.lectureType || "LEC");
              newStubs.push({
                id: lecId,
                blockId,
                lectureTitle: rep.lectureTitle || "",
                lectureNumber: hasNum ? rawNum : (seqCounter++),
                lectureType: rawType,
                subject: rep.discipline || rep.subject || "",
                filename: "",
                uploadedAt: new Date().toISOString(),
              });
              existingIds.add(lecId);
            });
          });
          if (newStubs.length > 0) {
            const merged = [...metaArr, ...newStubs];
            localStorage.setItem("rxt-lec-meta", JSON.stringify(merged));
            console.log(`Auto-recovered ${newStubs.length} lecture stubs from objectives`);
          }
        } catch (e) {
          console.warn("Lecture stub recovery failed:", e);
        }

        const t = await sGet("rxt-terms");
        const s = await sGet("rxt-sessions");
        const a = await sGet("rxt-analyses");
        const l = await loadLectures();
        setTerms(t || DEFAULT_TERMS);
        setSessions(s || []);
        setAnalyses(a || {});
        setLecs(l || []);
      } catch (e) {
        console.error(e);
        setTerms(DEFAULT_TERMS);
      }
      setReady(true);
    })();
  }, []);

  useEffect(() => {
    if (typeof window === "undefined") return;
    const keysToTrim = [
      "rxt-learning-profile",
      "rxt-weak-areas",
      "rxt-dl-sessions",
      "rxt-objectives-backup",
    ];

    let freed = 0;
    keysToTrim.forEach((key) => {
      const size = (localStorage.getItem(key) || "").length * 2;
      if (size > 500000) {
        try {
          localStorage.removeItem(key);
          freed += size;
          console.log(
            `Cleared ${key}:`,
            (size / 1024 / 1024).toFixed(2) + "MB freed"
          );
        } catch {}
      }
    });

    const histoSize = (localStorage.getItem("rxt-histo-manual") || "").length * 2;
    if (histoSize > 3 * 1024 * 1024) {
      try {
        localStorage.removeItem("rxt-histo-manual");
        freed += histoSize;
        console.log(
          "Cleared rxt-histo-manual:",
          (histoSize / 1024 / 1024).toFixed(2) + "MB freed"
        );
      } catch {}
    }

    if (freed > 0) {
      console.log(
        "Total freed:",
        (freed / 1024 / 1024).toFixed(2) + "MB"
      );
    }
  }, []);

  useEffect(() => {
    if (typeof window === "undefined") return;
    try {
      const stored = JSON.parse(localStorage.getItem("rxt-block-objectives") || "{}");
      const totalObjs = Object.values(stored)
        .flatMap((v) => (Array.isArray(v) ? v : Object.values(v || {}).flat()))
        .filter(Boolean).length;
      if (totalObjs > 200) {
        console.log("Running objective store compression...");
        compressObjectiveStore();
      }
    } catch (e) {
      console.warn("Objective store compression skipped:", e);
    }
  }, []);

  useEffect(() => {
    if (activeBlock?.id) compressOldLectures(activeBlock.id);
  }, [activeBlock?.id]);

  // One-time repair: re-detect lectureType/lectureNumber/weekNumber for already-uploaded lectures.
  // dayOfWeek is preserved (user-set only, not overwritten).
  const lectureRepairDoneRef = useRef(false);
  useEffect(() => {
    if (!ready || lectureRepairDoneRef.current) return;
    lectureRepairDoneRef.current = true;
    setLecs((prev) => {
      if (!prev?.length) return prev;
      let changed = false;
      const next = prev.map((lec) => {
        const fileName = lec.fileName || lec.filename || "";
        const title = lec.lectureTitle || "";
        const detectedType = detectLectureType(fileName, title);
        const detectedNum = detectLectureNumber(fileName, title, detectedType);
        const detectedWeek = lec.weekNumber ?? detectWeekNumber(fileName, title);
        const current = (lec.lectureType || "LEC").toUpperCase();
        const currentNorm = current === "LECTURE" || current.startsWith("LECT") ? "LEC" : current.slice(0, 4);
        if (detectedType !== currentNorm || (detectedNum != null && detectedNum !== lec.lectureNumber) || (detectedWeek != null && detectedWeek !== lec.weekNumber)) {
          changed = true;
          return {
            ...lec,
            lectureType: detectedType,
            lectureNumber: detectedNum ?? lec.lectureNumber,
            weekNumber: detectedWeek ?? lec.weekNumber,
          };
        }
        return lec;
      });
      if (changed) {
        saveLectures(next);
        return next;
      }
      return prev;
    });
  }, [ready]);

  // Sync blockId/termId when terms load: ensure blockId exists in terms
  useEffect(() => {
    if (!ready || !terms?.length) return;
    const allBlocks = terms.flatMap((t) => t.blocks || []);
    const exists = allBlocks.some((b) => b.id === blockId);
    if (exists) return;
    const saved = localStorage.getItem("rxt-current-block");
    if (saved && allBlocks.some((b) => b.id === saved)) {
      setBlockId(saved);
      const term = terms.find((t) => t.blocks?.some((b) => b.id === saved));
      if (term) setTermId(term.id);
      return;
    }
    const inProgress = allBlocks.find((b) => b.status === "inprogress" || b.status === "active");
    const next = inProgress || allBlocks.find((b) => b.status !== "completed" && b.status !== "done" && b.status !== "complete") || allBlocks[allBlocks.length - 1] || allBlocks[0];
    if (next) {
      setBlockId(next.id);
      localStorage.setItem("rxt-current-block", next.id);
      const term = terms.find((t) => t.blocks?.some((b) => b.id === next.id));
      if (term) setTermId(term.id);
    }
  }, [ready, terms, blockId]);

  // Only auto-pick the "preferred" block on first load when no block is selected
  // and nothing is saved. After that, respect the user's selection — never clobber it.
  const didInitBlockRef = useRef(false);
  useEffect(() => {
    if (!ready || !terms?.length) return;
    if (didInitBlockRef.current) return;
    if (blockId) { didInitBlockRef.current = true; return; }
    try {
      const saved = localStorage.getItem("rxt-current-block");
      if (saved) { didInitBlockRef.current = true; return; }
    } catch {}
    const preferred = getActiveBlockFromTerms(terms);
    if (!preferred?.id) return;
    didInitBlockRef.current = true;
    setBlockId(preferred.id);
    if (preferred.termId) setTermId(preferred.termId);
    try {
      localStorage.setItem("rxt-current-block", preferred.id);
    } catch {}
  }, [ready, terms, blockId]);

  useEffect(() => {
    if (typeof window === "undefined") return;
    function handleStorageChange(e) {
      if (e.key !== "rxt-terms" || e.newValue == null) return;
      try {
        const nextTerms = JSON.parse(e.newValue || "[]");
        if (!Array.isArray(nextTerms)) return;
        setTerms(nextTerms);
        const updated = getActiveBlockFromTerms(nextTerms);
        if (updated?.id && updated.id !== blockId) {
          setBlockId(updated.id);
          if (updated.termId) setTermId(updated.termId);
          try {
            localStorage.setItem("rxt-current-block", updated.id);
          } catch {}
        }
      } catch (_) {}
    }
    window.addEventListener("storage", handleStorageChange);
    return () => window.removeEventListener("storage", handleStorageChange);
  }, [blockId]);

  useEffect(() => {
    if (typeof window === "undefined") return;
    localStorage.setItem("rxt-theme", theme);
  }, [theme]);


  useEffect(() => {
    if (typeof window === "undefined") return;
    updateLearningProfile(learningProfile);
  }, [learningProfile]);

  // ── Auto-save ──────────────────────────────
  const save = (t, s, a) => {
    if (!ready) return;
    if (saveRef.current) clearTimeout(saveRef.current);
    setSaveMsg("saving");
    saveRef.current = setTimeout(async () => {
      await sSet("rxt-terms", t);
      await sSet("rxt-sessions", s);
      await sSet("rxt-analyses", a);
      setSaveMsg("saved");
      setTimeout(() => setSaveMsg(""), 2500);
    }, 700);
  };

  useEffect(() => { if (ready) save(terms, sessions, analyses); }, [terms, sessions, analyses, ready]);
  useEffect(() => { if (ready) saveLectures(lectures); }, [lectures, ready]);
  useEffect(() => {
    if (import.meta.env.DEV && typeof window !== "undefined") {
      console.log("Theme tokens loaded. Search codebase for hardcoded bg colors if light mode looks wrong.");
    }
  }, []);

  // ── Derived ────────────────────────────────
  const blockLecs   = getBlockLecs(lectures, resolveBlockMeta(blockId), blockId);
  const sortedLecs = [...blockLecs].sort((a, b) => {
    if (lecSort === "number") {
      if (a.lectureNumber == null && b.lectureNumber == null) return 0;
      if (a.lectureNumber == null) return 1;
      if (b.lectureNumber == null) return -1;
      return a.lectureNumber - b.lectureNumber;
    }
    if (lecSort === "name") {
      return (a.lectureTitle || "").localeCompare(b.lectureTitle || "");
    }
    if (lecSort === "subject") {
      return (a.subject || "").localeCompare(b.subject || "");
    }
    if (lecSort === "score") {
      const aScore = getAvgScore(a.id, sessions);
      const bScore = getAvgScore(b.id, sessions);
      return bScore - aScore;
    }
    if (lecSort === "recent") {
      return new Date(b.uploadedAt || 0) - new Date(a.uploadedAt || 0);
    }
    return 0;
  });
  const groupedByWeek = blockLecs.reduce((acc, lec) => {
    const wk = lec.weekNumber ?? 0;
    if (!acc[wk]) acc[wk] = [];
    acc[wk].push(lec);
    return acc;
  }, {});
  const sortedWeeks = Object.keys(groupedByWeek)
    .map(Number)
    .sort((a, b) => (a === 0 ? 1 : b === 0 ? -1 : a - b));
  const tc          = activeTerm?.color || "#ef4444";

  const bScore = (bid) => {
    const bs = sessions.filter(s => s.blockId === bid);
    if (!bs.length) return null;
    return pct(bs.reduce((a,s)=>a+s.correct,0), bs.reduce((a,s)=>a+s.total,0));
  };

  const selectBlock = (bid) => {
    const term = terms.find((t) => t.blocks?.some((b) => b.id === bid));
    if (!term) return;
    const nextTerms = terms.map((t) => ({
      ...t,
      blocks: (t.blocks || []).map((b) => {
        if (b.id === bid) return { ...b, status: "active" };
        if (b.status === "active") return { ...b, status: "complete" };
        return b;
      }),
    }));
    const flat = nextTerms.flatMap((t) =>
      (t.blocks || []).map((b) => ({ ...b, termId: t.id, termName: t.name }))
    );
    const fullBlock = flat.find((b) => b.id === bid);
    try {
      localStorage.setItem("rxt-terms", JSON.stringify(nextTerms));
    } catch (e) {
      console.error("Failed to update term status:", e);
    }
    setTerms(nextTerms);
    if (fullBlock) setActiveBlock(fullBlock);
    setTermId(term.id);
    try {
      if (typeof window !== "undefined") localStorage.setItem("rxt-current-block", bid);
    } catch {}
    setView("block");
    setTab("lectures");
  };

  // ── Term / Block CRUD ──────────────────────
  const addTerm = () => {
    if (!newTermName.trim()) return;
    setTerms(p => [...p, { id:uid(), name:newTermName.trim(), color: themes[theme]?.blue ?? "#2563eb", blocks:[] }]);
    setNewTermName(""); setShowNewTerm(false);
  };
  const delTerm = (id) => {
    setTerms(p => p.filter(t => t.id !== id));
    setLecs(p => p.filter(l => l.termId !== id));
  };
  const addBlock = (tid) => {
    if (!newBlockName.trim()) return;
    const type = newBlockType || "standard";
    setTerms((p) =>
      p.map((tr) =>
        tr.id === tid
          ? {
              ...tr,
              blocks: [
                ...(tr.blocks || []),
                {
                  id: uid(),
                  name: newBlockName.trim(),
                  type,
                  status: "upcoming",
                  createdAt: new Date().toISOString(),
                },
              ],
            }
          : tr
      )
    );
    setNewBlockName("");
    setNewBlockType("standard");
    setShowNewBlk(null);
  };
  const delBlock = (tid, bid) => {
    setTerms(p => p.map(t => t.id===tid ? { ...t, blocks:t.blocks.filter(b => b.id!==bid) } : t));
    lectures.filter(l => l.blockId===bid).forEach(l => sDel("rxt-lec-"+l.id));
    setLecs(p => p.filter(l => l.blockId !== bid));
    if (activeBlock?.id === bid) {
      setBlockId(null);
      setView("overview");
    }
  };
  const updateBlock = (bid, patch) => {
    setTerms((p) =>
      p.map((t) => ({
        ...t,
        blocks: (t.blocks || []).map((b) =>
          b.id === bid ? { ...b, ...patch } : b
        ),
      }))
    );
    // Keep activeBlock snapshot in sync — otherwise inputs that read from
    // `activeBlock?.foo` (e.g. Block start date) keep showing the old value
    // even though terms state has updated.
    setActiveBlock((prev) => (prev && prev.id === bid ? { ...prev, ...patch } : prev));
  };

  const renameBlock = (bid, name) => {
    if (!name.trim()) return;
    updateBlock(bid, { name: name.trim() });
    setRenamingBlockId(null);
    setRenamingBlockVal("");
  };

  const reorderBlock = (termId, fromIndex, toIndex) => {
    if (fromIndex === toIndex) return;
    setTerms((p) =>
      p.map((t) => {
        if (t.id !== termId) return t;
        const blocks = [...(t.blocks || [])];
        const [moved] = blocks.splice(fromIndex, 1);
        blocks.splice(toIndex, 0, moved);
        return { ...t, blocks };
      })
    );
  };

  const setStatus = (tid, bid, status) => {
    setTerms((p) => {
      let updated = p.map((t) =>
        t.id === tid ? { ...t, blocks: t.blocks.map((b) => (b.id === bid ? { ...b, status } : b)) } : t
      );
      const allBlocks = updated.flatMap((t) => t.blocks || []);
      const isComplete = status === "complete" || status === "completed" || status === "done";
      if (isComplete) {
        const nextBlock = allBlocks.find(
          (b) => b.id !== bid && b.status !== "complete" && b.status !== "completed" && b.status !== "done"
        );
        if (nextBlock) {
          updated = updated.map((t) => ({
            ...t,
            blocks: (t.blocks || []).map((b) => {
              if (b.id === nextBlock.id) return { ...b, status: "active" };
              const isDone = b.status === "complete" || b.status === "completed" || b.status === "done";
              if (b.status === "active" && !isDone) {
                return { ...b, status: "upcoming" };
              }
              return b;
            }),
          }));
          const nextTerm = updated.find((t) => t.blocks?.some((b) => b.id === nextBlock.id));
          queueMicrotask(() => {
            setBlockId(nextBlock.id);
            if (typeof window !== "undefined") localStorage.setItem("rxt-current-block", nextBlock.id);
            if (nextTerm) setTermId(nextTerm.id);
            console.log("Auto-advanced current block to:", nextBlock.name);
          });
        }
      }
      return updated;
    });
  };
  const updateLec = (id, patch) => {
    setLecs(prev => {
      const updated = prev.map(l => l.id === id ? { ...l, ...patch } : l);
      saveLectures(updated);
      return updated;
    });
  };

  const renameLecture = useCallback(
    (lecId, newTitle) => {
      const t = (newTitle || "").trim();
      if (!t) return;
      try {
        updateLec(lecId, { lectureTitle: t });
        window.dispatchEvent(new CustomEvent("rxt-lec-updated"));
      } catch (e) {
        console.error("renameLecture failed:", e);
      }
    },
    [updateLec]
  );

  const deleteLecture = useCallback(
    (lecId, bid) => {
      if (!lecId || !bid) return;
      try {
        const lecs = JSON.parse(localStorage.getItem("rxt-lec-meta") || "[]");
        const lec = (Array.isArray(lecs) ? lecs : []).find((l) => l && l.id === lecId);
        saveTombstone(lec);
        const filtered = lecs.filter((l) => l.id !== lecId);
        safeSetItem("rxt-lec-meta", filtered);
        sDel("rxt-lec-" + lecId);

        const objs = getMSKObjectives(bid);
        const withoutLec = objs.filter((o) => o.linkedLecId !== lecId);
        saveMSKObjectives(bid, withoutLec);

        setLecs((prev) => {
          const next = prev.filter((l) => l.id !== lecId);
          saveLectures(next);
          return next;
        });
        setMergeSelected((prev) => prev.filter((id) => id !== lecId));

        window.dispatchEvent(new CustomEvent("rxt-lec-updated"));
        window.dispatchEvent(new CustomEvent("rxt-objectives-updated"));
        window.dispatchEvent(new CustomEvent("rxt-completion-updated"));
        console.log("Deleted lecture:", lecId);
      } catch (e) {
        console.error("deleteLecture failed:", e);
      }
    },
    [setLecs]
  );

  useEffect(() => {
    const performSignInPush = async (userId) => {
      const now = Date.now();
      const last = handleUserSignedInDedupRef.current;
      if (last.id === userId && now - last.t < 5000) {
        return;
      }
      handleUserSignedInDedupRef.current = { id: userId, t: now };

      try {
        const alreadySyncedThisSession =
          typeof window !== "undefined" && sessionStorage.getItem("rxt-sync-resolved");

        if (alreadySyncedThisSession) {
          clearDebouncedCloudPush();
          await pushAllLocalDataToSupabase(userId).catch(() => {});
          setHasCloudData(true);
          return;
        }

        clearDebouncedCloudPush();
        setSyncStatus("syncing");
        await pushAllLocalDataToSupabase(userId);
        setSyncStatus("synced");
        setHasCloudData(true);
        if (typeof window !== "undefined") {
          sessionStorage.setItem("rxt-sync-resolved", "true");
        }
        console.log("Auto-synced local data to Supabase");
        const hasLocalTerms = typeof window !== "undefined" && localStorage.getItem("rxt-terms");
        if (!hasLocalTerms) {
          setShowImportScreen(true);
        }
      } catch (err) {
        console.warn("Background sync failed:", err);
        setSyncStatus("error");
      }
    };

    supabase.auth.getSession().then(({ data: { session } }) => {
      const u = session?.user ?? null;
      setUser(u);
      setCurrentUser(u);
      setAuthLoading(false);
      if (session?.user && !hasSyncedRef.current) {
        hasSyncedRef.current = true;
        void performSignInPush(session.user.id);
      }
    });

    const {
      data: { subscription },
    } = supabase.auth.onAuthStateChange(async (event, session) => {
      if (event !== "TOKEN_REFRESHED") {
        console.log("Auth event:", event, session?.user?.email);
      }

      if (event === "SIGNED_OUT") {
        clearDebouncedCloudPush();
        if (typeof window !== "undefined") {
          sessionStorage.removeItem("rxt-sync-resolved");
        }
        setUser(null);
        setCurrentUser(null);
        hasSyncedRef.current = false;
        setShowImportScreen(false);
        setHasCloudData(false);
        setSyncStatus(null);
        handleUserSignedInDedupRef.current = { id: null, t: 0 };
        return;
      }

      if (event === "TOKEN_REFRESHED" && session?.user) {
        setCurrentUser(session.user);
        return;
      }

      if (event === "SIGNED_IN" && session?.user) {
        setUser(session.user);
        setCurrentUser(session.user);

        if (hasSyncedRef.current) return;

        hasSyncedRef.current = true;
        void performSignInPush(session.user.id);
        return;
      }

      if (session?.user) {
        setUser(session.user);
        setCurrentUser(session.user);
      }
    });

    return () => {
      subscription?.unsubscribe();
    };
  }, []);

  useEffect(() => {
    if (!user?.id) {
      setHasCloudData(false);
      return;
    }
    let cancelled = false;
    (async () => {
      const { data } = await supabase.from("terms").select("user_id").eq("user_id", user.id).maybeSingle();
      if (!cancelled) setHasCloudData(!!data);
    })();
    return () => {
      cancelled = true;
    };
  }, [user?.id]);

  const reanalyzeLecture = useCallback(
    async (lec) => {
      const text = getLecText(lec);
      if (!text || text.length < 100) {
        setUpMsg("No lecture text to analyze — re-upload the PDF first.");
        setTimeout(() => setUpMsg(""), 3000);
        return;
      }
      try {
        setUpMsg("Analyzing lecture content with AI...");
        const teachingMap = await analyzeLecture(lec, text);
        updateLec(lec.id, {
          teachingMap: teachingMap || null,
          teachingMapDate: teachingMap ? new Date().toISOString() : undefined,
        });
        if (teachingMap?.sections?.length > 0) {
          const bid = lec.blockId;
          setBlockObjectives((prev) => {
            const data = pickBlockObjectivesState(prev, bid);
            const normNoteKey = (t) =>
              String(t || "")
                .slice(0, 55)
                .toLowerCase()
                .replace(/\W/g, "");
            const notesByNormText = new Map();
            for (const o of data.extracted || []) {
              if (o?.linkedLecId !== lec.id || !o?.personalNotes?.trim()) continue;
              const k = normNoteKey(o.objective || o.text);
              if (k) notesByNormText.set(k, o.personalNotes);
            }
            const existingExtracted = (data.extracted || []).filter((o) => o.linkedLecId !== lec.id);
            const aiObjectives = teachingMap.sections.flatMap((section, si) =>
              (section.objectives || []).map((objText) => {
                const nk = normNoteKey(objText);
                const personalNotes = nk ? notesByNormText.get(nk) : undefined;
                return {
                  id: typeof crypto !== "undefined" && crypto.randomUUID ? crypto.randomUUID() : uid(),
                  text: objText,
                  objective: objText,
                  linkedLecId: lec.id,
                  sourceFile: lec.id,
                  lectureType: lec.lectureType,
                  lectureNumber: lec.lectureNumber,
                  sectionIndex: si,
                  status: "untested",
                  bloom_level: 2,
                  bloom_level_name: "Understand",
                  ...(personalNotes ? { personalNotes } : {}),
                };
              })
            );
            const wk = blockObjectivesStorageKey(prev, bid);
            const next = {
              ...prev,
              [wk]: { ...data, extracted: [...existingExtracted, ...aiObjectives] },
            };
            try {
              safeSetItem("rxt-block-objectives", next);
            } catch {}
            return next;
          });
        }
        setUpMsg("Done ✓");
      } catch (err) {
        console.error("Re-analyze failed:", err);
        setUpMsg("Analysis failed: " + (err?.message || String(err)));
      }
      setTimeout(() => setUpMsg(""), 4000);
    },
    [updateLec, setBlockObjectives, setUpMsg]
  );

  const getLecPerf = useCallback(
    (lec, bid) => {
      // ONLY use exact key match — never fall back to lecture number matching.
      // Lecture number matching causes LEC1 from one session to bleed into
      // a newly uploaded LEC1.
      const exactKey = makeTopicKey(lec.id, bid);
      if (performanceHistory[exactKey]) return performanceHistory[exactKey];
      // Secondary: startsWith lec.id — catches old key formats for THIS lecture
      const byId = Object.keys(performanceHistory || {}).find((k) =>
        k.startsWith(lec.id + "__")
      );
      if (byId) return performanceHistory[byId];
      // STOP HERE — do not fall back to lecture number matching.
      // A new upload with the same lecture number must start fresh.
      return null;
    },
    [makeTopicKey, performanceHistory]
  );

  const blockSessionCount = useMemo(() => {
    try {
      if (!activeBlock?.id) return 0;
      const blockLecs = JSON.parse(localStorage.getItem("rxt-lec-meta") || "[]").filter(
        (l) => l.blockId === activeBlock.id
      );
      const perf = JSON.parse(localStorage.getItem("rxt-performance") || "{}");
      let total = 0;
      blockLecs.forEach((lec) => {
        const key = `${lec.id}__${activeBlock.id}`;
        const entry = perf[key];
        if (Array.isArray(entry?.sessions)) {
          total += entry.sessions.length;
        } else if (typeof entry?.sessions === "number") {
          total += entry.sessions;
        }
      });
      const sessions = JSON.parse(localStorage.getItem("rxt-sessions") || "[]");
      const blockSessions = sessions.filter((s) => s.blockId === activeBlock.id).length;
      return Math.max(total, blockSessions);
    } catch (e) {
      return 0;
    }
  }, [activeBlock?.id, refreshKey]);

  const blockAvgScore = useMemo(() => {
    try {
      if (!activeBlock?.id) return 0;
      const blockLecs = JSON.parse(localStorage.getItem("rxt-lec-meta") || "[]").filter(
        (l) => l.blockId === activeBlock.id
      );
      const perf = JSON.parse(localStorage.getItem("rxt-performance") || "{}");
      const scores = [];
      blockLecs.forEach((lec) => {
        const key = `${lec.id}__${activeBlock.id}`;
        if (perf[key]?.score != null) {
          scores.push(Number(perf[key].score));
        }
      });
      if (scores.length === 0) return 0;
      return Math.round(scores.reduce((a, b) => a + b, 0) / scores.length);
    } catch (e) {
      return 0;
    }
  }, [activeBlock?.id, refreshKey]);

  const blockStreak = useMemo(() => {
    try {
      if (!activeBlock?.id) return 0;
      const comp = JSON.parse(localStorage.getItem("rxt-completion") || "{}");
      const blockLecs = JSON.parse(localStorage.getItem("rxt-lec-meta") || "[]").filter(
        (l) => l.blockId === activeBlock.id
      );
      const activityDates = new Set();
      blockLecs.forEach((lec) => {
        const key = `${lec.id}__${activeBlock.id}`;
        const entry = comp[key];
        if (!entry?.activityLog) return;
        entry.activityLog.forEach((log) => {
          if (log?.date) activityDates.add(log.date.split("T")[0]);
        });
      });
      if (activityDates.size === 0) return 0;
      let streak = 0;
      const today = new Date();
      for (let i = 0; i < 365; i++) {
        const date = new Date(today);
        date.setDate(date.getDate() - i);
        const dateStr = date.toISOString().split("T")[0];
        if (activityDates.has(dateStr)) {
          streak++;
        } else if (i > 0) {
          break;
        }
      }
      return streak;
    } catch (e) {
      return 0;
    }
  }, [activeBlock?.id, refreshKey]);

  const blockLevel = useMemo(() => {
    const score = blockAvgScore;
    if (score >= 80) return "HIGH";
    if (score >= 60) return "MEDIUM";
    if (score >= 40) return "LOW";
    return "BEGINNER";
  }, [blockAvgScore]);

  const blockTrend = useMemo(() => {
    try {
      if (!activeBlock?.id) return "→ Stable";
      const perf = JSON.parse(localStorage.getItem("rxt-performance") || "{}");
      const blockLecs = JSON.parse(localStorage.getItem("rxt-lec-meta") || "[]").filter(
        (l) => l.blockId === activeBlock.id
      );
      const scoredEntries = [];
      blockLecs.forEach((lec) => {
        const key = `${lec.id}__${activeBlock.id}`;
        const entry = perf[key];
        if (entry?.score != null && entry?.date) {
          scoredEntries.push({
            score: Number(entry.score),
            date: entry.date,
          });
        }
      });
      if (scoredEntries.length < 2) return "→ Stable";
      scoredEntries.sort((a, b) => new Date(a.date) - new Date(b.date));
      const recent = scoredEntries.slice(-3);
      const older = scoredEntries.slice(0, -3);
      if (older.length === 0) return "→ Stable";
      const recentAvg = recent.reduce((s, e) => s + e.score, 0) / recent.length;
      const olderAvg = older.reduce((s, e) => s + e.score, 0) / older.length;
      const diff = recentAvg - olderAvg;
      if (diff > 5) return "↑ Improving";
      if (diff < -5) return "↓ Declining";
      return "→ Stable";
    } catch (e) {
      return "→ Stable";
    }
  }, [activeBlock?.id, refreshKey]);

  const blockChartSessions = useMemo(() => {
    try {
      if (!activeBlock?.id) return [];
      const perf = JSON.parse(localStorage.getItem("rxt-performance") || "{}");
      const blockLecs = JSON.parse(localStorage.getItem("rxt-lec-meta") || "[]").filter(
        (l) => l.blockId === activeBlock.id
      );
      const all = [];
      blockLecs.forEach((lec) => {
        const key = `${lec.id}__${activeBlock.id}`;
        const entry = perf[key];
        if (Array.isArray(entry?.sessions)) {
          entry.sessions.forEach((s) => {
            if (s?.score != null) all.push({ score: Number(s.score), date: s.date || "" });
          });
        }
      });
      all.sort((a, b) => new Date(a.date || 0) - new Date(b.date || 0));
      return all;
    } catch (e) {
      return [];
    }
  }, [activeBlock?.id, refreshKey]);

  const getLectureSubtopicCompletion = useCallback(
    (lec, bid) => {
      if (!lec?.subtopics?.length) {
        const perf = getLecPerf(lec, bid);
        const sessions = perf?.sessions?.length || 0;
        return Math.min(100, sessions * 33);
      }
      const subCompletions = (lec.subtopics || []).map((_, si) => {
        const subKey = makeSubtopicKey(lec.id, si, bid);
        return performanceHistory[subKey]?.completion || 0;
      });
      if (!subCompletions.length) return 0;
      return Math.round(subCompletions.reduce((a, b) => a + b, 0) / subCompletions.length);
    },
    [getLecPerf, makeSubtopicKey, performanceHistory]
  );

  const getLecCompletion = useCallback(
    (lec, blockId) => {
      const blockObjs = getBlockObjectives(blockId) || [];
      const lecObjs = blockObjs.filter(
        (o) =>
          o.linkedLecId === lec.id ||
          (lec.mergedFrom || []).some((m) => m && m.id === o.linkedLecId)
      );
      if (lecObjs.length === 0) {
        const perf = getLecPerf(lec, blockId);
        const sessions = perf?.sessions?.length || 0;
        return Math.min(100, sessions * 33);
      }
      const mastered = lecObjs.filter((o) => o.status === "mastered").length;
      const inProgress = lecObjs.filter((o) => o.status === "inprogress").length;
      const total = lecObjs.length;
      return Math.round(((mastered + inProgress * 0.5) / total) * 100);
    },
    [getBlockObjectives, getLecPerf]
  );

  const getSubtopicCompletion = useCallback(
    (lec, si, subName, blockId) => {
      const blockObjs = getBlockObjectives(blockId) || [];
      const lecObjs = blockObjs.filter(
        (o) =>
          o.linkedLecId === lec.id ||
          (lec.mergedFrom || []).some((m) => m && m.id === o.linkedLecId)
      );
      if (lecObjs.length === 0) {
        return { pct: 0, mastered: 0, total: 0, sessions: 0, weakness: null };
      }
      const objsToUse = matchObjectivesToSubtopic(subName, lecObjs);
      if (objsToUse.length === 0) {
        const lecPct = getLecCompletion(lec, blockId);
        return {
          pct: lecPct,
          mastered: 0,
          total: 0,
          sessions: 0,
          weakness: null,
        };
      }
      const mastered = objsToUse.filter((o) => o.status === "mastered").length;
      const inProgress = objsToUse.filter((o) => o.status === "inprogress").length;
      const struggling = objsToUse.filter((o) => o.status === "struggling").length;
      const untested = objsToUse.filter((o) => o.status === "untested").length;
      const total = objsToUse.length;
      const pct = Math.round(((mastered + inProgress * 0.5) / total) * 100);
      const weakness =
        struggling > 0
          ? "critical"
          : pct < 50 && untested > 0
            ? "weak"
            : pct < 80 && total > 0
              ? "review"
              : null;
      const subKey = makeSubtopicKey(lec.id, si, blockId);
      const subPerf = performanceHistory[subKey];
      const sessions = subPerf?.sessions?.length || 0;
      return {
        pct,
        mastered,
        total,
        sessions,
        lastScore: subPerf?.lastScore,
        weakness,
      };
    },
    [getBlockObjectives, getLecCompletion, makeSubtopicKey, performanceHistory]
  );

  const currentWeek = useMemo(() => {
    const bid = activeBlock?.id ?? blockId;
    const plan = buildStudySchedule(bid);
    const todayKey = new Date().toISOString().slice(0, 10);
    const todaySessions = plan?.schedule.find(([d]) => d === todayKey)?.[1] || [];
    if (todaySessions.length > 0) {
      const todayLecId = todaySessions[0]?.lectureId;
      const todayLec = lectures.find((l) => l.id === todayLecId);
      if (todayLec?.weekNumber) return todayLec.weekNumber;
    }
    const blockLecsForWeek = getBlockLecs(lectures, resolveBlockMeta(bid));
    const weekScores = {};
    blockLecsForWeek.forEach((l) => {
      if (!l.weekNumber) return;
      const perf = getLecPerf(l, bid);
      const last = perf?.sessions?.slice(-1)[0];
      if (last) {
        if (!weekScores[l.weekNumber] || new Date(last.date) > new Date(weekScores[l.weekNumber])) {
          weekScores[l.weekNumber] = last.date;
        }
      }
    });
    const mostRecent = Object.entries(weekScores).sort(
      (a, b) => new Date(b[1]) - new Date(a[1])
    )[0];
    if (mostRecent) return parseInt(mostRecent[0], 10);
    const untestedByWeek = {};
    blockLecsForWeek.forEach((l) => {
      if (!l.weekNumber) return;
      const objs = (getBlockObjectives(bid) || []).filter(
        (o) =>
          o.linkedLecId === l.id ||
          (l.mergedFrom || []).some((m) => m && m.id === o.linkedLecId)
      );
      const untested = objs.filter((o) => o.status === "untested").length;
      untestedByWeek[l.weekNumber] = (untestedByWeek[l.weekNumber] || 0) + untested;
    });
    const mostUntested = Object.entries(untestedByWeek).sort((a, b) => b[1] - a[1])[0];
    return mostUntested ? parseInt(mostUntested[0], 10) : 1;
  }, [activeBlock?.id, blockId, lectures, performanceHistory, buildStudySchedule, getBlockObjectives, getLecPerf, resolveBlockMeta]);

  const [bulkWeekTarget, setBulkWeekTarget] = useState(null);
  const [collapsedCardWeeks, setCollapsedCardWeeks] = useState(() => new Set());
  const toggleCardWeek = useCallback((wk) => {
    setCollapsedCardWeeks((prev) => {
      const next = new Set(prev);
      if (next.has(wk)) next.delete(wk);
      else next.add(wk);
      return next;
    });
  }, []);
  useEffect(() => {
    const bid = activeBlock?.id ?? blockId;
    const unassigned = getBlockLecs(lectures, resolveBlockMeta(bid)).filter((l) => !l.weekNumber);
    if (unassigned.length === 0) setBulkWeekTarget(null);
  }, [lectures, activeBlock?.id, blockId, resolveBlockMeta]);
  useEffect(() => {
    const toCollapse = new Set(sortedWeeks.filter((wk) => wk !== currentWeek && wk !== 0));
    setCollapsedCardWeeks(toCollapse);
  }, [currentWeek, sortedWeeks.join(",")]);
  const delLec = (id) => {
    setLecs((prev) => {
      const removed = prev.find((l) => l.id === id);
      if (removed) saveLectureIdTombstone(removed);
      const next = prev.filter((l) => l.id !== id);
      (async () => {
        await sDel("rxt-lec-" + id);
        await saveLectures(next);
      })();
      return next;
    });
  };

  const clearBlockLectures = () => {
    if (!blockId || !activeBlock) return;
    if (!window.confirm("Delete all " + blockLecs.length + " lecture" + (blockLecs.length !== 1 ? "s" : "") + " in " + activeBlock.name + "? This cannot be undone.")) return;
    const ids = blockLecs.map((l) => l.id);
    setLecs((prev) => {
      const toRemove = prev.filter((l) => l.blockId === blockId);
      toRemove.forEach((l) => saveLectureIdTombstone(l));
      const next = prev.filter((l) => l.blockId !== blockId);
      (async () => {
        for (const id of ids) await sDel("rxt-lec-" + id);
        await saveLectures(next);
      })();
      return next;
    });
  };

  const onMergeToggle = (id) => {
    setMergeSelected(prev =>
      prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]
    );
  };

  const executeMerge = (ids) => {
    const toLectures = ids.map(id => lectures.find(l => l.id === id)).filter(Boolean);
    if (toLectures.length < 2) return;
    setMergeConfig({ lectures: toLectures, open: true });
  };

  const confirmMerge = ({ title, subject, lecNum, lecType, strategy, keepOriginals, lectures: toMerge }) => {
    const primary = toMerge[0];
    const secondary = toMerge.slice(1);

    let mergedChunks = [];
    if (strategy === "append") {
      mergedChunks = [
        ...(primary.chunks || []),
        ...secondary.flatMap(l => l.chunks || []),
      ];
    } else if (strategy === "interleave") {
      const maxLen = Math.max(...toMerge.map(l => l.chunks?.length || 0));
      for (let i = 0; i < maxLen; i++) {
        for (const l of toMerge) {
          if (l.chunks?.[i]) mergedChunks.push(l.chunks[i]);
        }
      }
    } else {
      mergedChunks = [...(primary.chunks || [])];
    }

    const mergedSubtopics = [...new Set(toMerge.flatMap(l => l.subtopics || []))];
    const mergedKeyTerms = [...new Set(toMerge.flatMap(l => l.keyTerms || []))];
    const mergedFullText = toMerge.map(l => l.fullText || "").filter(Boolean).join("\n\n---\n\n");

    const mergedId = "merged_" + Date.now();
    const sourceLecIds = new Set(toMerge.map(l => l.id));
    const blockId = primary.blockId;

    const mergedLec = {
      ...primary,
      id: mergedId,
      lectureTitle: title || primary.lectureTitle,
      subject: subject || primary.subject,
      lectureNumber: lecNum,
      lectureType: lecType,
      chunks: mergedChunks,
      fullText: mergedFullText || primary.fullText,
      subtopics: mergedSubtopics,
      keyTerms: mergedKeyTerms,
      isMerged: true,
      mergedFrom: toMerge.map(l => ({
        id: l.id,
        title: l.lectureTitle || l.filename,
        num: l.lectureNumber,
      })),
      uploadedAt: new Date().toISOString(),
    };

    setLecs(prev => {
      const idsToRemove = keepOriginals ? [] : toMerge.map(l => l.id);
      const filtered = prev.filter(l => !idsToRemove.includes(l.id));
      const updated = [...filtered, mergedLec];
      saveLectures(updated);
      return updated;
    });

    // Re-link objectives that belonged to either source lecture to the merged lecture; also link unlinked objectives that match merged lecture by type+number or activity
    const mergedLecTypeNorm = (lecType || "LEC").toString().toUpperCase().replace(/^LECTURE$|^LECT/i, "LEC");
    const mergedLecNumStr = String(lecNum ?? "");
    const mergedActivityNorm = mergedLecNumStr ? (mergedLecTypeNorm + mergedLecNumStr) : "";
    setBlockObjectives(prev => {
      const data = pickBlockObjectivesState(prev, blockId);
      const wk = blockObjectivesStorageKey(prev, blockId);
      const relink = (obj) =>
        sourceLecIds.has(obj.linkedLecId) ? { ...obj, linkedLecId: mergedId, sourceFile: mergedId } : obj;
      const linkToMergedIfMatch = (obj) => {
        const afterRelink = relink(obj);
        if (afterRelink.linkedLecId === mergedId) return afterRelink;
        const objTypeNorm = (obj.lectureType || "LEC").toString().toUpperCase().replace(/^LECTURE$|^LECT/i, "LEC");
        const objNumStr = String(obj.lectureNumber ?? "");
        const matchesTypeNum = objTypeNorm === mergedLecTypeNorm && objNumStr === mergedLecNumStr;
        const objActNorm = (obj.activity || "").toUpperCase().replace(/\s+/g, "").trim();
        const matchesActivity = mergedActivityNorm && (objActNorm === mergedActivityNorm || objActNorm === mergedLecTypeNorm + " " + mergedLecNumStr);
        if (matchesTypeNum || matchesActivity) return { ...afterRelink, linkedLecId: mergedId, sourceFile: mergedId };
        return afterRelink;
      };
      const updatedImported = (data.imported || []).map(linkToMergedIfMatch);
      const updatedExtracted = (data.extracted || []).map(linkToMergedIfMatch);
      const next = { ...prev, [wk]: { ...data, imported: updatedImported, extracted: updatedExtracted } };
      try {
        safeSetItem("rxt-block-objectives", next);
      } catch (e) {
        console.warn("Failed to persist objectives after merge:", e);
      }
      return next;
    });

    setMergeConfig({ open: false, lectures: [] });
    setMergeMode(false);
    setMergeSelected([]);
  };

  // ── Upload (single place for all lecture uploads) ────────────────────────
  const onFileParsed = (filename, questions) => {
    if (!questions?.length) return;
    try {
      const next = JSON.parse(localStorage.getItem("rxt-question-banks") || "{}");
      next[filename] = questions;
      localStorage.setItem("rxt-question-banks", JSON.stringify(next));
    } catch (e) {
      console.warn("Failed to save question bank:", e);
    }
  };

  const processUploadQueue = async () => {
    if (isProcessingQueueRef.current) return;
    isProcessingQueueRef.current = true;
    setIsProcessingQueue(true);
    setUploading(true);
    logUploadPhase("queue", "queue_batch_start", {
      queued: uploadQueueRef.current.filter((i) => i.status === "queued").length,
    });
    let added = 0;
    let failed = 0;
    const addedInBatch = new Set();

    const commitPdfTail = async ({
      lectureToSave,
      contentResult,
      extractedObjectives,
      extractMethodUsed,
      teachingMap,
      file,
      queueId,
      bid,
      skipSetLecs,
      textQualityAssessment = null,
      replacedLectureOldId = null,
    }) => {
      if (teachingMap?.sections?.length > 0) {
        setUpMsg("Mapping objectives to content...");
        if (bid === "cpr1") {
          const teachingRows = teachingMap.sections.flatMap((section, si) =>
            (section.objectives || []).map((objText) => ({
              text: objText,
              objective: objText,
              lectureType: lectureToSave.lectureType,
              lectureNumber: lectureToSave.lectureNumber,
              sectionIndex: si,
              status: "untested",
              bloom_level: 2,
              bloom_level_name: "Understand",
            }))
          );
          const mergedTeaching = await saveExtractedObjectivesForLecture(
            lectureToSave.id,
            bid,
            teachingRows,
            replacedLectureOldId ? [replacedLectureOldId] : []
          );
          setBlockObjectives((prev) => ({ ...prev, [bid]: mergedTeaching }));
        } else {
          setBlockObjectives((prev) => {
            // Legacy shape: prev[bid] may be a flat array. Normalize first so we
            // never lose existing items by spreading them as numeric keys.
            const data = pickBlockObjectivesState(prev, bid);
            const normNoteKey = (t) =>
              String(t || "")
                .slice(0, 55)
                .toLowerCase()
                .replace(/\W/g, "");
            const notesByNormText = new Map();
            for (const o of data.extracted || []) {
              if (o?.linkedLecId !== lectureToSave.id || !o?.personalNotes?.trim()) continue;
              const k = normNoteKey(o.objective || o.text);
              if (k) notesByNormText.set(k, o.personalNotes);
            }
            const existingExtracted = (data.extracted || []).filter((o) => o.linkedLecId !== lectureToSave.id);
            const aiObjectives = teachingMap.sections.flatMap((section, si) =>
              (section.objectives || []).map((objText) => {
                const nk = normNoteKey(objText);
                const personalNotes = nk ? notesByNormText.get(nk) : undefined;
                return {
                  id: typeof crypto !== "undefined" && crypto.randomUUID ? crypto.randomUUID() : uid(),
                  text: objText,
                  objective: objText,
                  linkedLecId: lectureToSave.id,
                  sourceFile: lectureToSave.id,
                  lectureType: lectureToSave.lectureType,
                  lectureNumber: lectureToSave.lectureNumber,
                  sectionIndex: si,
                  status: "untested",
                  bloom_level: 2,
                  bloom_level_name: "Understand",
                  ...(personalNotes ? { personalNotes } : {}),
                };
              })
            );
            const next = {
              ...prev,
              [bid]: {
                imported: data.imported,
                extracted: [...existingExtracted, ...aiObjectives],
              },
            };
            try {
              safeSetItem("rxt-block-objectives", next);
            } catch {}
            return next;
          });
        }
      }

      updateQueueItem(queueId, { status: "linking", progress: 72 });
      setTimeout(() => updateQueueItem(queueId, { progress: 90 }), 30);
      setUpMsg("Saving lecture...");
      if (!skipSetLecs) {
        await new Promise((resolve) => {
          setLecs((prev) => {
            const hasNum = lectureToSave.lectureNumber != null && String(lectureToSave.lectureNumber).trim() !== "";
            const filtered = prev.filter((l) => {
              if (hasNum) {
                return !(
                  l.blockId === bid &&
                  (l.lectureType || "LEC").trim() === (lectureToSave.lectureType || "LEC").trim() &&
                  String(l.lectureNumber).trim() === String(lectureToSave.lectureNumber).trim()
                );
              }
              return !(l.blockId === bid && l.filename === file.name);
            });
            const updated = [...filtered, lectureToSave];
            saveLectures(updated)
              .then(() => {
                migrateOrphanedRecords(lectureToSave, setPerformanceHistory);
              })
              .catch(() => {})
              .finally(resolve);
            return updated;
          });
        });
      } else {
        migrateOrphanedRecords(lectureToSave, setPerformanceHistory);
      }
      reconcileCompletionOnUpload(lectureToSave);
      migratePerformanceOnUpload(lectureToSave, bid, lectures, setPerformanceHistory);
      setUpMsg("Done ✓");
      setTimeout(() => setUpMsg(""), 2000);

      setBlockObjectives((prev) => {
        const blockData = prev[bid] || { imported: [], extracted: [] };
        const blockLecs = [...(lectures || []).filter((l) => l.blockId === bid), lectureToSave];
        let repaired = 0;
        const repair = (obj) => {
          const stillLinked = blockLecs.some((l) => l.id === obj.linkedLecId);
          if (
            !stillLinked &&
            String(obj.lectureType) === String(lectureToSave.lectureType) &&
            String(obj.lectureNumber) === String(lectureToSave.lectureNumber)
          ) {
            repaired++;
            return { ...obj, linkedLecId: lectureToSave.id, sourceFile: lectureToSave.id };
          }
          return obj;
        };
        const imported = (blockData.imported || []).map(repair);
        const extracted = (blockData.extracted || []).map(repair);
        if (repaired === 0) return prev;
        const next = { ...prev, [bid]: { ...blockData, imported, extracted } };
        try {
          safeSetItem("rxt-block-objectives", next);
        } catch {}
        return next;
      });

      if (contentResult.questions?.length) {
        onFileParsed(file.name, contentResult.questions);
      }

      let objectivesForSave = Array.isArray(extractedObjectives) ? extractedObjectives : [];
      const bidIsCprCommit = String(bid || "").toLowerCase().startsWith("cpr");
      if (
        objectivesForSave.length === 0 &&
        bidIsCprCommit &&
        lectureToSave?.chunks?.length
      ) {
        console.log("No objectives from pipeline — trying inline SOM before save");
        setUpMsg("Deriving objectives from slide content…");
        objectivesForSave = await extractInlineSOMCodes(
          lectureToSave.chunks,
          lectureToSave,
          bid,
          new Set()
        );
        console.log(`Inline SOM fallback found: ${objectivesForSave.length}`);
      }

      if (objectivesForSave.length > 0) {
        if (bid === "cpr1") {
          await trySaveCPRLectureExtractedObjectives(
            bid,
            lectureToSave,
            objectivesForSave,
            true,
            replacedLectureOldId
          );
        } else {
          const oldLecId = lectures.find((l) => l.blockId === bid && l.filename === file.name)?.id ?? null;
          const dropLecIds = new Set([oldLecId, replacedLectureOldId].filter(Boolean));
          setBlockObjectives((prev) => {
            // Legacy shape: prev[bid] may be a flat array. Normalize first so we
            // never lose existing items by spreading them as numeric keys.
            const blockData = pickBlockObjectivesState(prev, bid);
            const blockLecs = [...lectures.filter((l) => l.blockId === bid), lectureToSave];
            const isOrphan = (obj) =>
              String(obj.lectureType) === String(lectureToSave.lectureType) &&
              String(obj.lectureNumber) === String(lectureToSave.lectureNumber) &&
              !blockLecs.some((l) => l.id === obj.linkedLecId);
            const cleanedImported = (blockData.imported || []).filter((obj) => !isOrphan(obj));
            const cleanedExtracted = (blockData.extracted || []).filter((obj) => !isOrphan(obj));
            const existing = cleanedExtracted;
            let existingFiltered = existing;
            if (dropLecIds.size > 0) {
              existingFiltered = existing.filter(
                (obj) => !dropLecIds.has(obj.linkedLecId) && !dropLecIds.has(obj.sourceFile)
              );
            } else {
              existingFiltered = existing.filter(
                (obj) =>
                  !(
                    String(obj.lectureType) === String(lectureToSave.lectureType) &&
                    String(obj.lectureNumber) === String(lectureToSave.lectureNumber)
                  )
              );
            }
            const existingKeys = new Set(
              existingFiltered.map((o) => (o.objective || "").slice(0, 55).toLowerCase().replace(/\W/g, ""))
            );
            const flatForNotes = getMSKObjectives(bid);
            const newOnes = objectivesForSave
              .filter(
                (o) => !existingKeys.has((o.objective || "").slice(0, 55).toLowerCase().replace(/\W/g, ""))
              )
              .map((o) => {
                const enriched = enrichObjectiveWithBloom(o, lectureToSave.lectureType || "LEC");
                const id =
                  enriched.id ||
                  (typeof crypto !== "undefined" && crypto.randomUUID ? crypto.randomUUID() : uid());
                const existingSameId = flatForNotes.find((e) => e.id === id);
                const personalNotes =
                  existingSameId?.personalNotes != null && String(existingSameId.personalNotes).trim()
                    ? existingSameId.personalNotes
                    : enriched.personalNotes;
                return {
                  ...enriched,
                  id,
                  linkedLecId: lectureToSave.id,
                  lectureType: lectureToSave.lectureType,
                  lectureNumber: lectureToSave.lectureNumber,
                  activity: activityForLectureSave(enriched, lectureToSave),
                  sourceFile: lectureToSave.id,
                  ...(personalNotes ? { personalNotes } : {}),
                };
              });
            const updatedExtracted = [...existingFiltered, ...newOnes];
            const allLectures = [...lectures.filter((l) => l.blockId === bid), lectureToSave];
            const alignedImported = alignObjectivesToLectures(bid, cleanedImported, allLectures);
            const updated = {
              ...prev,
              [bid]: { imported: alignedImported, extracted: updatedExtracted },
            };
            try {
              safeSetItem("rxt-block-objectives", updated);
            } catch {}
            return updated;
          });
        }
      } else {
        console.log("No objectives to save — skipping write");
      }

      const objCount = objectivesForSave.length;
      const qCount = contentResult.questions?.length || 0;
      const aiObjCount = teachingMap?.sections?.length
        ? teachingMap.sections.flatMap((s) => s.objectives || []).length
        : 0;
      const totalObjCount = objectivesForSave.length + aiObjCount;
      const nExtract = objectivesForSave.length;
      const typeLabel = String(lectureToSave.lectureType || "LEC")
        .replace(/^LECTURE$/i, "LEC")
        .slice(0, 4);
      const numPart =
        lectureToSave.lectureNumber != null && String(lectureToSave.lectureNumber).trim() !== ""
          ? String(lectureToSave.lectureNumber)
          : null;
      const extLab = extractionMethodSuffix(extractMethodUsed);
      let resultSummary;
      let resultSummaryColor = "#27500A";
      if (
        (extractMethodUsed === "none" || extractMethodUsed === "error") &&
        !(contentResult.fullText || "").trim()
      ) {
        resultSummary = "⚠ No text extracted — is this a scanned PDF?";
        resultSummaryColor = "#BA7517";
      } else if (numPart != null) {
        if (nExtract === 0) {
          resultSummary = `⚠ ${typeLabel} ${numPart} · 0 objectives found — PDF may be image-based${
            extLab ? " · " + extLab : ""
          }`;
          resultSummaryColor = "#BA7517";
        } else if (nExtract < 3) {
          resultSummary = `△ ${typeLabel} ${numPart} · ${nExtract} objectives — may be incomplete${
            extLab ? " · " + extLab : ""
          }`;
          resultSummaryColor = "#BA7517";
        } else {
          resultSummary = `✓ ${typeLabel} ${numPart} · ${nExtract} objectives${extLab ? " · " + extLab : ""}`;
        }
      } else {
        resultSummary = `✓ Uploaded · ${nExtract} objectives${extLab ? " · " + extLab : ""}`;
      }
      const textQualityWarning =
        textQualityAssessment?.quality === "poor" && textQualityAssessment?.reason
          ? `⚠ Poor text quality — ${textQualityAssessment.reason}. Try Mistral OCR for better results.`
          : null;
      const showEnableOcr =
        !!textQualityWarning &&
        !!import.meta.env.VITE_MISTRAL_API_KEY &&
        extractMethodUsed !== "mistral-ocr";
      updateQueueItem(queueId, {
        status: "done",
        progress: 100,
        result: {
          lectureId: lectureToSave.id,
          lectureType: lectureToSave.lectureType,
          lectureNumber: lectureToSave.lectureNumber,
          objectiveCount: totalObjCount,
          resultSummary,
          resultSummaryColor,
          textQualityWarning,
          showEnableOcr,
          extractMethod: extractMethodUsed,
          typeWarning: shouldWarnLectureTypeBadge(lectureToSave.lectureType, file.name),
        },
      });
      if (Array.isArray(lectureToSave?.subtopics) && lectureToSave.subtopics.length > 0) {
        window.setTimeout(() => stampLectureObjectivesWithSubtopics(bid, lectureToSave), 450);
      }
      markAsProcessed(file, bid);
      setUpMsg(
        "Done ✓ — " +
          file.name +
          (qCount > 0 ? " · " + qCount + " questions" : "") +
          (objCount > 0 ? " · " + objCount + " objectives" : " · objectives aligned")
      );
    };

    const mergePartBIntoPartA = async (filB, partALecSnapshot, queueId, bid) => {
      updateQueueItem(queueId, { status: "extracting", progress: 5 });
      setUpMsg("📖 Extracting Part B…");
      const forceOcr = uploadForceOcrQueueIdRef.current.has(queueId);
      if (forceOcr) uploadForceOcrQueueIdRef.current.delete(queueId);
      const tMergeEx = typeof performance !== "undefined" ? performance.now() : 0;
      const { contentResult: cr0, method: extractMethodUsed } = await extractWithSmartFallback(
        filB,
        (msg) => setUpMsg(msg),
        { forceMistralOcr: forceOcr }
      );
      if (typeof performance !== "undefined") {
        logUploadPhase(queueId, "merge_partB_extract", { method: extractMethodUsed }, performance.now() - tMergeEx);
      }
      const textB = (cr0.fullText || (cr0.chunks || []).map((c) => getChunkBody(c)).join("\n\n") || "").trim();
      const chunksB =
        cr0.chunks && cr0.chunks.length > 0 ? cr0.chunks : textB ? [{ text: textB }] : [];

      let allLecs = [];
      try {
        allLecs = JSON.parse(localStorage.getItem("rxt-lec-meta") || "[]");
      } catch {
        allLecs = [];
      }
      const idx = allLecs.findIndex((l) => l.id === partALecSnapshot.id);
      if (idx === -1) throw new Error("Part A lecture not found");

      const partA = allLecs[idx];
      const mergedChunks = [...(partA.chunks || []), { text: "\n\n--- Part B ---\n\n" }, ...chunksB];
      const combinedBodyFromChunks = mergedChunks.map((c) => getChunkBody(c)).join("\n\n");

      let mergedTitle = (partA.lectureTitle || "")
        .replace(/_Part A_/gi, " ")
        .replace(/\s*[-–(]\s*part\s*[a-z0-9]+\s*[)]*\s*$/i, "")
        .replace(/\s*[-–]\s*[A-Z]\s*$/i, "")
        .replace(/\s+/g, " ")
        .trim();
      if (!mergedTitle) mergedTitle = (partA.filename || "Lecture").replace(/\.pdf$/i, "");

      const mergedFilename = `${mergedTitle} (Parts A+B)`;

      let mergedLec = {
        ...partA,
        lectureTitle: mergedTitle,
        filename: mergedFilename,
        chunks: mergedChunks,
        fullText: combinedBodyFromChunks,
        mergedFrom: [
          { id: partA.id, title: partA.filename || partA.lectureTitle, num: partA.lectureNumber },
          { id: partA.id, title: filB.name, num: partA.lectureNumber, partLabel: "B" },
        ],
        mergedAt: new Date().toISOString(),
        partABMerged: true,
        extractionMethod: cr0.extractionMethod || partA.extractionMethod,
        pageCount: (partA.pageCount || 0) + (cr0.pageCount || chunksB.length || 0),
      };

      allLecs[idx] = mergedLec;
      try {
        localStorage.setItem("rxt-lec-meta", JSON.stringify(allLecs));
      } catch (e) {
        console.error("mergePartBIntoPartA persist failed:", e);
      }

      setLecs((prev) => {
        const without = prev.filter((l) => l.id !== mergedLec.id);
        const updated = [...without, mergedLec];
        saveLectures(updated);
        return updated;
      });

      updateQueueItem(queueId, { status: "parsing", progress: 45 });
      setUpMsg("🎯 Extracting learning objectives (merged)…");

      let nObj = 0;
      try {
        const out = await extractAndSaveObjectivesForMergedLecture(mergedLec, bid, { alsoDropLinkedLecIds: [] });
        nObj = out.count;
      } catch (e) {
        console.warn("merge extractAndSaveObjectivesForMergedLecture:", e);
      }

      updateQueueItem(queueId, { status: "parsing", progress: 72 });
      setUpMsg("Analyzing merged lecture…");
      let teachingMap = null;
      try {
        teachingMap = await analyzeLecture(mergedLec, getLecText(mergedLec));
      } catch (e) {
        console.warn("merge analyzeLecture:", e);
      }

      if (teachingMap) {
        mergedLec = {
          ...mergedLec,
          teachingMap,
          teachingMapDate: new Date().toISOString(),
        };
        try {
          const fresh = JSON.parse(localStorage.getItem("rxt-lec-meta") || "[]");
          const fi = fresh.findIndex((l) => l.id === mergedLec.id);
          if (fi >= 0) {
            fresh[fi] = { ...fresh[fi], teachingMap, teachingMapDate: mergedLec.teachingMapDate };
            localStorage.setItem("rxt-lec-meta", JSON.stringify(fresh));
          }
        } catch (e) {
          console.warn("merge teaching map persist:", e);
        }
        setLecs((prev) => {
          const updated = prev.map((l) => (l.id === mergedLec.id ? mergedLec : l));
          saveLectures(updated);
          return updated;
        });
      }

      reconcileCompletionOnUpload(mergedLec);
      migratePerformanceOnUpload(mergedLec, bid, lectures, setPerformanceHistory);

      const typeLabel = String(mergedLec.lectureType || "LEC")
        .replace(/^LECTURE$/i, "LEC")
        .slice(0, 4);
      const numPart =
        mergedLec.lectureNumber != null && String(mergedLec.lectureNumber).trim() !== ""
          ? String(mergedLec.lectureNumber)
          : "";
      const resultSummary = `⊕ ${typeLabel} ${numPart} Part B → merged with Part A · ${nObj} combined objectives`;

      updateQueueItem(queueId, {
        status: "done",
        progress: 100,
        result: {
          mergedPartB: true,
          lectureId: mergedLec.id,
          lectureType: mergedLec.lectureType,
          lectureNumber: mergedLec.lectureNumber,
          objectiveCount: nObj,
          resultSummary,
          resultSummaryColor: "#185FA5",
          extractMethod: extractMethodUsed,
        },
      });
      markAsProcessed(filB, bid);
      setUpMsg("⊕ Merged Part B with Part A ✓");
      setTimeout(() => setUpMsg(""), 2500);
      window.dispatchEvent(new CustomEvent("rxt-lec-updated"));
      window.dispatchEvent(new CustomEvent("rxt-objectives-updated"));
      console.log("Merged into:", mergedTitle, "chunks:", mergedChunks.length);
    };

    const runOne = async ({ file, queueId, bid, tid }) => {
      logUploadPhase(queueId, "runOne_begin", { name: file.name, bid });
      uploadFileByQueueIdRef.current.set(queueId, file);
      uploadRetryFilesRef.current.set(queueId, file);
      console.log(
        "Upload starting for:",
        file.name,
        "activeBlock:",
        activeBlock?.id,
        "activeBlock name:",
        activeBlock?.name,
        "| resolved bid:",
        bid
      );
      if (isAlreadyProcessed(file, bid)) {
        updateQueueItem(queueId, {
          status: "done",
          progress: 100,
          result: {
            skipped: true,
            reason: "Already uploaded",
            resultSummary: "Already uploaded — skipped",
          },
        });
        return;
      }

      const isPdf = file.name.toLowerCase().endsWith(".pdf") || file.type === "application/pdf";
      const existingInBlock = lectures.some((l) => l.blockId === bid && l.filename === file.name);
      const existingInBatch = addedInBatch.has(file.name);
      let lecturesForRun = lectures;
      if (existingInBlock || existingInBatch) {
        const existingLec = lectures.find((l) => l.blockId === bid && l.filename === file.name);
        if (existingLec) {
          console.log(`Re-uploading ${file.name} — replacing existing`);
          delLec(existingLec.id);
          lecturesForRun = lectures.filter((l) => l.id !== existingLec.id);
        }
      }

      const partInfoEarly = detectPartInfo(file.name);
      if (isPdf && partInfoEarly.isPart && partInfoEarly.isPartB) {
        let storeLecs = [];
        try {
          storeLecs = JSON.parse(localStorage.getItem("rxt-lec-meta") || "[]");
        } catch {
          storeLecs = [];
        }
        const matchA = findMatchingPartALecture(storeLecs, bid, partInfoEarly);
        if (matchA) {
          console.log("Found matching Part A:", matchA.lectureTitle || matchA.filename, "— merging with Part B");
          try {
            await mergePartBIntoPartA(file, matchA, queueId, bid);
            added++;
            addedInBatch.add(file.name);
          } catch (e) {
            console.error("mergePartBIntoPartA failed:", e);
            uploadRetryFilesRef.current.set(queueId, file);
            updateQueueItem(queueId, { status: "error", error: e.message || "Merge failed", progress: 100 });
            failed++;
          }
          return;
        }
      }

      try {
        if (isPdf) {
          updateQueueItem(queueId, { status: "extracting", progress: 0 });
          setTimeout(() => updateQueueItem(queueId, { progress: 40 }), 30);
          setUpMsg("📖 Extracting PDF text...");
          const forceOcr = uploadForceOcrQueueIdRef.current.has(queueId);
          if (forceOcr) uploadForceOcrQueueIdRef.current.delete(queueId);
          const tExtract = typeof performance !== "undefined" ? performance.now() : 0;
          const { contentResult: cr0, method: extractMethodUsed } = await extractWithSmartFallback(
            file,
            (msg) => setUpMsg(msg),
            { forceMistralOcr: forceOcr }
          );
          if (typeof performance !== "undefined") {
            logUploadPhase(queueId, "extract_done", { method: extractMethodUsed }, performance.now() - tExtract);
          }
          let contentResult = cr0;
          if (contentResult.chunks?.length > 0) {
            console.log("Chunk sample keys:", Object.keys(contentResult.chunks[0]));
            console.log("Chunk sample:", JSON.stringify(contentResult.chunks[0]).slice(0, 300));
          }
          const fullRawTextJoin =
            (contentResult.fullText || (contentResult.chunks || []).map((c) => getChunkBody(c)).join("\n\n")) || "";
          const textQualityAssessment = assessTextQuality(fullRawTextJoin);

          const lecTitlePre =
            contentResult.lectureTitle ?? file.name.replace(/\.[^.]+$/, "");
          const fnInfo = detectLectureInfo(file.name);
          const lectureTypePre = fnInfo.lectureType || detectLectureType(file.name, lecTitlePre);
          let lecNumPre =
            contentResult.lectureNumber ??
            (fnInfo.lectureNumber != null && !isNaN(fnInfo.lectureNumber) ? fnInfo.lectureNumber : null) ??
            detectLectureNumber(file.name, lecTitlePre, lectureTypePre);
          if (uploadForceUniqueRef.current.get(queueId)) {
            const blockLecs = lecturesForRun.filter((l) => l.blockId === bid);
            lecNumPre = allocateUniqueLectureNumber(blockLecs, lectureTypePre, lecNumPre);
            uploadForceUniqueRef.current.delete(queueId);
          }
          const pendingLecId =
            typeof crypto !== "undefined" && crypto.randomUUID ? crypto.randomUUID() : uid();
          const lecForExtract = {
            id: pendingLecId,
            blockId: bid,
            termId: tid,
            lectureType: lectureTypePre,
            lectureNumber: lecNumPre,
            lectureTitle: lecTitlePre,
            title: lecTitlePre,
            filename: file.name,
          };

          const lecTitle = lecTitlePre;
          const lectureType = lectureTypePre;
          const lecNum = lecNumPre;
          console.log("Detected type/number:", lectureType, lecNum, "from:", file.name);

          const newLec = {
            id: pendingLecId,
            blockId: bid,
            termId: tid,
            filename: file.name,
            lectureNumber: lecNum,
            lectureTitle: lecTitle,
            lectureType,
            weekNumber: detectWeekNumber(file.name, lecTitle) || null,
            subject: contentResult.subject || contentResult.discipline || "",
            chunks: contentResult.chunks || contentResult.sections || [],
            subtopics: contentResult.subtopics || contentResult.topics || contentResult.subtopicList || [],
            keyTerms: contentResult.keyTerms || contentResult.terms || contentResult.keywords || [],
            summary: contentResult.summary || "",
            fullText: fullRawTextJoin,
            extractionMethod: contentResult.extractionMethod || "pdfplumber",
            pageCount: contentResult.pageCount ?? (contentResult.chunks || []).length,
            slideImages: contentResult.slideImages || [],
            uploadedAt: new Date().toISOString(),
            uploadDate: new Date().toISOString(),
          };

          let duplicateReplacedId = null;
          let duplicateInherit = null;
          try {
            const allLecsLive = JSON.parse(localStorage.getItem("rxt-lec-meta") || "[]");
            const dup = allLecsLive.find(
              (l) =>
                l &&
                l.blockId === bid &&
                String(l.lectureType || "LEC").trim() === String(newLec.lectureType || "LEC").trim() &&
                String(l.lectureNumber).trim() === String(newLec.lectureNumber).trim() &&
                l.id !== newLec.id
            );
            if (dup) {
              duplicateReplacedId = dup.id;
              duplicateInherit = {
                weekNumber: dup.weekNumber,
                dayOfWeek: dup.dayOfWeek,
                lectureDate: dup.lectureDate,
                lectureTitle: dup.lectureTitle ?? dup.title,
              };
              Object.assign(newLec, duplicateInherit);
            }
          } catch (e) {
            console.warn("duplicate lecture lookup (inherit):", e);
          }

          const replacedLectureOldIdFromTombstone = peekTombstoneOldLecId(bid, {
            blockId: bid,
            lectureType: lectureTypePre,
            lectureNumber: lecNumPre,
          });

          // Save lecture immediately after text extraction (before any AI calls).
          updateQueueItem(queueId, { status: "saving", progress: 42 });
          setLecs((prev) => {
            const hasNum = newLec.lectureNumber != null && String(newLec.lectureNumber).trim() !== "";
            const filtered = prev.filter((l) => {
              if (hasNum) {
                return !(
                  l.blockId === bid &&
                  (l.lectureType || "LEC").trim() === (newLec.lectureType || "LEC").trim() &&
                  String(l.lectureNumber).trim() === String(newLec.lectureNumber).trim()
                );
              }
              return !(l.blockId === bid && l.filename === file.name);
            });
            const updated = [...filtered, newLec];
            saveLectures(updated);
            return updated;
          });
          migrateOrphanedRecords(newLec, setPerformanceHistory);
          console.log("✓ Lecture saved:", newLec.id, newLec.blockId);

          updateQueueItem(queueId, { status: "parsing", progress: 45 });
          setTimeout(() => updateQueueItem(queueId, { progress: 70 }), 30);

          if (!newLec.subtopics?.length) {
            try {
              const allText = (contentResult.chunks || []).map((c) => getChunkBody(c)).join("\n").slice(0, 8000);

              if (allText.length > 200) {
                const GEMINI_KEY = import.meta.env.VITE_GEMINI_API_KEY || "";
                const res = await fetch(
                  `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=${GEMINI_KEY}`,
                  {
                    method: "POST",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify({
                      contents: [
                        {
                          parts: [
                            {
                              text:
                                "Extract from this medical lecture:\n" +
                                "- 5-8 subtopics (short phrases)\n" +
                                "- 5-10 key terms\n" +
                                "- lecture number and title\n\n" +
                                "Return ONLY complete valid JSON:\n" +
                                '{"subtopics":["Back anatomy","Vertebral column"],"keyTerms":["lamina","pedicle"],"lectureNumber":1,"lectureTitle":"The Back"}\n\n' +
                                "TEXT:\n" +
                                allText.slice(0, 4000),
                            },
                          ],
                        },
                      ],
                      generationConfig: { maxOutputTokens: 1000, temperature: 0.1 },
                      safetySettings: [
                        { category: "HARM_CATEGORY_DANGEROUS_CONTENT", threshold: "BLOCK_NONE" },
                        { category: "HARM_CATEGORY_HARASSMENT", threshold: "BLOCK_NONE" },
                        { category: "HARM_CATEGORY_HATE_SPEECH", threshold: "BLOCK_NONE" },
                        { category: "HARM_CATEGORY_SEXUALLY_EXPLICIT", threshold: "BLOCK_NONE" },
                      ],
                    }),
                  }
                );

                const d = await res.json();
                const raw = (d.candidates?.[0]?.content?.parts?.[0]?.text || "").trim();
                const cleaned = raw
                  .replace(/^```json\s*/i, "")
                  .replace(/^```\s*/i, "")
                  .replace(/\s*```$/, "")
                  .trim();
                console.log("Subtopic cleaned:", cleaned.slice(0, 200));

                let parsed = null;

                try {
                  parsed = JSON.parse(cleaned);
                } catch {}

                if (!parsed?.subtopics?.length) {
                  const items = [];
                  const matches = cleaned.matchAll(/"([^"]{5,80})"/g);
                  for (const m of matches) {
                    const val = m[1].trim();
                    if (["subtopics", "keyTerms", "lectureTitle", "lectureNumber"].includes(val)) continue;
                    if (/^[A-Z]/.test(val) || /^[a-z]/.test(val)) {
                      items.push(val);
                    }
                  }
                  if (items.length > 0) {
                    const firstNumIdx = items.findIndex((i) => /^\d+$/.test(i));
                    const subtopics = firstNumIdx > 0 ? items.slice(0, firstNumIdx) : items.slice(0, 10);
                    parsed = { subtopics };
                  }
                }

                if (parsed?.subtopics?.length) {
                  newLec.subtopics = parsed.subtopics.filter((s) => s.length > 3 && s.length < 100);
                  newLec.keyTerms = parsed.keyTerms || [];
                  if (!newLec.lectureNumber && parsed.lectureNumber) newLec.lectureNumber = parsed.lectureNumber;
                  if ((!newLec.lectureTitle || newLec.lectureTitle === file.name) && parsed.lectureTitle) {
                    newLec.lectureTitle = parsed.lectureTitle;
                  }
                  console.log("Subtopics extracted:", newLec.subtopics);
                }
              }
      } catch (e) {
              console.warn("Subtopic extraction error:", e.message);
            }
          }

          let teachingMap = null;
          try {
            setUpMsg("Analyzing lecture content with AI...");
            teachingMap = await analyzeLecture(newLec, getLecText(newLec));
            console.log("Teaching map generated:", teachingMap?.sections?.length, "sections");
          } catch (err) {
            console.error("Teaching map generation failed:", err);
          }

          let extractedObjectives = [];
          try {
            setUpMsg("🎯 Extracting learning objectives...");
            if (uploadObjectivesExtractedRef.current.has(pendingLecId)) {
              console.log("Already extracted for", pendingLecId, "— skipping");
              extractedObjectives = [];
            } else {
              uploadObjectivesExtractedRef.current.add(pendingLecId);
              extractedObjectives = await extractObjectivesFromLecture(
                fullRawTextJoin,
                { ...lecForExtract, chunks: contentResult.chunks || contentResult.sections || [] },
                bid
              );
              if (
                extractedObjectives.length === 0 &&
                String(bid || "").toLowerCase().startsWith("cpr") &&
                newLec.chunks?.length
              ) {
                console.log("No objectives from pipeline — trying inline SOM before save");
                setUpMsg("Deriving objectives from slide content…");
                extractedObjectives = await extractInlineSOMCodes(newLec.chunks, newLec, bid, new Set());
                console.log(`Inline SOM fallback found: ${extractedObjectives.length}`);
              }
            }
            if (extractedObjectives.length > 0) {
              console.log("Saved", extractedObjectives.length, "objectives for", bid);
            } else {
              console.log("No objectives to save — skipping write");
            }
          } catch (objErr) {
            const msg = objErr?.message || String(objErr);
            if (/Timeout/i.test(msg)) {
              uploadRetryFilesRef.current.set(queueId, file);
              updateQueueItem(queueId, {
                status: "error",
                error: "AI parsing timed out — try again",
                progress: 100,
                retryable: true,
              });
              failed++;
              return;
            }
            console.warn("Objective extraction failed:", objErr);
          }

          let lectureToSave = {
            ...newLec,
            teachingMap: teachingMap || null,
            teachingMapDate: teachingMap ? new Date().toISOString() : undefined,
          };
          if (duplicateInherit) {
            lectureToSave = {
              ...lectureToSave,
              weekNumber: duplicateInherit.weekNumber,
              dayOfWeek: duplicateInherit.dayOfWeek,
              lectureDate: duplicateInherit.lectureDate,
              lectureTitle: duplicateInherit.lectureTitle,
            };
          }

          if (duplicateReplacedId) {
            try {
              const allObjs = getMSKObjectives(bid);
              const relinked = allObjs.map((o) =>
                o.linkedLecId === duplicateReplacedId || o.sourceFile === duplicateReplacedId
                  ? { ...o, linkedLecId: lectureToSave.id, sourceFile: lectureToSave.id }
                  : o
              );
              saveMSKObjectives(bid, relinked);
            } catch (e) {
              console.warn("Objective relink on duplicate upload:", e);
            }
          }

          await commitPdfTail({
            lectureToSave,
            contentResult,
            extractedObjectives,
            extractMethodUsed,
            teachingMap,
            file,
            queueId,
            bid,
            skipSetLecs: false,
            textQualityAssessment,
            replacedLectureOldId: duplicateReplacedId || replacedLectureOldIdFromTombstone,
          });
          added++;
          addedInBatch.add(file.name);
        } else {
          updateQueueItem(queueId, { status: "extracting", progress: 0 });
          setTimeout(() => updateQueueItem(queueId, { progress: 40 }), 30);
          setUpMsg("Reading file...");
          let text = await file.text();
          text = (text || "").trim();
          if (!text || text.length < 50) {
            setUpMsg("⚠ No text in " + file.name);
            uploadRetryFilesRef.current.set(queueId, file);
            updateQueueItem(queueId, { status: "error", error: "No text in file", progress: 100 });
            failed++;
            return;
          }
          updateQueueItem(queueId, { status: "parsing", progress: 55 });
          setTimeout(() => updateQueueItem(queueId, { progress: 70 }), 30);
          setUpMsg("🧠 AI parsing...");
          let meta;
          try {
            meta = await detectMeta(text);
          } catch {
            meta = { subject: "Unassigned", subtopics: ["Unknown"], keyTerms: [], lectureTitle: file.name };
          }
          const rawSubject = (meta.subject || "").trim();
          if (["Medicine", "Unknown", "General", ""].includes(rawSubject)) {
            meta = { ...meta, subject: "Unassigned" };
          }
          const lectureType = detectLectureType(file.name, meta.lectureTitle || "");
          const lectureNumber = detectLectureNumber(file.name, meta.lectureTitle || "", lectureType) ?? meta.lectureNumber ?? null;
          const lec = {
            id: typeof crypto !== "undefined" && crypto.randomUUID ? crypto.randomUUID() : uid(),
            blockId: bid,
            termId: tid,
            filename: file.name,
            uploadedAt: new Date().toISOString(),
            fullText: text.slice(0, 12000),
            ...meta,
            lectureNumber,
            lectureType,
            weekNumber: detectWeekNumber(file.name, meta.lectureTitle || "") || null,
          };
          updateQueueItem(queueId, { status: "linking", progress: 75 });
          setTimeout(() => updateQueueItem(queueId, { progress: 90 }), 30);
          setLecs((p) => [...p.filter((l) => !(l.blockId === bid && l.filename === file.name)), lec]);
          setBlockObjectives((prev) => {
            const blockData = prev[bid];
            if (!blockData?.imported?.length) return prev;
            const allLectures = [...lecturesForRun.filter((l) => l.blockId === bid), lec];
            const aligned = alignObjectivesToLectures(bid, blockData.imported, allLectures);
            const updated = { ...prev, [bid]: { ...blockData, imported: aligned } };
            try {
              safeSetItem("rxt-block-objectives", updated);
            } catch {}
            return updated;
          });
          const typeLabel = String(lec.lectureType || "LEC")
            .replace(/^LECTURE$/i, "LEC")
            .slice(0, 4);
          const numPart =
            lec.lectureNumber != null && String(lec.lectureNumber).trim() !== ""
              ? String(lec.lectureNumber)
              : null;
          const resultSummary =
            numPart != null
              ? `${typeLabel} ${numPart} · 0 objectives`
              : "Uploaded · 0 objectives";
          updateQueueItem(queueId, {
            status: "done",
            progress: 100,
            result: {
              lectureType: lec.lectureType,
              lectureNumber: lec.lectureNumber,
              objectiveCount: 0,
              resultSummary,
              extractMethod: "text",
              typeWarning: shouldWarnLectureTypeBadge(lec.lectureType, file.name),
            },
          });
          markAsProcessed(file, bid);
          setUpMsg("✓ " + file.name);
          added++;
          addedInBatch.add(file.name);
        }
      } catch (e) {
        setUpMsg("✗ " + file.name + ": " + (e.message || String(e)));
        uploadRetryFilesRef.current.set(queueId, file);
        updateQueueItem(queueId, { status: "error", error: e.message || "Upload failed", progress: 100 });
        failed++;
        console.error("Upload failed:", e);
      }
    };

    uploadResolveCollisionRef.current = async (queueId, resolution) => {
      const stash = uploadCollisionResumeRef.current.get(queueId);
      if (!stash) return;
      const {
        file,
        bid,
        tid,
        lectureToSave,
        colliding,
        contentResult,
        extractedObjectives,
        extractMethodUsed,
        teachingMap,
        textQualityAssessment,
      } = stash;
      if (resolution === "keep") {
        uploadCollisionResumeRef.current.delete(queueId);
        updateQueueItem(queueId, {
          status: "done",
          progress: 100,
          result: {
            skipped: true,
            reason: "keep_existing",
            resultSummary: "Kept existing lecture — skipped",
          },
        });
        return;
      }
      uploadCollisionResumeRef.current.delete(queueId);
      if (resolution === "replace") {
        uploadCollisionSkipRef.current = queueId;
        clearUploadCacheHash(file);
        delLec(colliding.id);
        updateQueueItem(queueId, {
          status: "queued",
          progress: 0,
          error: null,
          bid,
          tid,
          collisionExisting: undefined,
          collisionLabel: undefined,
          showMergeOption: undefined,
          uniqueNumberHint: undefined,
          statusLabel: "Queued",
        });
        if (!isProcessingQueueRef.current) {
          void processUploadQueueRef.current?.();
        }
        return;
      }
      if (resolution === "new") {
        clearUploadCacheHash(file);
        uploadForceUniqueRef.current.set(queueId, true);
        updateQueueItem(queueId, {
          status: "queued",
          progress: 0,
          error: null,
          bid,
          tid,
          collisionExisting: undefined,
          collisionLabel: undefined,
          showMergeOption: undefined,
          uniqueNumberHint: undefined,
          statusLabel: "Queued",
        });
        if (!isProcessingQueueRef.current) {
          void processUploadQueueRef.current?.();
        }
        return;
      }
      if (resolution === "merge") {
        const baseTitle = (colliding.lectureTitle || "").replace(/\s*\(Parts.*\)\s*$/i, "").trim();
        const mergedTitle = `${baseTitle || lectureToSave.lectureTitle || ""} (Parts 1 & 2)`.trim();
        const mergedLec = {
          ...lectureToSave,
          lectureTitle: mergedTitle,
          chunks: [...(colliding.chunks || []), ...(lectureToSave.chunks || [])],
          fullText: [colliding.fullText, lectureToSave.fullText].filter(Boolean).join("\n\n---\n\n"),
          subtopics: [...new Set([...(colliding.subtopics || []), ...(lectureToSave.subtopics || [])])],
          keyTerms: [...new Set([...(colliding.keyTerms || []), ...(lectureToSave.keyTerms || [])])],
          isMerged: true,
          mergedFrom: [
            { id: colliding.id, title: colliding.lectureTitle, num: colliding.lectureNumber },
            { id: lectureToSave.id, title: lectureToSave.lectureTitle, num: lectureToSave.lectureNumber },
          ],
        };
        setLecs((prev) => {
          const filtered = prev.filter((l) => l.id !== colliding.id);
          const updated = [...filtered, mergedLec];
          saveLectures(updated);
          return updated;
        });
        setBlockObjectives((prev) => {
          const data = prev[bid] || { imported: [], extracted: [] };
          const relink = (obj) =>
            obj.linkedLecId === colliding.id
              ? { ...obj, linkedLecId: mergedLec.id, sourceFile: mergedLec.id }
              : obj;
          const imported = (data.imported || []).map(relink);
          const extracted = (data.extracted || []).map(relink);
          const next = { ...prev, [bid]: { ...data, imported, extracted } };
          try {
            safeSetItem("rxt-block-objectives", next);
          } catch {}
          return next;
        });
        await commitPdfTail({
          lectureToSave: mergedLec,
          contentResult,
          extractedObjectives,
          extractMethodUsed,
          teachingMap,
          file,
          queueId,
          bid,
          skipSetLecs: true,
          textQualityAssessment: textQualityAssessment ?? null,
          replacedLectureOldId: colliding.id,
        });
      }
    };

    runOneUploadRef.current = runOne;

    try {
      while (uploadQueueRef.current.some((i) => i.status === "queued")) {
        const idx = uploadQueueRef.current.findIndex((i) => i.status === "queued");
        if (idx === -1) break;
        const item = uploadQueueRef.current[idx];
        const queueId = item.id;
        const { bid: itemBid, tid: itemTid } = item;
        let file = uploadFileByQueueIdRef.current.get(queueId);
        if (!file) {
          try {
            file = await getUploadQueueBlob(queueId);
            if (file) {
              uploadFileByQueueIdRef.current.set(queueId, file);
              uploadRetryFilesRef.current.set(queueId, file);
              logUploadPhase(queueId, "file_from_idb", { ok: true, name: file.name });
            }
          } catch (e) {
            logUploadPhase(queueId, "file_from_idb", { ok: false, err: String(e) });
          }
        }
        if (!file) {
          logUploadPhase(queueId, "file_missing", { afterIdb: true });
          updateQueueItem(queueId, {
            status: "error",
            error: "File reference lost — re-upload the PDF",
            progress: 100,
            statusLabel: "✗ Failed — tap to retry",
          });
          failed++;
          await new Promise((r) => setTimeout(r, 1000));
          continue;
        }
        updateQueueItem(queueId, { status: "processing", progress: 10, statusLabel: "Processing…" });
        try {
          const tRun = typeof performance !== "undefined" ? performance.now() : 0;
          await runOne({ file, queueId, bid: itemBid, tid: itemTid });
          if (typeof performance !== "undefined") {
            logUploadPhase(queueId, "runOne_complete", file?.name, performance.now() - tRun);
          }
          const st = uploadQueueRef.current.find((i) => i.id === queueId)?.status;
          if (st === "done") {
            await new Promise((r) => setTimeout(r, 1500));
          } else if (st === "error") {
            await new Promise((r) => setTimeout(r, 1000));
          }
        } catch (err) {
          console.error("Upload queue item failed:", err);
          updateQueueItem(queueId, {
            status: "error",
            error: err?.message || String(err),
            progress: 0,
            statusLabel: "✗ Failed — tap to retry",
          });
          await new Promise((r) => setTimeout(r, 1000));
        }
      }
    } finally {
      setUploading(false);
      setUploadComplete(true);
      try {
        const l = await loadLectures();
        setLecs(l || []);
        const raw = localStorage.getItem("rxt-block-objectives") || "{}";
        const parsed = JSON.parse(raw);
        setBlockObjectives(parsed);
      } catch (err) {
        console.warn("Post-upload refresh failed:", err);
      }
      try {
        window.dispatchEvent(new CustomEvent("rxt-objectives-updated"));
      } catch (_) {}

      const uploadSyncUid = userRef.current?.id;
      if (uploadSyncUid) scheduleSyncToSupabase(uploadSyncUid);
      setTimeout(() => void backgroundSync(), 3000);

      const parts = [];
      if (added) parts.push("✓ Added " + added + " lecture" + (added !== 1 ? "s" : ""));
      if (failed) parts.push("⚠ " + failed + " failed");
      setUpMsg(parts.length ? parts.join(", ") : "No files processed.");
      setTimeout(() => setUpMsg(""), 8000);

      isProcessingQueueRef.current = false;
      setIsProcessingQueue(false);
    }
  };

  // Extract bolded/key terms from a lecture's slide text (Mistral-OCR preserves bold as markdown).
  // These become `lec.highYieldDetails` which the MCQ generation prompt already injects
  // as "must-test" items.
  const [highYieldExtractStatus, setHighYieldExtractStatus] = useState({}); // { [lecId]: "running"|"done"|"error" }

  const extractHighYieldDetails = useCallback(async (lec) => {
    if (!lec?.id) return;
    setHighYieldExtractStatus((s) => ({ ...s, [lec.id]: "running" }));
    try {
      const text = (getLecText(lec) || "").slice(0, 12000);
      if (text.length < 200) {
        setHighYieldExtractStatus((s) => ({ ...s, [lec.id]: "error" }));
        return { error: "Not enough lecture text — re-upload the PDF first." };
      }
      const fallback = { details: [] };
      const result = await callAIJSON(
        `You are a USMLE Step 1 study assistant. Extract HIGH-YIELD DETAILS from a medical lecture's slides.
Focus specifically on:
- Bolded terms (often shown as **term** in markdown OCR) and their defining characteristic
- Key differentiating features within a subtopic (e.g. "Foreign body giant cells: nuclei centrally grouped")
- Eponyms / named structures / cell types and what makes them distinctive
- Lab values, normal ranges, mechanisms, classic clinical associations
Skip generic background / introductory wording. Each entry must be a specific testable fact, not a category header.

Return ONLY valid JSON of this shape:
{
  "details": [
    { "term": "Foreign body giant cells", "fact": "Nuclei centrally grouped; typical of non-immunological agents", "why_tested": "Differentiates from Langhans' giant cells (peripheral horseshoe nuclei)" }
  ]
}

Return up to 30 details. Be precise. No fluff.`,
        `Lecture: ${lec.lectureTitle || lec.fileName || "Untitled"}
Type: ${lec.lectureType || "LEC"}

LECTURE CONTENT (markdown OCR — bolded terms appear inside **double asterisks**):
${text}`,
        fallback,
        4000
      );
      const details = Array.isArray(result?.details)
        ? result.details
            .filter((d) => d && (d.term || d.name) && (d.fact || d.detail))
            .slice(0, 30)
            .map((d) => ({
              term: String(d.term || d.name).trim().slice(0, 120),
              fact: String(d.fact || d.detail).trim().slice(0, 280),
              why_tested: d.why_tested ? String(d.why_tested).trim().slice(0, 200) : null,
            }))
        : [];
      if (!details.length) {
        setHighYieldExtractStatus((s) => ({ ...s, [lec.id]: "error" }));
        return { error: "No details extracted — model returned empty list." };
      }
      // Persist into both React state and localStorage rxt-lec-meta.
      setLecs((prev) =>
        (prev || []).map((l) => (l.id === lec.id ? { ...l, highYieldDetails: details } : l))
      );
      try {
        const stored = JSON.parse(localStorage.getItem("rxt-lec-meta") || "[]");
        const next = (stored || []).map((l) =>
          l && l.id === lec.id ? { ...l, highYieldDetails: details } : l
        );
        safeSetItem("rxt-lec-meta", next);
      } catch (e) {
        console.warn("persist highYieldDetails to lec-meta failed:", e);
      }
      setHighYieldExtractStatus((s) => ({ ...s, [lec.id]: "done" }));
      return { details };
    } catch (e) {
      console.error("extractHighYieldDetails failed:", e);
      setHighYieldExtractStatus((s) => ({ ...s, [lec.id]: "error" }));
      return { error: e?.message || String(e) };
    }
  }, []);

  // Auto-extract highYieldDetails for any lecture that has text but hasn't been processed yet.
  // Runs serially with a small delay so we don't blast Gemini with 27 parallel calls on first
  // load. Idempotent: marks an in-flight ref while running, so the effect won't re-trigger
  // until the persisted highYieldDetails appears in `lectures`.
  const highYieldAutoQueueRef = useRef({ inFlight: new Set(), failed: new Set() });
  useEffect(() => {
    let cancelled = false;
    const run = async () => {
      for (const lec of lectures || []) {
        if (cancelled) return;
        if (!lec?.id) continue;
        if (Array.isArray(lec.highYieldDetails) && lec.highYieldDetails.length > 0) continue;
        if (highYieldAutoQueueRef.current.inFlight.has(lec.id)) continue;
        if (highYieldAutoQueueRef.current.failed.has(lec.id)) continue;
        // Need real text content (post-OCR) to extract anything.
        const textLen = (lec.fullText?.length || 0) +
          (Array.isArray(lec.chunks) ? lec.chunks.reduce((n, c) => n + (getChunkBody(c)?.length || 0), 0) : 0);
        if (textLen < 400) continue;
        highYieldAutoQueueRef.current.inFlight.add(lec.id);
        try {
          const r = await extractHighYieldDetails(lec);
          if (r?.error) highYieldAutoQueueRef.current.failed.add(lec.id);
        } finally {
          highYieldAutoQueueRef.current.inFlight.delete(lec.id);
        }
        // Pace requests so we don't melt the API on first load with many lectures.
        await new Promise((r) => setTimeout(r, 1500));
      }
    };
    void run();
    return () => { cancelled = true; };
  }, [lectures, extractHighYieldDetails]);

  // Pull testable facts out of an uploaded Q-bank in one batch call. Returns
  // [{ term, fact, why_tested, conceptKey, lectureMatchHint }] for downstream layering
  // into highYieldDetails + optional weak-concepts.
  const extractTestableFromBankQuestions = async (qs, blockName) => {
    if (!qs?.length) return [];
    // Compact each question to just the fields the model needs.
    const compact = qs.slice(0, 60).map((q, i) => ({
      i: i + 1,
      stem: String(q.stem || q.question || "").slice(0, 600),
      correct: String(
        q.correct ||
          (q.choices && q.correct ? q.choices[q.correct] : null) ||
          q.answer ||
          ""
      ).slice(0, 200),
      explanation: String(q.explanation || q.rationale || "").slice(0, 400),
      topic: String(q.topic || "").slice(0, 80),
    }));
    const fallback = { items: [] };
    try {
      const result = await callAIJSON(
        `You convert exam questions into TESTABLE FACTS for a medical-student spaced-repetition system.
For each question, extract the SPECIFIC factual content the student must know to answer it — NOT the question stem itself.
Return JSON only:
{ "items": [
  { "i": 1, "term": "G6PD deficiency", "fact": "X-linked recessive; episodic hemolysis triggered by fava beans, sulfa drugs, infection; Heinz bodies on smear", "why_tested": "classic Step 1 trigger-symptom-pathology triad", "conceptKey": "G6PD deficiency", "lectureMatchHint": "Hemoglobinopathies" }
] }
Rules:
- One item per input question (preserve "i").
- "term" is the named entity / concept (eponym, lab value, disease, mechanism).
- "fact" is the testable detail in 1 sentence — be specific (numbers, mechanisms, eponyms).
- "why_tested" notes the clinical/exam relevance briefly.
- "conceptKey" is a short normalized concept name for grouping (e.g. "G6PD deficiency" not "G6PD def").
- "lectureMatchHint" is a 1–4 word topic the question fits (e.g. "Spirometry", "Pulmonary Circulation").
Skip items where the question is too vague to extract.`,
        `Block: ${blockName || "Medical block"}
QUESTIONS:
${compact.map((q) => `--- Q${q.i} ---
TOPIC: ${q.topic}
STEM: ${q.stem}
CORRECT: ${q.correct}
EXPLANATION: ${q.explanation}`).join("\n\n")}
`,
        fallback,
        6000
      );
      const items = Array.isArray(result?.items) ? result.items : [];
      return items
        .map((it) => ({
          i: Number(it.i) || null,
          term: String(it.term || "").trim().slice(0, 120),
          fact: String(it.fact || "").trim().slice(0, 280),
          why_tested: it.why_tested ? String(it.why_tested).trim().slice(0, 200) : null,
          conceptKey: String(it.conceptKey || it.term || "").trim().slice(0, 120),
          lectureMatchHint: String(it.lectureMatchHint || "").trim().slice(0, 60),
        }))
        .filter((x) => x.term && x.fact);
    } catch (e) {
      console.warn("extractTestableFromBankQuestions failed:", e);
      return [];
    }
  };

  // Match a parsed question (or extracted item) to one of this block's lectures.
  // Best-effort: substring on lecture title or NotebookLM topic hint.
  const matchLectureForBank = (text, blockLecsArr) => {
    const t = String(text || "").toLowerCase();
    if (!t || !blockLecsArr?.length) return null;
    return (
      blockLecsArr.find((l) => {
        const title = (l.lectureTitle || l.fileName || "").toLowerCase();
        if (!title) return false;
        return t.includes(title.slice(0, 18)) || title.includes(t.slice(0, 18));
      }) || null
    );
  };

  const handleQuestionBankUpload = async (files, bidParam, opts = {}) => {
    if (!files?.length) return;
    const wrongOnly = !!opts.wrongOnly;
    const targetBid = bidParam ?? activeBlock?.id ?? blockId;
    const blockNameForExtract = activeBlock?.name || targetBid || "";
    const blockLecsArr = (lectures || []).filter((l) => l && l.blockId === targetBid);
    setQbankUploading(true);
    setQbankUploadStatus("");
    let totalSaved = 0;
    let totalFiles = 0;
    let totalErrors = 0;
    let totalHighYield = 0;
    let totalWeakConcepts = 0;
    try {
      for (const file of Array.from(files)) {
        totalFiles += 1;
        try {
          setQbankUploadStatus(`📄 ${file.name} — reading…`);
          const result = await parseExamPDF(file, (msg) => setQbankUploadStatus(`${file.name} — ${msg}`));
          const qs = (result?.questions || []).map((q) => ({
            ...q,
            id: q.id || (typeof crypto !== "undefined" && crypto.randomUUID ? crypto.randomUUID() : `qb-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`),
            blockId: targetBid,
            sourceFile: file.name,
            importedAt: new Date().toISOString(),
            bankType: wrongOnly ? "wrong" : "neutral",
          }));
          if (!qs.length) {
            setQbankUploadStatus(`⚠ ${file.name} — no questions detected`);
            continue;
          }
          const banks = (() => {
            try { return JSON.parse(localStorage.getItem("rxt-question-banks") || "{}"); } catch { return {}; }
          })();
          banks[file.name] = qs;
          try {
            safeSetItem("rxt-question-banks", banks);
          } catch {
            localStorage.setItem("rxt-question-banks", JSON.stringify(banks));
          }
          totalSaved += qs.length;
          setQbankUploadStatus(`✓ ${file.name} — ${qs.length} questions saved · extracting key details…`);

          // ── Layer 1: extract testable facts → lec.highYieldDetails ────────
          const extracted = await extractTestableFromBankQuestions(qs, blockNameForExtract);
          if (extracted.length) {
            const detailsByLec = new Map(); // lecId -> [items]
            extracted.forEach((it) => {
              const sourceQ = qs[(it.i || 1) - 1];
              const matchText = it.lectureMatchHint || sourceQ?.topic || "";
              const lec = matchLectureForBank(matchText, blockLecsArr);
              if (!lec) return;
              if (!detailsByLec.has(lec.id)) detailsByLec.set(lec.id, []);
              detailsByLec.get(lec.id).push({
                term: it.term,
                fact: it.fact,
                why_tested: it.why_tested ||
                  (wrongOnly ? "Tested on uploaded exam — student missed previously" : "Tested on uploaded exam"),
                source: "qbank",
                bankType: wrongOnly ? "wrong" : "neutral",
              });
            });
            if (detailsByLec.size > 0) {
              setLecs((prev) =>
                (prev || []).map((l) => {
                  const incoming = detailsByLec.get(l.id);
                  if (!incoming?.length) return l;
                  const existing = Array.isArray(l.highYieldDetails) ? l.highYieldDetails : [];
                  const seenTerms = new Set(existing.map((d) => (d.term || "").toLowerCase().trim()));
                  const merged = [...existing];
                  incoming.forEach((d) => {
                    const k = (d.term || "").toLowerCase().trim();
                    if (k && !seenTerms.has(k)) {
                      merged.push(d);
                      seenTerms.add(k);
                    }
                  });
                  return { ...l, highYieldDetails: merged.slice(0, 60) };
                })
              );
              try {
                const stored = JSON.parse(localStorage.getItem("rxt-lec-meta") || "[]");
                const next = (stored || []).map((l) => {
                  const incoming = detailsByLec.get(l?.id);
                  if (!incoming?.length) return l;
                  const existing = Array.isArray(l.highYieldDetails) ? l.highYieldDetails : [];
                  const seenTerms = new Set(existing.map((d) => (d.term || "").toLowerCase().trim()));
                  const merged = [...existing];
                  incoming.forEach((d) => {
                    const k = (d.term || "").toLowerCase().trim();
                    if (k && !seenTerms.has(k)) {
                      merged.push(d);
                      seenTerms.add(k);
                    }
                  });
                  return { ...l, highYieldDetails: merged.slice(0, 60) };
                });
                safeSetItem("rxt-lec-meta", next);
              } catch (e) {
                console.warn("persist bank highYield to lec-meta failed:", e);
              }
              totalHighYield += [...detailsByLec.values()].reduce((s, x) => s + x.length, 0);
            }

            // ── Layer 3: wrong-only → push concepts to rxt-weak-concepts ─────
            if (wrongOnly) {
              for (const it of extracted) {
                const sourceQ = qs[(it.i || 1) - 1];
                if (!sourceQ) continue;
                const matchText = it.lectureMatchHint || sourceQ.topic || "";
                const lec = matchLectureForBank(matchText, blockLecsArr);
                try {
                  await recordWrongAnswer({
                    blockId: targetBid,
                    blockName: blockNameForExtract,
                    question: String(sourceQ.stem || sourceQ.question || "").slice(0, 300),
                    wrongAnswer: "Missed on uploaded external exam",
                    correctAnswer: String(sourceQ.correct || sourceQ.answer || "").slice(0, 200),
                    linkedLecId: lec?.id || null,
                    lectureLabel: lec
                      ? `${lec.lectureType || "LEC"} ${lec.lectureNumber ?? ""} — ${lec.lectureTitle || ""}`.trim()
                      : (it.lectureMatchHint || ""),
                    source: "qbank-wrong-import",
                    objectiveId: null,
                  });
                  totalWeakConcepts += 1;
                } catch (e) {
                  console.warn("Wrong-only concept push failed for one Q:", e);
                }
              }
              window.dispatchEvent(new CustomEvent("rxt-weak-concepts-updated"));
            }
          }
        } catch (err) {
          totalErrors += 1;
          console.error("Question bank upload failed:", err);
          setQbankUploadStatus(`✗ ${file.name} — ${err?.message || String(err)}`);
        }
      }
      const tail =
        (totalHighYield > 0 ? ` · ${totalHighYield} key details added` : "") +
        (totalWeakConcepts > 0 ? ` · ${totalWeakConcepts} weak concepts logged` : "") +
        (totalErrors > 0 ? ` · ${totalErrors} failed` : "");
      const summary = `${totalSaved} question${totalSaved === 1 ? "" : "s"} added from ${totalFiles} file${totalFiles === 1 ? "" : "s"}${tail}`;
      setQbankUploadStatus(summary);
      window.dispatchEvent(new CustomEvent("rxt-question-banks-updated"));
    } finally {
      setQbankUploading(false);
    }
  };

  const handleLectureUpload = (files, bidParam, tidParam) => {
    if (!files?.length) return;
    const uploadBlockId = activeBlock?.id || getActiveBlockFromTerms()?.id || bidParam || "cpr1";
    const uploadTermId = activeBlock?.termId || getActiveBlockFromTerms()?.termId || tidParam || "term1";
    const bid = uploadBlockId;
    const termForBid = terms.find((t) => t.blocks?.some((b) => b.id === bid));
    const tid = termForBid?.id ?? uploadTermId;
    console.log(
      "Upload starting —",
      Array.from(files)
        .map((f) => f.name)
        .join(", "),
      "| activeBlock:",
      activeBlock?.id,
      activeBlock?.name,
      "| resolved blockId:",
      bid,
      "| termId:",
      tid
    );
    const fileList = Array.from(files);
    const pairs = fileList.map((file) => ({
      file,
      queueId: typeof crypto !== "undefined" && crypto.randomUUID ? crypto.randomUUID() : uid(),
    }));
    const sortedPairs = [...pairs].sort((a, b) => {
      const aInfo = detectPartInfo(a.file.name);
      const bInfo = detectPartInfo(b.file.name);
      if (aInfo.isPart && bInfo.isPart) {
        if (aInfo.isPartA && bInfo.isPartB) return -1;
        if (aInfo.isPartB && bInfo.isPartA) return 1;
      }
      return 0;
    });
    const newItems = sortedPairs.map(({ queueId, file }) => ({
      id: queueId,
      name: file.name,
      filename: file.name,
      status: "queued",
      progress: 0,
      error: null,
      result: null,
      bid,
      tid,
      statusLabel: "Queued",
    }));
    uploadQueueRef.current = [...uploadQueueRef.current, ...newItems];
    setUploadQueue([...uploadQueueRef.current]);
    sortedPairs.forEach(({ queueId, file }) => uploadFileByQueueIdRef.current.set(queueId, file));
    async function processUploadsSequentially(pairs) {
      for (const { queueId, file } of pairs) {
        try {
          await putUploadQueueBlob(queueId, file);
        } catch (e) {
          console.warn("[rxt-upload] IndexedDB persist failed:", e);
        }
        await new Promise((r) => setTimeout(r, 1500));
      }
    }
    void processUploadsSequentially(sortedPairs);
    setUploadPanelOpen(true);
    setUploadPanelCollapsed(false);
    setUploadComplete(false);
    uploadObjectivesExtractedRef.current = new Set();
    if (!isProcessingQueueRef.current) {
      void processUploadQueue();
    }
  };

  processUploadQueueRef.current = processUploadQueue;

  useEffect(() => {
    const ac = new AbortController();
    (async () => {
      const need = uploadQueueRef.current.filter((i) => i.restoredFromSession);
      if (!need.length) return;
      for (const item of need) {
        const f = await getUploadQueueBlob(item.id);
        if (ac.signal.aborted) return;
        if (f) {
          uploadFileByQueueIdRef.current.set(item.id, f);
          uploadRetryFilesRef.current.set(item.id, f);
          const patch = { restoredFromSession: false };
          if (item.status === "collision") {
            patch.statusLabel = item.collisionLabel || "Resolve collision below";
          } else {
            patch.status = "queued";
            patch.statusLabel = "Queued";
            patch.progress = 0;
          }
          updateQueueItem(item.id, patch);
        } else {
          updateQueueItem(item.id, {
            restoredFromSession: false,
            status: "error",
            error:
              "PDF not found in browser storage (cleared, private mode, or quota). Re-upload the file.",
            progress: 0,
            statusLabel: "Interrupted",
            retryable: true,
          });
        }
      }
      if (ac.signal.aborted) return;
      if (uploadQueueRef.current.some((i) => i.status === "queued") && !isProcessingQueueRef.current) {
        void processUploadQueueRef.current?.();
      }
    })();
    return () => ac.abort();
  }, [updateQueueItem]);

  const retryQueueItem = useCallback(
    (queueId) => {
      const file = uploadRetryFilesRef.current.get(queueId) || uploadFileByQueueIdRef.current.get(queueId);
      if (file) uploadFileByQueueIdRef.current.set(queueId, file);
      updateQueueItem(queueId, {
        status: "queued",
        progress: 0,
        error: null,
        retryable: false,
        statusLabel: "Queued",
      });
      if (!isProcessingQueueRef.current) {
        void processUploadQueueRef.current?.();
      }
    },
    [updateQueueItem]
  );

  const retryUploadQueuedFile = retryQueueItem;

  const forceReuploadQueuedFile = useCallback(
    (queueId) => {
      const file = uploadFileByQueueIdRef.current.get(queueId);
      if (!file) return;
      clearUploadCacheHash(file);
      updateQueueItem(queueId, {
        status: "queued",
        progress: 0,
        error: null,
        result: null,
        retryable: false,
        statusLabel: "Queued",
      });
      if (!isProcessingQueueRef.current) {
        void processUploadQueueRef.current?.();
      }
    },
    [updateQueueItem]
  );

  const forceOcrQueuedFile = useCallback(
    (queueId) => {
      const file = uploadFileByQueueIdRef.current.get(queueId);
      if (!file) return;
      clearUploadCacheHash(file);
      uploadForceOcrQueueIdRef.current.add(queueId);
      updateQueueItem(queueId, {
        status: "queued",
        progress: 0,
        error: null,
        result: null,
        retryable: false,
        statusLabel: "Queued",
      });
      if (!isProcessingQueueRef.current) {
        void processUploadQueueRef.current?.();
      }
    },
    [updateQueueItem]
  );

  const skipQueuedUploadItem = useCallback((queueId) => {
    const item = uploadQueueRef.current.find((i) => i.id === queueId);
    if (!item || item.status !== "queued") return;
    void deleteUploadQueueBlob(queueId);
    uploadFileByQueueIdRef.current.delete(queueId);
    uploadRetryFilesRef.current.delete(queueId);
    uploadQueueRef.current = uploadQueueRef.current.filter((i) => i.id !== queueId);
    setUploadQueue([...uploadQueueRef.current]);
    setUploadProgress((p) => {
      const n = { ...p };
      delete n[queueId];
      return n;
    });
  }, []);

  const reExtractObjectivesForLecture = useCallback(
    async (lecId, blockBid) => {
      const lec =
        lectures.find((l) => l.id === lecId) ||
        (() => {
          try {
            return JSON.parse(localStorage.getItem("rxt-lec-meta") || "[]").find((l) => l.id === lecId);
          } catch {
            return null;
          }
        })();
      if (!lec) return;
      const text = getLecText(lec).trim();
      if (!text) {
        window.alert("No extracted text available — re-upload this lecture");
        return;
      }
      setReExtractingLectureId(lecId);
      try {
        const lecStub = {
          ...lec,
          blockId: blockBid,
          lectureTitle: lec.lectureTitle || "",
        };
        const newObjs = await extractObjectivesFromLecture(text, lecStub, blockBid);
        if (newObjs.length === 0) return;
        if (blockBid === "cpr1") {
          const tombOld = peekTombstoneOldLecId(blockBid, {
            blockId: blockBid,
            lectureType: lec.lectureType,
            lectureNumber: lec.lectureNumber,
          });
          await trySaveCPRLectureExtractedObjectives(blockBid, lecStub, newObjs, true, tombOld);
          setTimeout(() => void backgroundSync(), 3000);
          return;
        }

        const enriched = newObjs.map((o) => ({
          ...enrichObjectiveWithBloom(o, lec?.lectureType || "LEC"),
          lectureType: lec.lectureType,
          lectureNumber: lec.lectureNumber,
          activity: activityForLectureSave(o, lec),
        }));
        await saveExtractedObjectivesForLecture(lecId, blockBid, enriched);
        setTimeout(() => void backgroundSync(), 3000);
      } catch (e) {
        console.error("reExtractObjectivesForLecture:", e);
      } finally {
        setReExtractingLectureId(null);
      }
    },
    [lectures, backgroundSync]
  );

  // ── Study ──────────────────────────────────
  const startTopic = (lec, sub) => {
    setStudyCfg({
      mode: "lecture",
      lecture: lec,
      subject: lec.subject,
      subtopic: sub,
      qCount: 10,
      blockId: lec.blockId,
      blockName: activeBlock?.name || lec.blockId,
      sessions,
      termColor: tc,
    });
    setView("config");
  };

  const startBlock = () => {
    if (!blockLecs.length) return;
    setStudyCfg({
      mode: "block",
      blockLectures: blockLecs,
      qCount: 10,
      blockId,
      blockName: activeBlock?.name || blockId,
      sessions,
      termColor: tc,
    });
    setView("config");
  };

  const [objectiveQuizLoading, setObjectiveQuizLoading] = useState(false);
  const [quizLoadingId, setQuizLoadingId] = useState(null);
  const [quizErrorId, setQuizErrorId] = useState(null);
  const [quizFlashLectureId, setQuizFlashLectureId] = useState(null);
  const [quizSavedState, setQuizSavedState] = useState(null);
  const [blockExamLoading, setBlockExamLoading] = useState(false);
  const [examConfigModal, setExamConfigModal] = useState(null); // { mode: "objectives"|"weak"|"full", blockId, open: true }

  const startRegularBlockExam = () => {
    if (!blockLecs.length) return;
    setStudyCfg({
      mode: "block",
      blockLectures: blockLecs,
      qCount: 10,
      blockId,
      blockName: activeBlock?.name || blockId,
      sessions,
      termColor: tc,
    });
    setView("config");
  };

  const startBlockExam = async (cfg) => {
    const {
      mode,
      questionCount = 20,
      focusMode,
      selectedGroups = [],
      targetObjectives,
      blockId: cfgBlockId,
    } = typeof cfg === "object" && cfg !== null ? cfg : { mode: cfg, targetObjectives: null, selectedGroups: [], blockId };

    const bid = cfgBlockId ?? blockId;
    let targetObjs = targetObjectives;
    if (!targetObjs?.length) {
      const blockObjs = getBlockObjectives(bid) || [];
      if (mode === "objectives") {
        const priority = [
          ...blockObjs.filter((o) => o.status === "struggling"),
          ...blockObjs.filter((o) => o.status === "untested"),
          ...blockObjs.filter((o) => o.status === "inprogress"),
          ...blockObjs.filter((o) => o.status === "mastered"),
        ];
        targetObjs = priority.slice(0, 40);
      } else if (mode === "weak") {
        targetObjs = blockObjs.filter((o) => o.status === "struggling" || o.status === "untested");
        if (targetObjs.length === 0) targetObjs = blockObjs;
      } else {
        targetObjs = [...blockObjs].sort(() => Math.random() - 0.5);
      }
    }
    if (!targetObjs?.length) {
      startRegularBlockExam();
      return;
    }

    let questionBanksByFile = {};
    try {
      questionBanksByFile = JSON.parse(localStorage.getItem("rxt-question-banks") || "{}");
    } catch {}

    const selectedLecIds = (selectedGroups || []).filter((g) => g.matchedLec).map((g) => g.matchedLec.id);
    const examContext = buildQuestionContext(bid, selectedGroups?.length === 1 ? selectedGroups[0]?.matchedLec?.id : null, questionBanksByFile, "exam", { selectedLecIds });

    setBlockExamLoading(true);
    const topicKey = "block__" + bid;
    const blockDiff = getTopicDifficulty(topicKey);
    const perfData = performanceHistory[topicKey];
    const streak = perfData?.streak || 0;
    const lastScore = perfData?.sessions?.slice(-1)[0]?.score ?? null;
    console.log(`Generating for ${topicKey} at difficulty: ${blockDiff}, streak: ${streak}, lastScore: ${lastScore}`);
    const safetySettings = [
      { category: "HARM_CATEGORY_DANGEROUS_CONTENT", threshold: "BLOCK_NONE" },
      { category: "HARM_CATEGORY_HARASSMENT", threshold: "BLOCK_NONE" },
      { category: "HARM_CATEGORY_HATE_SPEECH", threshold: "BLOCK_NONE" },
      { category: "HARM_CATEGORY_SEXUALLY_EXPLICIT", threshold: "BLOCK_NONE" },
    ];
    const batchSize = 6;
    const batches = Math.ceil(questionCount / batchSize);
    const allQuestions = [];

    try {
      for (let batch = 0; batch < batches; batch++) {
        const batchCount = Math.min(batchSize, questionCount - allQuestions.length);
        setBlockExamLoading(`Generating questions ${allQuestions.length + 1}–${allQuestions.length + batchCount}...`);

        const batchObjs = targetObjs
          .slice(batch * 8, batch * 8 + 15)
          .concat(targetObjs.slice(0, 3));

        const prompt = buildExamPromptFromContext(batchCount, batchObjs, { ...examContext, stylePrefs }, blockDiff);

        const res = await fetch(
          `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=${GEMINI_KEY}`,
          {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
              contents: [{ parts: [{ text: prompt }] }],
              generationConfig: { maxOutputTokens: 16000, temperature: 0.7 },
              safetySettings,
            }),
          }
        );
        const d = await res.json();
        const raw = d.candidates?.[0]?.content?.parts?.[0]?.text || "";
        const parsed = safeJSON(raw);
        const qs = (parsed.questions || []).map((q, i) => ({
          id: `blockexam_${Date.now()}_${allQuestions.length}_${i}`,
          stem: q.stem || "",
          choices: q.choices || { A: "", B: "", C: "", D: "" },
          correct: q.correct || "A",
          explanation: q.explanation || "",
          topic: q.topic ?? q.objectiveCovered ?? q.lectureRef ?? "Block Review",
          objectiveId: q.objectiveId || null,
          difficulty: q.difficulty || blockDiff || "medium",
          usedUploadedStyle: !!q.usedUploadedStyle || !!examContext.hasUploadedQs,
        }));
        allQuestions.push(...qs);

        if (qs.length < batchSize * 0.5 && allQuestions.length < questionCount) {
          console.log(`Batch ${batch + 1} only got ${qs.length}/${batchSize} — retrying for remainder`);
          const retryCount = Math.min(batchSize - qs.length, questionCount - allQuestions.length);
          try {
            const retryPrompt = buildExamPromptFromContext(retryCount, batchObjs.slice(3), { ...examContext, stylePrefs }, blockDiff);
            const retryRes = await fetch(
              `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=${GEMINI_KEY}`,
              {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                  contents: [{ parts: [{ text: retryPrompt }] }],
                  generationConfig: { maxOutputTokens: 16000, temperature: 0.8 },
                  safetySettings,
                }),
              }
            );
            const retryD = await retryRes.json();
            const retryRaw = retryD.candidates?.[0]?.content?.parts?.[0]?.text || "";
            const retryParsed = safeJSON(retryRaw);
            const retryQs = (retryParsed.questions || []).map((q, i) => ({
              id: `blockexam_retry_${Date.now()}_${i}`,
              stem: q.stem || "",
              choices: q.choices || { A: "", B: "", C: "", D: "" },
              correct: q.correct || "A",
              explanation: q.explanation || "",
              topic: q.topic ?? q.objectiveCovered ?? q.lectureRef ?? "Block Review",
              objectiveId: q.objectiveId || null,
              difficulty: q.difficulty || blockDiff || "medium",
              usedUploadedStyle: !!q.usedUploadedStyle,
            }));
            allQuestions.push(...retryQs);
          } catch (e) {
            console.warn("Retry batch failed:", e.message);
          }
        }

        await new Promise((r) => setTimeout(r, 300));
      }

      const questions = allQuestions.slice(0, questionCount);
      const validatedQuestions = validateAndFixQuestions(questions);
      setCurrentSessionMeta({
        blockId: bid,
        topicKey: "block__" + bid,
        difficulty: blockDiff,
        targetObjectives: targetObjs,
      });
      setStudyCfg({
        mode: "objectives",
        vignettes: validatedQuestions,
        subject: "Block Exam",
        subtopic: mode === "weak" ? "Weak Objectives" : mode === "objectives" ? "Objectives Weighted" : "Full Review",
        blockId: bid,
        blockName: activeBlock?.name || bid,
        termColor: tc,
        objectiveBlockId: bid,
      });
    studyReturnViewRef.current = view !== "study" ? view : studyReturnViewRef.current;
    setView("study");
    } catch (e) {
      console.error("Block exam generation failed:", e);
      alert("Exam generation failed: " + (e.message || String(e)));
    } finally {
      setBlockExamLoading(false);
    }
  };

  const startObjectiveQuiz = async (objectives, lectureTitle, optionalBlockId, extraMeta = {}) => {
    if (!objectives?.length) return;
    setQuizGenerating(true);
    setQuizGeneratingMsg("Generating questions...");
    setQuizError(null);
    const bid = optionalBlockId ?? blockId;
    let questionBanksByFile = {};
    try {
      questionBanksByFile = JSON.parse(localStorage.getItem("rxt-question-banks") || "{}");
    } catch {}
    const lecForQuiz = lectures.find(
      (l) =>
        l.blockId === bid &&
        (l.lectureTitle || l.fileName || "")
          .toLowerCase()
          .includes((lectureTitle || "").slice(0, 20).toLowerCase())
    );
    const lectureIdForMeta =
      extraMeta?.lectureId ??
      objectives?.map((o) => o.linkedLecId).find(Boolean) ??
      objectives?.[0]?.linkedLecId ??
      lecForQuiz?.id ??
      null;
    const quizLevelSnap = getLecQuizLevel(lectureIdForMeta, bid) || { level: 1 };

    const flatStore = bid ? getMSKObjectives(bid) : [];
    const byId = new Map(flatStore.map((o) => [o.id, o]));
    const merged = (objectives || []).map((o) => {
      if (!o?.id) return enrichObjectiveForLectureQuiz(o);
      const fresh = byId.get(o.id);
      return enrichObjectiveForLectureQuiz(fresh ? { ...o, ...fresh } : o);
    });
    const sorted = [...merged].sort((a, b) => (a.consecutiveCorrect || 0) - (b.consecutiveCorrect || 0));
    const maxLen = sorted.length;
    const rawQ = extraMeta.questionCount;
    let takeN;
    if (rawQ === "all") takeN = maxLen;
    else if (rawQ == null) takeN = Math.min(10, maxLen);
    else takeN = Math.max(1, Number(rawQ));
    // `selected` is the UNIQUE objective pool (max maxLen). The total *question* count
    // (takeN) is honored separately by the batch loop below — when takeN > maxLen we
    // ask the LLM for additional questions on the weakest-first objectives with fresh
    // angles, instead of putting duplicate entries in the prompt (which made it dedupe
    // and return fewer questions than asked).
    const selected = sorted.slice(0, Math.min(takeN, maxLen));
    const targetQuestionCount = Math.max(takeN, selected.length);
    if (!selected.length) {
      setQuizGenerating(false);
      setQuizGeneratingMsg("");
      return;
    }

    const useContentBased = selected.length < 5;

    const lectureContent = lecForQuiz ? getLecText(lecForQuiz) : "";
    const allChunkText = (lecForQuiz?.chunks || []).map((c) => getChunkBody(c)).join("\n\n");
    const contentToUse = lectureContent.length > allChunkText.length ? lectureContent : allChunkText;

    if (allChunkText.length < 200 && selected.length < 2) {
      setQuizError(
        `Not enough content extracted from "${lectureTitle}". Re-upload the PDF to improve extraction before quizzing.`
      );
      setQuizGenerating(false);
      setQuizGeneratingMsg("");
      return;
    }

    const tier = getLecQuestionLevel(lecForQuiz || { id: lectureIdForMeta }, bid);
    const tierLabel = ORDER_LABELS[tier] || ORDER_LABELS[1];

    setQuizLoadingId(lectureIdForMeta);
    setQuizErrorId(null);
    setQuizSavedState(null);
    const topicKey = bid ? "block__" + bid + "__objectives" : "default";
    const diffKey = bid ? "block__" + bid : "default";
    const difficulty = getTopicDifficulty(diffKey);
    console.log(
      `Generating quiz for ${lectureTitle} — tier ${tier} (${tierLabel}) · ${topicKey} · difficulty ${difficulty}`
    );
    setBlockExamLoading(`Generating quiz for ${lectureTitle}...`);
    const lectureIdForContext = lecForQuiz?.id ?? null;
    const quizContext = buildQuestionContext(bid, lectureIdForContext, questionBanksByFile, "quiz", { objectivesOnlyQuiz: true });

    // ── Layer 2: serve banked Qs verbatim, fill remainder with LLM ──────────
    // Pull matching Q-bank entries for this lecture, prefer wrong-marked, cap at
    // half of the requested count (or 5, whichever lower) so we still get fresh
    // generated material on top.
    const bankServeVignettes = (() => {
      try {
        const all = Object.values(questionBanksByFile || {}).flat();
        const lecTitleLc = (lectureTitle || "").toLowerCase().slice(0, 25);
        const matches = all.filter((q) => {
          if (!q || !q.stem || !q.choices) return false;
          if (q.blockId && bid && q.blockId !== bid) return false;
          // Match by lecture title fragment OR explicit lectureRef.
          const topicLc = String(q.topic || "").toLowerCase();
          const titleHit = lecTitleLc && (topicLc.includes(lecTitleLc) || lecTitleLc.includes(topicLc.slice(0, 18)));
          const lecRefHit = q.lectureRef && lecForQuiz?.id && q.lectureRef === lecForQuiz.id;
          return titleHit || lecRefHit;
        });
        // Wrong-marked banks first, then neutral, dedupe by stem.
        matches.sort((a, b) => {
          const aw = a.bankType === "wrong" ? 0 : 1;
          const bw = b.bankType === "wrong" ? 0 : 1;
          if (aw !== bw) return aw - bw;
          return Math.random() - 0.5;
        });
        const seen = new Set();
        const cap = Math.min(Math.floor(targetQuestionCount / 2), 5, matches.length);
        const picked = [];
        for (const q of matches) {
          if (picked.length >= cap) break;
          const key = String(q.stem || "").slice(0, 80).toLowerCase();
          if (seen.has(key)) continue;
          seen.add(key);
          // Normalise choices into A/B/C/D map regardless of source format.
          let choicesMap = {};
          if (q.choices && typeof q.choices === "object" && !Array.isArray(q.choices)) {
            ["A", "B", "C", "D"].forEach((L) => {
              if (q.choices[L] != null) choicesMap[L] = String(q.choices[L]);
            });
          } else if (Array.isArray(q.choices)) {
            ["A", "B", "C", "D"].forEach((L, i) => {
              if (q.choices[i] != null) choicesMap[L] = String(q.choices[i]);
            });
          }
          const correctLetter = String(q.correct || q.correctAnswer || "")
            .toUpperCase()
            .replace(/[^A-D]/g, "")
            .slice(0, 1);
          if (!correctLetter || !choicesMap[correctLetter]) continue;
          picked.push({
            id: `bank_${q.id || (typeof crypto !== "undefined" && crypto.randomUUID ? crypto.randomUUID() : Date.now() + "_" + picked.length)}`,
            stem: String(q.stem || q.question || "").trim(),
            choices: choicesMap,
            correct: correctLetter,
            explanation: String(q.explanation || q.rationale || "").trim() || `Correct answer: ${correctLetter}`,
            topic: q.topic || lectureTitle,
            qLevel: q.qLevel || 2,
            difficulty: q.difficulty || "medium",
            quizDifficultyTier: tier,
            objectiveId: null,
            objectiveCovered: q.objectiveCovered || null,
            lectureRef: lecForQuiz?.id || null,
            usedUploadedStyle: true,
            fromBank: true,
            bankSource: q.sourceFile || null,
            bankType: q.bankType || "neutral",
          });
        }
        return picked;
      } catch (e) {
        console.warn("Layer 2 bank-pull failed:", e);
        return [];
      }
    })();
    const questionCount = Math.max(0, targetQuestionCount - bankServeVignettes.length);
    if (bankServeVignettes.length > 0) {
      setQuizGeneratingMsg(`Pulled ${bankServeVignettes.length} from your uploaded exams · generating ${questionCount} more…`);
    }
    if (questionCount === 0) {
      // Edge case: bank fully covers requested count — skip LLM entirely.
      const bankOnlyCfg = {
        mode: "objectives",
        vignettes: bankServeVignettes,
        subject: lectureTitle,
        subtopic: "Objectives",
        blockId: bid,
        lectureId: lectureIdForMeta,
        blockName: activeBlock?.name || bid,
        termColor: tc,
        objectiveBlockId: bid,
        quizLevelSnap,
        perObjectiveDrillQuiz: true,
        qCount: bankServeVignettes.length,
        quizSessionObjectives: selected,
        lectureSlideImages: lecForQuiz?.slideImages || [],
        quizDifficultyTier: tier,
        quizTierLabel: tierLabel,
      };
      setBlockExamLoading(null);
      setQuizLoadingId(null);
      setCurrentSessionMeta({
        ...extraMeta,
        blockId: bid,
        topicKey: makeTopicKey(lectureIdForMeta, bid),
        difficulty,
        targetObjectives: selected,
        lectureTitle,
        lectureId: lectureIdForMeta,
        sessionType: "quiz",
        quizLevelSnap,
        perObjectiveDrillQuiz: true,
        quizDifficultyTier: tier,
        quizTierLabel: tierLabel,
      });
      setStudyCfg(bankOnlyCfg);
      studyReturnViewRef.current = view !== "study" ? view : studyReturnViewRef.current;
      setView("study");
      setQuizGenerating(false);
      setQuizGeneratingMsg("");
      return;
    }

    const tierInstruction = QUIZ_TIER_INSTRUCTIONS[tier] || QUIZ_TIER_INSTRUCTIONS[1];

    const systemPrompt = `You are a USMLE Step 1 question writer 
generating MCQs for a medical student.

STRICT CONTENT RULES:
1. Every question MUST be directly answerable from the 
   LECTURE CONTENT section in the user message — that section is 
   always required when text is available; do not add outside facts
2. EXCEPTION for Tier 3: you MAY extend into Step 1 
   concepts that naturally connect to the lecture content
   (e.g. if lecture covers aortic coarctation, you can 
   reference Turner syndrome or hypertension mechanisms)
3. Do NOT use the block name "CPR" or module name as 
   the question source — use ONLY the lecture title and content
4. Never generate generic anatomy or physiology questions
   unrelated to this specific lecture

CRITICAL FORMATTING RULES:
- The stem MUST end with a clear question mark
- Keep the clinical vignette to 3-4 sentences MAX
- The actual question must be on the last line
- Never cut off mid-sentence
- Format: [Vignette 3-4 sentences]. [Question]?
- Total stem must be under 100 words

${tierInstruction}

Lecture: ${lectureTitle}
Current student level: ${tierLabel}`;

    try {
      const BATCH_SIZE = 5;
      const allRawItems = [];
      // Drive the loop by total questions requested, not just objective count, so a
      // 10-question request against 7 objectives produces 10 questions (cycling the
      // unique objective list across batches with fresh angle hints).
      for (let i = 0; i < questionCount; i += BATCH_SIZE) {
        const batchCount = Math.min(BATCH_SIZE, questionCount - i);
        const batchObjs = [];
        for (let j = 0; j < batchCount; j++) batchObjs.push(selected[(i + j) % selected.length]);
        const seenInBatch = new Set();
        const objectivesList = batchObjs
          .map((o, ix) => {
            const key = o?.id || ix;
            const isRepeat = seenInBatch.has(key);
            seenInBatch.add(key);
            const tag = isRepeat ? " (different angle from above)" : "";
            return `${ix + 1}. ${(o.text || o.objective || "").trim()}${tag}`;
          })
          .join("\n");

        const tier3Block =
          tier === 3
            ? `
  STEP 1 INTEGRATION — for Tier 3 questions you may reference:
  - Pathophysiology mechanisms implied by this lecture's content
  - Related embryology, pharmacology, or clinical presentations
  - Connections between this lecture's structures and systemic disease
  - BUT only extend concepts that are directly relevant to the objectives
  `
            : "";

        const step1ConnJson = tier === 3 ? '"How this connects to Step 1..."' : "null";

        const lectureBody =
          contentToUse.trim().length > 0
            ? `${LECTURE_MARKDOWN_CONTEXT_FOR_AI}

  LECTURE CONTENT (required — every question must be grounded in this text):
  ${contentToUse.slice(0, 6000)}`
            : `LECTURE CONTENT: (none extracted — keep questions tightly aligned to the objective wording below and avoid inventing facts.)`;

        const batchUserPrompt = `
  LECTURE: ${lectureTitle}
  BLOCK: ${bid || ""}
  STUDENT LEVEL: ${tierLabel} — generate questions at this difficulty
  
  LEARNING OBJECTIVES (generate at least 1 question per objective):
  ${objectivesList}
  
  ${lectureBody}
  
  ${tier3Block}
  ${
    useContentBased
      ? `FEW OBJECTIVES (<5 total for this quiz): Generate all ${batchCount} questions in this batch. Cover each objective where possible, then add the rest as lecture-content questions (definitions, mechanisms, table comparisons, bolded terms, clinical details from the LECTURE CONTENT above). Map each question to the closest objective index (1–${batchCount}).`
      : "Include lecture-specific detail from the LECTURE CONTENT above in every stem or answer — do not write questions that could be answered from the objective line alone when the lecture text adds facts."
  }
  
  Generate ${batchCount} questions at ${tierLabel} difficulty.
  
  Every question must:
  - Test one or more of the listed objectives
  - Use the LECTURE CONTENT section as the primary source whenever it is non-empty
  - Have 4 options where wrong answers require real knowledge to exclude
  - Include explanation of why correct answer is right
  - Include why each wrong answer is wrong (whyWrong field)
  - Include a teaching point connecting to the bigger picture
  
  Return JSON array only:
  [{
    "stem": "A 45-year-old presents with...",
    "style": "vignette",
    "tier": ${tier},
    "objectiveIndices": [1],
    "options": [
      {"letter":"A","text":"...","isCorrect":false,
       "whyWrong":"This is wrong because..."},
      {"letter":"B","text":"...","isCorrect":true,"whyWrong":null},
      {"letter":"C","text":"...","isCorrect":false,
       "whyWrong":"This is wrong because..."},
      {"letter":"D","text":"...","isCorrect":false,
       "whyWrong":"This is wrong because..."}
    ],
    "explanation": "B is correct because...",
    "teachingPoint": "Key concept: ...",
    "step1Connection": ${step1ConnJson}
  }]`;
        setBlockExamLoading(
          `Generating quiz for ${lectureTitle}… (${Math.min(i + BATCH_SIZE, questionCount)}/${questionCount})`
        );
        setQuizGeneratingMsg(
          `Generating questions ${i + 1}–${Math.min(i + batchCount, questionCount)}...`
        );
        try {
          const batchResult = await callAIJSON(systemPrompt, batchUserPrompt, [], 6000, aiProvider);
          const batchList = Array.isArray(batchResult) ? batchResult : batchResult?.questions;
          if (Array.isArray(batchList) && batchList.length > 0) {
            allRawItems.push(...batchList);
            setQuizGeneratingMsg(`Generated ${allRawItems.length} questions...`);
          } else {
            console.warn(`Batch ${Math.floor(i / BATCH_SIZE) + 1} returned no questions — skipping`);
          }
        } catch (err) {
          console.warn(`Batch ${Math.floor(i / BATCH_SIZE) + 1} failed: ${err?.message || String(err)} — skipping`);
        }
      }
      const rawList = allRawItems.slice(0, questionCount);
      if (!rawList.length) {
        setQuizError("Could not generate questions — please try again");
        return;
      }
      const questions = rawList.slice(0, questionCount).map((q, i) => {
        const norm = normalizeObjectiveQuizAiItem(q, selected, i);
        const stem = norm.stem.trim();
        const rawLvl = q.level != null ? Number(q.level) : NaN;
        const qLevel = [1, 2, 3].includes(rawLvl) ? rawLvl : inferQuestionLevel(stem);
        // Map question back to its target objective. The batch loop cycles through
        // unique objectives via `selected[(batchStart + j) % selected.length]`, so for
        // overall question index i the target objective is selected[i % selected.length].
        const cycledObj = selected[i % selected.length] || null;
        const primaryIdx = (norm.objectiveIndices && norm.objectiveIndices[0]) || null;
        const primaryObj = primaryIdx != null ? (selected[(primaryIdx - 1) % selected.length] || cycledObj) : cycledObj;
        return {
          ...norm,
          stem,
          id: `objquiz_${Date.now()}_${i}`,
          num: i + 1,
          qLevel,
          difficulty: q.difficulty || difficulty || "medium",
          topic: q.topic || lectureTitle,
          usedUploadedStyle: !!q.usedUploadedStyle || !!quizContext.hasUploadedQs,
          step1Connection: norm.step1Connection ?? null,
          quizDifficultyTier: tier,
          objectiveId:
            norm.objectiveId ||
            q.objectiveId ||
            (q.objectiveIndex != null && selected[(Number(q.objectiveIndex) - 1) % selected.length]?.id) ||
            primaryObj?.id ||
            cycledObj?.id ||
            null,
        };
      });
      const afterFix = validateAndFixQuestions(questions);
      const validQuestions = filterObjectiveQuizQuestionsForTruncation(afterFix);
      if (validQuestions.length < afterFix.length) {
        console.warn(
          `Filtered ${afterFix.length - validQuestions.length} invalid/truncated objective quiz questions`
        );
      }
      if (!validQuestions.length) {
        setQuizError("Could not generate questions — please try again");
        setBlockExamLoading(null);
        setQuizLoadingId(null);
        setQuizGenerating(false);
        setQuizGeneratingMsg("");
        return;
      }
      const validated = validQuestions.map((q, i) => {
        const primaryIdx = (q.objectiveIndices && q.objectiveIndices[0]) || i + 1;
        const matched =
          selected.find((o) => o.id === q.objectiveId) || selected[primaryIdx - 1] || selected[i] || null;
        return {
          ...q,
          qLevel: q.qLevel ?? inferQuestionLevel(q.stem),
          objectiveId: q.objectiveId || matched?.id || null,
          objectiveCovered: (matched?.objective || matched?.text || q.objectiveCovered || "").slice(0, 400),
          lectureRef: lectureIdForMeta,
        };
      });
      setBlockExamLoading(null);
      setCurrentSessionMeta({
        ...extraMeta,
        blockId: bid,
        topicKey: makeTopicKey(lectureIdForMeta, bid),
        difficulty,
        targetObjectives: selected,
        lectureTitle,
        lectureId: lectureIdForMeta,
        sessionType: "quiz",
        quizLevelSnap,
        perObjectiveDrillQuiz: true,
        quizDifficultyTier: tier,
        quizTierLabel: tierLabel,
      });
      // Layer 2: prepend the verbatim banked Qs (real exam stems first, generated after).
      const finalVignettes = [...bankServeVignettes, ...validated];
      setStudyCfg({
        mode: "objectives",
        vignettes: finalVignettes,
        subject: lectureTitle,
        subtopic: "Objectives",
        blockId: bid,
        lectureId: lectureIdForMeta,
        blockName: activeBlock?.name || bid,
        termColor: tc,
        objectiveBlockId: bid,
        quizLevelSnap,
        perObjectiveDrillQuiz: true,
        qCount: finalVignettes.length,
        quizSessionObjectives: selected,
        lectureSlideImages: lecForQuiz?.slideImages || [],
        quizDifficultyTier: tier,
        quizTierLabel: tierLabel,
        bankServedCount: bankServeVignettes.length,
      });
      studyReturnViewRef.current = view !== "study" ? view : studyReturnViewRef.current;
      setView("study");
    } catch (e) {
      setBlockExamLoading(null);
      setQuizErrorId(lectureIdForMeta ?? extraMeta?.lectureId ?? null);
      console.error("startObjectiveQuiz failed:", e.message);
      setQuizError("Quiz generation failed: " + (e.message || String(e)));
    } finally {
      setQuizLoadingId(null);
      setQuizGenerating(false);
      setQuizGeneratingMsg("");
    }
  };

  const updateObjectivesFromQuiz = (lecId, bid, questionResults) => {
    try {
      const flat = [...getMSKObjectives(bid)];
      let changed = false;

      const findSlot = (o, result) => {
        const byId = o.id === result.objectiveId;
        const byText =
          result.objectiveText &&
          String(o.objective || o.text || "")
            .toLowerCase()
            .includes(String(result.objectiveText).toLowerCase().slice(0, 40));
        return byId || byText;
      };

      (questionResults || []).forEach((result) => {
        const idx = flat.findIndex((o) => findSlot(o, result));
        if (idx === -1) return;
        const obj = flat[idx];
        if (obj?.linkedLecId && lecId && obj.linkedLecId !== lecId) return;

        const prevStatus = obj.status;
        const score = Number.isFinite(result.score) ? Number(result.score) : result.correct ? 100 : 0;
        let newStatus;
        if (score >= 80 || result.correct === true) newStatus = "mastered";
        else if (score >= 50) newStatus = "inprogress";
        else newStatus = "struggling";

        const statusOrder = { untested: 0, inprogress: 1, struggling: 1, mastered: 2 };
        const prevOrder = statusOrder[prevStatus] ?? 0;
        const newOrder = statusOrder[newStatus] ?? 0;
        if (newOrder >= prevOrder || score < 30) {
          flat[idx] = {
            ...obj,
            status: newStatus,
            lastQuizzed: new Date().toISOString(),
            lastQuizScore: score,
          };
          changed = true;
        }
      });

      if (changed) {
        saveMSKObjectives(bid, flat);
      }
      return changed;
    } catch (e) {
      console.error("updateObjectivesFromQuiz failed:", e);
      return false;
    }
  };

  const updateAllLecObjectivesFromScore = (lecId, bid, overallScore) => {
    writeObjectiveStatuses(lecId, bid, overallScore);
    return true;
  };

  const updateObjectivesFromSession = (lecId, bid, objResults) => {
    try {
      const flat = [...getMSKObjectives(bid)];
      let changed = false;

      (objResults || []).forEach((result) => {
        const idx = flat.findIndex(
          (o) => o.id === result.objectiveId || (o.linkedLecId === lecId && result.objectiveId == null)
        );
        if (idx === -1) return;
        const score = Number(result?.score ?? 0);
        let newStatus;
        if (score >= 80) newStatus = "mastered";
        else if (score >= 55) newStatus = "inprogress";
        else newStatus = "struggling";
        const statusOrder = { untested: 0, inprogress: 1, struggling: 1, mastered: 2 };
        const prev = statusOrder[flat[idx]?.status] ?? 0;
        const next = statusOrder[newStatus] ?? 0;
        if (next >= prev || score < 30) {
          flat[idx] = {
            ...flat[idx],
            status: newStatus,
            lastSessionDate: new Date().toISOString(),
            lastSessionScore: score,
          };
          changed = true;
        }
      });
      if (changed) {
        saveMSKObjectives(bid, flat);
      }
      return changed;
    } catch (e) {
      console.error("updateObjectivesFromSession failed:", e);
      return false;
    }
  };

  const updateAllLecObjectivesFromSessionScore = (lecId, bid, score) => {
    try {
      const flat = [...getMSKObjectives(bid)];
      let changed = false;
      flat.forEach((obj, idx) => {
        if (obj.linkedLecId !== lecId) return;
        let newStatus;
        if (score >= 80) newStatus = "mastered";
        else if (score >= 55) newStatus = "inprogress";
        else newStatus = "struggling";
        const statusOrder = { untested: 0, inprogress: 1, struggling: 1, mastered: 2 };
        const prev = statusOrder[obj.status] ?? 0;
        const next = statusOrder[newStatus] ?? 0;
        if (next >= prev || score < 30) {
          flat[idx] = {
            ...obj,
            status: newStatus,
            lastSessionDate: new Date().toISOString(),
            lastSessionScore: score,
          };
          changed = true;
        }
      });
      if (changed) {
        saveMSKObjectives(bid, flat);
      }
      return changed;
    } catch (e) {
      console.error("updateAllLecObjectivesFromSessionScore failed:", e);
      return false;
    }
  };

  const saveQuizSession = (lec, bid, score, questionCount) => {
    try {
      const perfKey = "rxt-performance";
      const stored = JSON.parse(localStorage.getItem(perfKey) || "{}");
      const key = `${lec.id}__${bid}`;
      const existing = stored[key] || {};
      const now = new Date().toISOString();
      const existingSessions = Array.isArray(existing.sessions) ? existing.sessions : [];
      const sessionRecord = {
        score,
        date: now,
        startedAt: now,
        completedAt: now,
        questionCount: questionCount || 0,
        difficulty: currentSessionMeta?.difficulty || "medium",
        sessionType: "quiz",
        lectureId: lec.id,
        blockId: bid,
        topicKey: makeTopicKey(lec.id, bid),
        lectureType: lec?.lectureType ?? null,
        lectureNumber: lec?.lectureNumber ?? null,
        lectureName: lec?.lectureTitle || lec?.filename || lec?.fileName || null,
      };
      stored[key] = {
        ...existing,
        lectureId: lec.id,
        blockId: bid,
        score,
        date: now,
        sessions: [...existingSessions, sessionRecord].slice(-50),
        sessionType: "quiz",
        questionCount: questionCount || 0,
        lastQuizScore: score,
        lastScore: score,
        lastStudied: now,
      };
      localStorage.setItem(perfKey, JSON.stringify(stored));
      setPerformanceHistory((prev) => ({ ...prev, [key]: stored[key] }));
      window.dispatchEvent(new CustomEvent("rxt-completion-updated"));
      window.dispatchEvent(new CustomEvent("rxt-objectives-updated"));
    } catch (e) {
      console.error("saveQuizSession perf failed:", e);
    }
  };

  const syncQuizToTracker = (lec, bid, score) => {
    try {
      const completionKey = "rxt-completion";
      const stored = JSON.parse(localStorage.getItem(completionKey) || "{}");
      const key = `${lec.id}__${bid}`;
      const existing = stored[key] || {
        lectureId: lec.id,
        blockId: bid,
        ankiInRotation: false,
        firstCompletedDate: new Date().toISOString(),
        lastActivityDate: null,
        lastConfidence: null,
        reviewDates: [],
        activityLog: [],
      };
      const confidence = score >= 75 ? "good" : score >= 50 ? "okay" : "struggling";
      const now = new Date().toISOString();
      const activityEntry = {
        id: uid(),
        date: now,
        activityType: "questions",
        confidenceRating: confidence,
        durationMinutes: null,
        note: `Quiz — ${score}% on ${lec.lectureType} ${lec.lectureNumber}`,
      };
      const updatedLog = [activityEntry, ...(existing.activityLog || [])];
      const today = new Date();
      today.setHours(0, 0, 0, 0);
      const intervals =
        confidence === "good" ? [2, 7, 14, 30] : confidence === "okay" ? [1, 5, 10, 21] : [0, 2, 5, 10];
      const reviewDates = intervals.map((d) => {
        const r = new Date(today);
        r.setDate(r.getDate() + d);
        return r.toISOString();
      });
      stored[key] = {
        ...existing,
        lastActivityDate: now,
        lastConfidence: confidence,
        firstCompletedDate: existing.firstCompletedDate || now,
        reviewDates,
        activityLog: updatedLog,
      };
      localStorage.setItem(completionKey, JSON.stringify(stored));
      window.dispatchEvent(new CustomEvent("rxt-completion-updated"));
      window.dispatchEvent(new CustomEvent("rxt-objectives-updated"));
    } catch (e) {
      console.error("syncQuizToTracker failed:", e);
    }
  };

  const distributeResultsToSubtopics = (_results, _lec, _blockId) => {
    // Session data is written only in finalizeSession — no separate subtopic writes
  };

  const finalizeSession = (results, meta) => {
    const sessionMeta = meta || currentSessionMeta;
    const bid = sessionMeta?.blockId ?? blockId;
    const targetLecId =
      sessionMeta?.lectureId ??
      sessionMeta?.targetObjectives?.[0]?.linkedLecId ??
      (studyCfg?.mode === "lecture" ? studyCfg?.lecture?.id : null);

    if (!targetLecId) {
      console.warn("⚠️ finalizeSession called without lectureId — session not saved");
      return;
    }

    const targetLec = lectures.find((l) => l.id === targetLecId);
    const targetObjectives = sessionMeta?.targetObjectives ?? [];
    const syncStats = syncSessionToObjectives(results, bid, targetObjectives, targetLecId);

    const topicKey = makeTopicKey(targetLecId, bid);
    const now = new Date().toISOString();
    const date = now;
    const correct = results.filter((r) => mcqResultCountsTowardCorrectScore(r)).length;
    const total = results.length;

    const sessionRecord = {
      score: Math.round((correct / Math.max(total, 1)) * 100),
      date: now,
      startedAt: sessionMeta?.startedAt || now,
      completedAt: now,
      questionCount: total,
      difficulty: sessionMeta?.difficulty || "medium",
      sessionType: sessionMeta?.sessionType || "quiz",
      lectureId: targetLecId,
      blockId: bid,
      topicKey,
      lectureType: targetLec?.lectureType ?? null,
      lectureNumber: targetLec?.lectureNumber ?? null,
      lectureName: targetLec?.lectureTitle || targetLec?.filename || targetLec?.fileName || null,
      preSAQScore: sessionMeta?.preSAQScore ?? null,
      postMCQScore: sessionMeta?.postMCQScore ?? null,
      confidenceLevel: sessionMeta?.confidenceLevel ?? null,
      nextReview: sessionMeta?.nextReview ?? null,
      ...(sessionMeta?.sessionType === "anki" && {
        cardCount: sessionMeta.cardCount ?? null,
        newCards: sessionMeta.newCards ?? null,
        reviewCards: sessionMeta.reviewCards ?? null,
        retention: sessionMeta.retention ?? null,
        timeSpent: sessionMeta.timeSpent ?? null,
        notes: sessionMeta.notes ?? null,
      }),
    };
    const overallScore = sessionRecord.score;

    setPerformanceHistory((prev) => {
      const existing = prev[topicKey] || { sessions: [] };
      const updated = {
        ...existing,
        sessions: [...(existing.sessions || []), sessionRecord].slice(-50),
        lastStudied: now,
        firstStudied: existing.firstStudied || now,
        lastScore: sessionRecord.score,
        lectureId: targetLecId,
        blockId: bid,
        lectureType: sessionRecord.lectureType ?? targetLec?.lectureType ?? existing.lectureType,
        lectureNumber: sessionRecord.lectureNumber ?? targetLec?.lectureNumber ?? existing.lectureNumber,
        lectureName: sessionRecord.lectureName ?? (targetLec?.lectureTitle || targetLec?.filename || targetLec?.fileName) ?? existing.lectureName,
        confidenceLevel: sessionRecord.confidenceLevel ?? existing.confidenceLevel,
        nextReview: sessionMeta?.nextReview
          ? (() => {
              const d = new Date();
              d.setDate(d.getDate() + sessionMeta.nextReview);
              return d.toISOString();
            })()
          : existing.nextReview,
        currentDifficulty: sessionMeta?.difficulty || existing.currentDifficulty || "medium",
      };
      const newState = { ...prev, [topicKey]: updated };
      try {
        safeSetItem("rxt-performance", newState);
      } catch {}
      console.log("✅ Session saved:", topicKey, sessionRecord);
      return newState;
    });

    // Activity tracking (rxt-completion) — separate from rxt-performance
    if (targetLecId && bid && sessionRecord?.sessionType) {
      const confMap =
        sessionRecord.confidenceLevel === "High" ? "good"
          : sessionRecord.confidenceLevel === "Low" ? "struggling"
            : sessionRecord.confidenceLevel === "Medium" ? "okay"
              : "okay";
      const activityType =
        sessionRecord.sessionType === "deepLearn" ? "deep_learn"
          : sessionRecord.sessionType === "anki" ? "anki"
            : sessionRecord.sessionType === "quiz" || sessionRecord.sessionType === "objectiveQuiz" || sessionRecord.sessionType === "blockExam"
              ? "questions"
              : "manual";
      logActivityToCompletion(targetLecId, bid, activityType, confMap, { date: now.slice(0, 10) });
    }

    if (sessionMeta?.sessionType === "deepLearn" && targetLecId && bid) {
      const objResults = (results || [])
        .filter((r) => r && (r.objectiveId || r.score != null || r.correct != null))
        .map((r) => {
          const guessed = r.confidenceFlag === "guessed";
          const baseScore = Number.isFinite(r.score) ? Number(r.score) : r.correct ? 100 : 0;
          return {
            objectiveId: r.objectiveId || null,
            score: guessed ? 60 : baseScore,
            confidenceFlag: r.confidenceFlag || null,
          };
        });
      if (objResults.some((r) => !!r.objectiveId)) {
        updateObjectivesFromSession(targetLecId, bid, objResults);
      } else {
        updateAllLecObjectivesFromSessionScore(targetLecId, bid, overallScore);
      }
      if (targetLec) {
        const label = `${targetLec.lectureType || "LEC"} ${targetLec.lectureNumber ?? ""} — ${targetLec.lectureTitle || targetLec.fileName || ""}`;
        for (const r of results || []) {
          if (r?._weakLogged) continue; // already recorded per-question
          const guessed = r?.confidenceFlag === "guessed";
          const wrong = r?.correct === false || (Number.isFinite(r?.score) && r.score < 60);
          if (!guessed && !wrong) continue;
          void recordWrongAnswer({
            blockId: bid,
            blockName: activeBlock?.name || "",
            question: r.stem || r.topic || "Deep Learn MCQ",
            wrongAnswer: guessed
              ? "Guessed / lucky (self-reported)"
              : String(r.userAnswerText || r.selectedText || r.chosen || "incorrect").slice(0, 200),
            correctAnswer: String(r.correctText || r.correctAnswer || "").slice(0, 200),
            linkedLecId: targetLec.id,
            lectureLabel: label,
            source: guessed ? "deeplearn-guessed" : "deeplearn",
            objectiveId: r.objectiveId || null,
          });
        }
      }
    }

    syncTrackerRow(targetLecId, bid, sessionRecord);

    if (targetLec) {
      distributeResultsToSubtopics(results, targetLec, bid);
    }

    if (syncStats?.updatedCount > 0) {
      setPerfToast({
        type: "sync",
        title: "Objectives Updated ✓",
        message:
          `${syncStats.updatedCount} objectives synced · ` +
          (syncStats.masteredCount > 0 ? `${syncStats.masteredCount} mastered · ` : "") +
          (syncStats.strugglingCount > 0 ? `${syncStats.strugglingCount} need review` : ""),
        color: syncStats.masteredCount > 0 ? "#10b981" : "#f59e0b",
      });
    } else {
      showPerformanceFeedback(topicKey, sessionRecord.score);
    }

    const base = { id: uid(), blockId: bid, termId, correct, total, date };
    const subject = studyCfg?.mode === "lecture" ? studyCfg.subject : studyCfg?.mode === "objectives" ? studyCfg.subject : "Block Exam";
    const subtopic = studyCfg?.mode === "lecture" ? studyCfg.subtopic : studyCfg?.mode === "objectives" ? "Objectives" : "Comprehensive";
    const questions = studyCfg?.vignettes?.map((q) => ({ stem: q.stem })) || [];
    if (studyCfg?.mode === "lecture") {
      setSessions((p) => [...p, { ...base, lectureId: studyCfg.lecture.id, subject, subtopic, questions }]);
    } else {
      setSessions((p) => [...p, { ...base, lectureId: null, subject, subtopic, questions }]);
    }
    syncSessionToTracker({ correct, total }, studyCfg || {});
    setTrackerKey((k) => k + 1);
    setActiveSessions((prev) => {
      const next = { ...prev };
      delete next[topicKey];
      return next;
    });
    let nextProfile = learningProfile;
    for (let i = 0; i < correct; i++) {
      nextProfile = recordAnswer(nextProfile, subject, subtopic, true, "clinicalVignette");
    }
    for (let i = 0; i < total - correct; i++) {
      nextProfile = recordAnswer(nextProfile, subject, subtopic, false, "clinicalVignette");
    }
    setLearningProfile(nextProfile);
    updateLearningProfile(nextProfile);

    {
      const updatesArr = syncStats?.updates ?? [];
      const strugglingObjs = updatesArr
        .filter((u) => u.newStatus === "struggling")
        .map((u) => ({ id: u.id, objective: u.objective, linkedLecId: targetLecId }));
      const weakByLec = {};
      strugglingObjs.forEach((obj) => {
        const lecId = targetLec?.id || "unknown";
        if (!weakByLec[lecId]) {
          weakByLec[lecId] = {
            lec: targetLec || null,
            lecLabel: targetLec
              ? `${targetLec.lectureType || "LEC"} ${targetLec.lectureNumber ?? ""} — ${targetLec.lectureTitle || targetLec.fileName || ""}`.trim()
              : "Unlinked",
            lecId,
            objectives: [],
          };
        }
        weakByLec[lecId].objectives.push(obj);
      });
      const score = total > 0 ? Math.round((correct / total) * 100) : 0;
      setSessionSummary({
        correct,
        total,
        updates: updatesArr,
        sessionType: "quiz",
        lec: targetLec || null,
        bid,
        sessionDate: now,
        mastered: correct,
        okay: 0,
        struggling: Math.max(0, total - correct),
        skipped: 0,
        score,
        totalCorrect: correct,
        totalAnswered: total,
        weakLectures: Object.values(weakByLec),
        strugglingObjs,
        levelDistribution: { advanced: 0, maintained: 0, regressed: 0 },
      });
    }
    setCurrentSessionMeta(null);
    setStudyCfg(null);
    const areas = computeWeakAreas(bid);
    setWeakAreas(areas);
    window.dispatchEvent(new CustomEvent("rxt-completion-updated"));
    window.dispatchEvent(new CustomEvent("rxt-objectives-updated"));
    // Defer background push so setState updaters have committed to localStorage.
    setTimeout(() => {
      void backgroundSync();
    }, 3000);
  };

  const handleSessionComplete = (arg1, arg2) => {
    if (sessionSaveInProgress.current) {
      console.warn("handleSessionComplete called while already in progress — skipping");
      return;
    }
    sessionSaveInProgress.current = true;
    try {
      let payload;
      if (Array.isArray(arg1) && arg2 && typeof arg2 === "object") {
        const dlResults = arg1;
        const dlMeta = arg2;
        const correct = dlResults.filter((r) => mcqResultCountsTowardCorrectScore(r)).length;
        const total = dlResults.length;
        payload = { correct, total, date: new Date().toISOString(), results: dlResults, meta: dlMeta };
      } else {
        payload = arg1 || {};
      }

      const { correct = 0, total = 0, results = [], meta } = payload;
      const sessionMeta = { ...(currentSessionMeta || {}), ...(meta || {}) };
      const score =
        total > 0
          ? Math.round(
              (results.filter((r) => mcqResultCountsTowardCorrectScore(r)).length / total) * 100
            )
          : 0;
      const lec = lectures.find(
        (l) => l.id === (sessionMeta?.lectureId ?? sessionMeta?.targetObjectives?.[0]?.linkedLecId)
      );
      const sessionType = sessionMeta?.sessionType || "quiz";

      if (sessionType === "quiz") {
        const bid = sessionMeta?.blockId ?? blockId;
        const targetLecId =
          sessionMeta?.lectureId ??
          sessionMeta?.targetObjectives?.[0]?.linkedLecId ??
          results.find((r) => r?.lectureRef)?.lectureRef ??
          null;
        const targetLec =
          lec ||
          lectures.find((l) => l.id === targetLecId) ||
          lectures.find((l) => l.id === sessionMeta?.targetObjectives?.[0]?.linkedLecId) ||
          lectures.find((l) => l.id === sessionMeta?.lectureId);
        if (targetLec && bid) {
          const questionResults = (results || []).map((r) => ({
            objectiveId: r.objectiveId || null,
            objectiveText: r.objectiveCovered || r.topic || "",
            correct: !!r.correct,
            score: Number.isFinite(r.score) ? Number(r.score) : r.correct ? 100 : 0,
          }));
          const hasObjectiveIds = questionResults.some((r) => !!r.objectiveId);
          const linkedObjCount = (getBlockObjectives(bid) || []).filter(
            (o) => o.linkedLecId === targetLec.id
          ).length;
          const perObjectiveDrillQuiz = !!sessionMeta?.perObjectiveDrillQuiz;
          const useProgressiveLecQuiz = !!sessionMeta?.quizLevelSnap && !perObjectiveDrillQuiz;
          const objectiveUpdatedCount = useProgressiveLecQuiz
            ? linkedObjCount
            : hasObjectiveIds
              ? questionResults.length
              : linkedObjCount;
          if (!useProgressiveLecQuiz) {
            if (hasObjectiveIds) {
              updateObjectivesFromQuiz(targetLec.id, bid, questionResults);
            } else {
              updateAllLecObjectivesFromScore(targetLec.id, bid, score);
            }
          }
          saveQuizSession(targetLec, bid, score, total);
          syncQuizToTracker(targetLec, bid, score);
          // Bug fix: quiz/Practice path returns early from handleSessionComplete and never
          // reaches finalizeSession, which means activity never landed in rxt-completion.
          // Without this, the Today card stayed at "0 sessions" after a completed Practice.
          // Log the activity here so the Today/Reviews/coach UI sees the session.
          try {
            const confMap =
              score >= 80 ? "good" : score >= 50 ? "okay" : "struggling";
            logActivityToCompletion(targetLec.id, bid, "questions", confMap, {
              date: new Date().toISOString().slice(0, 10),
              note: `Practice · ${score}% (${total} q)`,
            });
          } catch (e) {
            console.warn("Practice completion log failed:", e);
          }
          // Persist per-question confidence + correctness for the Analytics calibration
          // panel. We store a compact rolling log so it survives across sessions and
          // stays cheap to query.
          try {
            const confs = sessionMeta?.confidences || {};
            const calibEntries = (results || [])
              .map((r) => ({
                date: new Date().toISOString(),
                blockId: bid,
                lectureId: targetLec.id,
                questionId: r.questionId,
                confidence: r.confidence || confs[r.questionId] || null,
                correct: !!r.correct,
                score: Number.isFinite(r.score) ? Number(r.score) : (r.correct ? 100 : 0),
                tier: sessionMeta?.quizDifficultyTier ?? null,
              }))
              .filter((e) => e.confidence != null);
            if (calibEntries.length) {
              const prev = (() => {
                try { return JSON.parse(localStorage.getItem("rxt-calibration") || "[]"); } catch { return []; }
              })();
              const next = [...(Array.isArray(prev) ? prev : []), ...calibEntries].slice(-2000);
              localStorage.setItem("rxt-calibration", JSON.stringify(next));
              window.dispatchEvent(new CustomEvent("rxt-calibration-updated"));
            }
          } catch (e) {
            console.warn("Calibration log failed:", e);
          }
          let quizObjRollup = { levelAdvanced: false };
          if (perObjectiveDrillQuiz) {
            const prevSnap = sessionMeta.quizLevelSnap;
            const newLevel = getLecQuizLevel(targetLec.id, bid);
            quizObjRollup = {
              levelAdvanced: !!(prevSnap && newLevel.level > (prevSnap.level ?? 1)),
              newLevel,
            };
          } else if (useProgressiveLecQuiz) {
            quizObjRollup = writeQuizResultsToObjectives(targetLec.id, bid, score, sessionMeta.quizLevelSnap) || {
              levelAdvanced: false,
            };
          }
          if (score < 50) {
            addLectureToTodayReview(targetLec, bid);
          }
          if ((results || []).length) {
            const label = `${targetLec.lectureType || "LEC"} ${targetLec.lectureNumber ?? ""} — ${targetLec.lectureTitle || targetLec.title || targetLec.fileName || ""}`;
            const toFlag = (results || []).filter((r) => !r.correct);
            for (const r of toFlag) {
              void recordWrongAnswer({
                blockId: bid,
                blockName: activeBlock?.name || "",
                question: r.question || r.stem || `Quiz: ${r.objectiveCovered || r.topic || "objective"}`,
                wrongAnswer: String(r.userAnswer || r.selected || r.chosen || "incorrect").slice(0, 200),
                correctAnswer: String(r.correctAnswer || r.expected || "").slice(0, 200),
                linkedLecId: targetLec.id,
                lectureLabel: label,
                source: "quiz",
                objectiveId: r.objectiveId || r.objectiveCoveredId || null,
              });
            }
          }
          let tierAdvancement = null;
          if (perObjectiveDrillQuiz && sessionMeta?.quizDifficultyTier != null) {
            const prevTier = sessionMeta.quizDifficultyTier ?? 1;
            const objsAfter = (getBlockObjectives(bid) || []).filter((o) => o.linkedLecId === targetLec.id);
            const newAvgConsec = objsAfter.length
              ? objsAfter.reduce((s, o) => s + (o.consecutiveCorrect || 0), 0) / objsAfter.length
              : 0;
            const newTier =
              score >= 85 && newAvgConsec >= 4 ? 3 : score >= 70 || newAvgConsec >= 2 ? 2 : 1;
            if (newTier > prevTier) {
              tierAdvancement = {
                from: prevTier,
                to: newTier,
                message:
                  newTier === 3
                    ? "🎯 Unlocked Step 1 Level — USMLE-style questions now active"
                    : "⚕ Unlocked Applied questions — clinical scenarios now included",
              };
            }
          }
          setTrackerKey((k) => k + 1);
          setQuizSavedState({
            saved: true,
            score,
            objectiveSynced: true,
            trackerSynced: true,
            objectiveUpdatedCount,
            levelAdvanced: !!quizObjRollup.levelAdvanced,
            levelUpNewLevel: quizObjRollup.newLevel,
            tierAdvancement,
          });
          setQuizFlashLectureId(targetLec.id);
          setTimeout(() => setQuizFlashLectureId(null), 1000);
          setTimeout(() => {
            void backgroundSync();
          }, 3000);
        } else {
          setQuizSavedState({ saved: false, score, objectiveSynced: false, trackerSynced: false });
          console.warn("Quiz completed but lecture/block context missing — skipped save");
        }
        return;
      }

      if (!["anki", "deepLearn"].includes(sessionType)) {
        setPendingConfidence({
          results,
          meta,
          lectureName: lec?.lectureTitle || lec?.fileName || sessionMeta?.lectureTitle || "Study Session",
          score,
          sessionType,
        });
        return;
      }

      finalizeSession(results, meta);
    } finally {
      setTimeout(() => {
        sessionSaveInProgress.current = false;
      }, 500);
    }
  };

  const handleConfidenceRated = (confidenceLevel) => {
    if (!pendingConfidence) return;
    const { results, meta } = pendingConfidence;
    const bid = meta?.blockId ?? blockId;
    const isCurrentBlock = bid === activeBlock?.id;
    const firstSessionDate = Object.values(performanceHistory)
      .flatMap((p) => p.sessions || [])
      .filter((s) => s.blockId === bid)
      .map((s) => s.date)
      .filter(Boolean)
      .sort()[0];
    const blockAgeMonths = firstSessionDate
      ? (Date.now() - new Date(firstSessionDate)) / (1000 * 60 * 60 * 24 * 30)
      : 0;
    const nextReview = getReviewInterval(confidenceLevel, isCurrentBlock, blockAgeMonths);
    finalizeSession(results, { ...meta, confidenceLevel, nextReview });
    setPendingConfidence(null);
    setView("block");
  };

  const onSessionDone = handleSessionComplete;

  // Single unified entry point: every practice session is an MCQ vignette session
  // routed through Session/handleSessionComplete. Scope determines the objective pool.
  const startPractice = useCallback(
    async (opts = {}) => {
      const bid = opts.blockId ?? activeBlock?.id ?? blockId;
      if (!bid) {
        alert("No active block — open a block first.");
        return;
      }
      const count = Math.max(1, Math.min(50, Number(opts.count) || 10));
      const blockObjs = (() => {
        try { return getBlockObjectives(bid) || []; } catch { return []; }
      })();
      const lec = opts.lecture || (opts.lectureId ? lectures.find((l) => l.id === opts.lectureId) : null);

      let objectives = opts.objectives;
      if (!objectives) {
        if (opts.scope === "flagged") {
          let flaggedQs = [];
          try { flaggedQs = JSON.parse(localStorage.getItem("rxt-flagged-questions") || "[]"); } catch {}
          const flaggedObjIds = new Set(
            flaggedQs.filter((q) => q && q.blockId === bid && q.objectiveId).map((q) => q.objectiveId)
          );
          objectives = blockObjs.filter((o) => flaggedObjIds.has(o.id));
          if (!objectives.length) {
            const wc = (() => { try { return getWeakConcepts(bid).block || []; } catch { return []; } })();
            const wcLecIds = new Set(
              wc.filter((c) => c.masteryLevel === "struggling" || (c.missCount || 0) > 0).map((c) => c.linkedLecId).filter(Boolean)
            );
            objectives = blockObjs.filter((o) => wcLecIds.has(o.linkedLecId) && o.status === "struggling");
          }
        } else if (opts.scope === "weak") {
          objectives = blockObjs.filter((o) => o.status === "struggling");
          if (!objectives.length) {
            objectives = blockObjs.filter((o) => o.status === "inprogress").slice(0, count);
          }
        } else if (opts.scope === "lecture" && lec) {
          objectives = blockObjs.filter((o) => o.linkedLecId === lec.id);
        } else if (opts.scope === "all") {
          objectives = blockObjs.slice();
        }
      }

      if (!objectives?.length) {
        alert("No objectives found for this scope.");
        return;
      }
      // Prioritize: struggling > inprogress > untested > mastered, then truncate.
      const rank = (s) => (s === "struggling" ? 0 : s === "inprogress" ? 1 : !s || s === "untested" ? 2 : 3);
      const ordered = [...objectives].sort((a, b) => rank(a.status) - rank(b.status));
      const trimmed = ordered.slice(0, count);
      const title =
        lec?.lectureTitle ||
        lec?.fileName ||
        (opts.scope === "flagged"
          ? "Flagged practice"
          : opts.scope === "weak"
            ? "Weak objectives"
            : opts.scope === "all"
              ? "Block practice"
              : "Practice");
      await startObjectiveQuiz(trimmed, title, bid, { questionCount: count, ...(opts.extraMeta || {}) });
    },
    [activeBlock?.id, blockId, lectures, startObjectiveQuiz]
  );
  useEffect(() => {
    startPracticeRef.current = startPractice;
  }, [startPractice]);

  useEffect(() => {
    setPerformanceHistory((prev) => {
      let changed = false;
      const migrated = { ...prev };
      Object.entries(prev).forEach(([key, val]) => {
        if (key.includes("__full") || key.includes("__weak")) {
          const lecId = key.split("__")[0];
          const lec = lectures.find((l) => l.id === lecId);
          if (lec) {
            const newKey = makeTopicKey(lecId, lec.blockId);
            if (!migrated[newKey]) {
              migrated[newKey] = val;
              changed = true;
              console.log("Migrated key:", key, "→", newKey);
            }
          }
        }
      });
      if (changed) {
        try {
          safeSetItem("rxt-performance", migrated);
        } catch {}
      }
      return changed ? migrated : prev;
    });
  }, [lectures.length]);

  useEffect(() => {
    setPerformanceHistory((prev) => {
      let changed = false;
      const updated = {};
      Object.entries(prev).forEach(([key, entry]) => {
        if (entry?.sessions) {
          const migratedSessions = entry.sessions.map((s) => {
            const raw = (s.topic || "").toString();
            if (raw.includes("__full__") || raw.includes("__weak__")) {
              changed = true;
              return {
                ...s,
                topic: resolveTopicLabel(s.topicKey || key, s, s.blockId),
              };
            }
            return s;
          });
          updated[key] = { ...entry, sessions: migratedSessions };
        } else {
          updated[key] = entry;
        }
      });
      if (changed) {
        try {
          safeSetItem("rxt-performance", updated);
        } catch {}
      }
      return changed ? updated : prev;
    });
  }, [resolveTopicLabel]);

  const runAnalysis = async () => {
    setALoading(true);
    const text = await genAnalysis(sessions.filter(s => s.blockId===blockId), blockLecs);
    setAnalyses(p => ({ ...p, [blockId]:text }));
    setALoading(false);
  };

  const saveYoutubeResource = useCallback(
    async (videoId, url, transcript) => {
      const bid = activeBlock?.id;
      if (!bid) return;
      let title = `YouTube: ${videoId}`;
      try {
        const oembedTitle = await fetchYouTubeTitleOembed(videoId);
        if (oembedTitle) title = oembedTitle;
      } catch {
        /* keep default */
      }
      const resource = {
        id: typeof crypto !== "undefined" && crypto.randomUUID ? crypto.randomUUID() : uid(),
        type: "youtube",
        videoId,
        url,
        title,
        transcript,
        blockId: bid,
        addedAt: new Date().toISOString(),
        transcriptLength: transcript.length,
      };
      try {
        const stored = JSON.parse(localStorage.getItem("rxt-supplemental-resources") || "[]");
        stored.push(resource);
        localStorage.setItem("rxt-supplemental-resources", JSON.stringify(stored));
      } catch (e) {
        console.error("saveYoutubeResource:", e);
        throw e;
      }
      console.log(`Saved YouTube resource: ${title} | transcript: ${transcript.length} chars`);
    },
    [activeBlock?.id]
  );

  const handleYoutubeUpload = useCallback(async () => {
    const url = youtubeUrlInput.trim();
    if (!url) return;
    const videoId =
      url.match(/(?:v=|youtu\.be\/|embed\/)([a-zA-Z0-9_-]{11})/)?.[1] || parseYouTubeVideoId(url);
    if (!videoId) {
      setYoutubeStatus("⚠ Could not parse YouTube URL");
      return;
    }
    setYoutubeStatus("Fetching transcript...");
    setYoutubeNeedsPaste(false);
    try {
      const transcriptUrl = `https://www.youtube.com/api/timedtext?lang=en&v=${encodeURIComponent(videoId)}&fmt=json3`;
      let transcript = "";
      try {
        const res = await fetch(transcriptUrl, { mode: "cors" });
        if (!res.ok) throw new Error(String(res.status));
        const data = await res.json();
        transcript = (data.events || [])
          .filter((e) => e.segs)
          .map((e) => e.segs.map((s) => s.utf8 || "").join(""))
          .join(" ")
          .replace(/\n/g, " ")
          .trim();
      } catch {
        try {
          transcript = await fetchYouTubeTranscriptText(videoId);
        } catch {
          setYoutubeStatus(
            "⚠ Auto-fetch blocked. Open YouTube → … → Show transcript → Copy all → paste below"
          );
          setYoutubeNeedsPaste(true);
          return;
        }
      }
      if (!transcript || transcript.length < 100) {
        setYoutubeStatus("⚠ No transcript found. Try pasting manually.");
        setYoutubeNeedsPaste(true);
        return;
      }
      await saveYoutubeResource(videoId, url, transcript);
      setYoutubeStatus("✓ Video transcript added successfully");
      setYoutubeUrlInput("");
    } catch (err) {
      setYoutubeStatus("⚠ Error: " + (err?.message || String(err)));
    }
  }, [youtubeUrlInput, saveYoutubeResource]);

  const handleBlockObjectivesUpload = useCallback(
    async (file) => {
      if (!file) {
        console.warn("handleBlockObjectivesUpload: no file");
        return;
      }
      console.log("handleBlockObjectivesUpload called with:", file.name);
      const bid = activeBlock?.id;
      if (!bid) return;
      const current = localStorage.getItem("rxt-block-objectives");
      if (current) {
        localStorage.setItem("rxt-block-objectives-backup", current);
        console.log("✓ Backup saved");
      }
      try {
        setBlockObjImportStatus({ stage: "parsing", count: 0 });
        setUpMsg("Extracting objectives PDF…");
        const pdfText = await extractObjectivesPdfText(file, (msg) => setUpMsg(msg));
        const importedRaw = await parseObjectivesFromPDFText(pdfText, (cur, total) => {
          setUpMsg(`Parsing objectives… ${cur}/${total}`);
        });
        if (!importedRaw.length) throw new Error("No objectives found in PDF");
        setBlockObjImportStatus({ stage: "linking", count: importedRaw.length });
        const stored = JSON.parse(localStorage.getItem("rxt-block-objectives") || "{}");
        const { imported: existingImported = [] } = parseBlockObjectivesRaw(getBlockObjectivesStoredRaw(stored, bid));
        const blockLectures = getBlockLecs(lectures, resolveBlockMeta(bid));
        const { merged: importedMerged, added, updated, skipped } = mergeImportedObjectives(
          importedRaw,
          existingImported,
          blockLectures,
          bid
        );
        const { deduped, removed } = deduplicateObjectives(importedMerged);
        const shaped = mapMergedObjectivesToAppShape(deduped);
        const aligned =
          blockLectures.length ? alignObjectivesToLectures(bid, shaped, blockLectures) : shaped;
        const linkedCount = aligned.filter((o) => o.hasLecture).length;
        setBlockObjImportStatus({ stage: "merging", count: linkedCount });
        const existing = getMSKObjectives(bid);
        const newObjs = aligned;
        if (newObjs.length > 0 && newObjs.length < existing.length) {
          console.error(
            "SAFETY BLOCK: new count",
            newObjs.length,
            "< existing",
            existing.length,
            "— not saving"
          );
          setBlockObjImportStatus({
            stage: "error",
            error: "Import would reduce stored objective count — cancelled (safety block).",
          });
          return;
        }
        const merged = mergeObjectives(existing, newObjs);
        saveMSKObjectives(bid, merged);
        repairUnlinkedObjectives(bid);
        const finalCount = merged.length;
        setBlockObjImportStatus({ stage: "done", count: finalCount });
        try {
          window.dispatchEvent(new CustomEvent("rxt-objectives-updated"));
        } catch (_) {}
        setTimeout(() => setBlockObjImportStatus(null), 8000);
        setUpMsg(
          `✓ Objectives: ${added} added · ${updated} updated · ${removed} duplicates removed · ${skipped} skipped`
        );
        setTimeout(() => setUpMsg(""), 6000);
      } catch (err) {
        console.error(err);
        setBlockObjImportStatus({
          stage: "error",
          error: err?.message || String(err),
        });
        setUpMsg("");
        alert("Objectives PDF import failed: " + (err?.message || String(err)));
      }
    },
    [
      activeBlock?.id,
      lectures,
      alignObjectivesToLectures,
      repairUnlinkedObjectives,
      getBlockLecs,
      resolveBlockMeta,
    ]
  );

  const handleImageUpload = useCallback(
    async (e) => {
      const files = e.target.files;
      if (!files?.length || !activeBlock?.id) return;
      const bid = activeBlock?.id;
      setImageUploadModalStatus("Analyzing…");
      let ok = 0;
      try {
        for (const file of Array.from(files)) {
          const allowed = ["image/png", "image/jpeg", "image/webp"];
          if (!allowed.includes(file.type)) continue;
          const base64 = await fileToRawBase64(file);
          const systemPrompt = "You are analyzing a medical education image.";
          const userPrompt =
            "Describe in detail:\n" +
            "- All labeled structures and their relationships\n" +
            "- Any comparison being shown (e.g. tissue types side by side)\n" +
            "- Key distinguishing features visible\n" +
            "- Clinical significance of what is shown\n" +
            "Return as structured markdown with bold key terms.";
          const description = await callAIWithImage(systemPrompt, userPrompt, base64, file.type, 2500);
          const resource = {
            id: typeof crypto !== "undefined" && crypto.randomUUID ? crypto.randomUUID() : uid(),
            type: "image",
            blockId: bid,
            filename: file.name,
            aiDescription: description,
            mimeType: file.type,
            addedAt: new Date().toISOString(),
          };
          const stored = JSON.parse(localStorage.getItem("rxt-supplemental-resources") || "[]");
          stored.push(resource);
          localStorage.setItem("rxt-supplemental-resources", JSON.stringify(stored));
          ok += 1;
        }
        setImageUploadModalStatus(ok ? `✓ Indexed ${ok} image(s)` : "⚠ No supported images (PNG/JPEG/WebP)");
      } catch (err) {
        console.error("Image upload:", err);
        setImageUploadModalStatus("⚠ " + (err?.message || String(err)));
      } finally {
        e.target.value = "";
      }
    },
    [activeBlock?.id]
  );

  // ─────────────────────────────────────────────
